export type Feature = 'home' | 'outline' | 'preview' | 'generate' | 'consultant' | 'gallery' | 'calendar' | 'clients' | 'inventory' | 'flash' | 'consent' | 'budget' | 'aftercare' | 'dashboard';
export type UserRole = 'admin' | 'client';

export interface Client {
    id: number;
    name: string;
    contact: string;
    notes: string;
    allergies?: string;
    loyalty_points?: number;
    createdAt: string;
}

export interface Appointment {
    id: number;
    date: string;
    time: string;
    name: string;
    contact: string;
    idea: string;
    reminderMethod: 'email' | 'sms';
    status: 'scheduled' | 'completed';
    deposit_paid?: boolean;
    price_estimated?: number;
}

export interface FlashSet {
    id: number;
    title: string;
    image_url: string;
    price: number;
    size_cm: number;
    is_repeatable: boolean;
    is_available: boolean;
}

export interface InventoryItem {
    id: number;
    item_name: string;
    quantity: number;
    min_stock: number;
    category: 'Tintas' | 'Agujas' | 'Higiene' | 'Otros';
}

import React, { useState, useEffect, useRef, useLayoutEffect } from 'react';
import type { Feature, UserRole } from './types';
import { OutlineCreator } from './components/OutlineCreator';
import { TattooPreviewer } from './components/TattooPreviewer';
import { DesignGenerator } from './components/DesignGenerator';
import { AiConsultant } from './components/AiConsultant';
import { DailyTips } from './components/DailyTips';
import { Gallery } from './components/Gallery';
import { Calendar } from './components/Calendar';
import { Clients } from './components/Clients';
import { AdminDashboard } from './components/AdminDashboard';
import { InventoryManager } from './components/InventoryManager';
import { FlashCatalog } from './components/FlashCatalog';
import { BudgetCalculator } from './components/BudgetCalculator';
import { AftercareGuide } from './components/AftercareGuide';
import { LogoIcon, SunIcon, MoonIcon, HomeIcon, GalleryIcon, CalendarIcon, ConsultantIcon, ClientsIcon, InventoryIcon, FlashIcon, BudgetIcon, CareIcon, DashboardIcon, UserRoleIcon } from './components/Icons';

const App: React.FC = () => {
    const [role, setRole] = useState<UserRole>(() => (localStorage.getItem('userRole') as UserRole) || 'client');
    const [activeFeature, setActiveFeature] = useState<Feature>('home');
    const [theme, setTheme] = useState(localStorage.getItem('theme') || 'dark');
    const navBarRef = useRef<HTMLElement>(null);
    const [navBarHeight, setNavBarHeight] = useState(0);

    useEffect(() => {
        document.documentElement.classList.toggle('dark', theme === 'dark');
        localStorage.setItem('theme', theme);
    }, [theme]);

    useEffect(() => {
        localStorage.setItem('userRole', role);
        setActiveFeature('home');
    }, [role]);

    useLayoutEffect(() => {
        const updateHeight = () => setNavBarHeight(navBarRef.current?.offsetHeight || 0);
        updateHeight();
        window.addEventListener('resize', updateHeight);
        return () => window.removeEventListener('resize', updateHeight);
    }, []);

    const toggleRole = () => setRole(prev => prev === 'admin' ? 'client' : 'admin');

    const adminMenu = [
        { id: 'dashboard', icon: <DashboardIcon />, label: 'Panel' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Agenda' },
        { id: 'inventory', icon: <InventoryIcon />, label: 'Stock' },
        { id: 'flash', icon: <FlashIcon />, label: 'Flash' },
        { id: 'clients', icon: <ClientsIcon />, label: 'Clientes' },
    ];

    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Diseños' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Reservar' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Generador IA" desc="Crea diseños desde cero" icon={<DashboardIcon />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Mira el tattoo en tu piel" icon={<DashboardIcon />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Prepara tu plantilla" icon={<DashboardIcon />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
                </div>
            );
            case 'dashboard': return <AdminDashboard />;
            case 'inventory': return <InventoryManager />;
            case 'calendar': return <Calendar adminMode={role === 'admin'} />;
            case 'clients': return <Clients />;
            case 'gallery': return <Gallery />;
            case 'consultant': return <AiConsultant />;
            case 'flash': return <FlashCatalog isAdmin={role === 'admin'} />;
            case 'budget': return <BudgetCalculator />;
            case 'aftercare': return <AftercareGuide />;
            case 'generate': return <DesignGenerator />;
            case 'preview': return <TattooPreviewer />;
            case 'outline': return <OutlineCreator />;
            default: return <div className="text-center py-20">Próximamente...</div>;
        }
    };

    return (
        <div className="min-h-screen flex flex-col transition-colors duration-500">
            <header className="sticky top-0 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md z-40 p-4 border-b border-gray-200 dark:border-gray-800">
                <div className="max-w-4xl mx-auto flex justify-between items-center">
                    <div className="flex items-center space-x-3">
                        <LogoIcon />
                        <h1 className="text-xl font-bold font-playfair tracking-tight">
                            {role === 'admin' ? 'Admin Portal' : 'Johana Tatuajes'}
                        </h1>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={toggleRole} className="p-2 rounded-full bg-purple-100 dark:bg-purple-900/30 text-purple-600 transition-all hover:scale-110" title="Cambiar Rol">
                            <UserRoleIcon />
                        </button>
                        <button onClick={() => setTheme(prev => prev === 'dark' ? 'light' : 'dark')} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-800 transition-colors">
                            {theme === 'dark' ? <SunIcon /> : <MoonIcon />}
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 overflow-x-hidden" style={{ paddingBottom: `${navBarHeight + 30}px` }}>
                <div className="max-w-4xl mx-auto animate-fade-in">
                    {renderFeature()}
                </div>
            </main>

            <nav ref={navBarRef} className="fixed bottom-0 left-0 right-0 bg-white/90 dark:bg-gray-950/90 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 z-50">
                <div className="max-w-4xl mx-auto grid grid-cols-5 h-20">
                    {currentMenu.map(item => (
                        <button key={item.id} onClick={() => setActiveFeature(item.id as Feature)} 
                                className={`flex flex-col items-center justify-center space-y-1 transition-all ${activeFeature === item.id ? 'text-purple-600 dark:text-purple-400 scale-110 font-bold' : 'text-gray-400'}`}>
                            <div className="w-6 h-6">{item.icon}</div>
                            <span className="text-[10px] uppercase tracking-widest">{item.label}</span>
                        </button>
                    ))}
                </div>
            </nav>
        </div>
    );
};

const FeatureCard = ({ title, desc, icon, onClick }: any) => (
    <button onClick={onClick} className="flex items-center p-6 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-2xl text-left hover:border-purple-500 transition-all group shadow-sm">
        <div className="p-4 bg-purple-50 dark:bg-purple-900/20 rounded-xl mr-4 group-hover:scale-110 transition-transform">{icon}</div>
        <div>
            <h4 className="font-bold text-lg">{title}</h4>
            <p className="text-sm text-gray-500">{desc}</p>
        </div>
    </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Spinner, CalendarIcon, InventoryIcon, UserIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            const { data: apps } = await supabase.from('appointments').select('*');
            const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
            const { data: clients } = await supabase.from('clients').select('*');

            setStats({
                appointments: apps?.filter(a => a.status === 'scheduled').length || 0,
                revenue: apps?.filter(a => a.status === 'completed').length * 150 || 0, // Mock revenue calculation
                lowStock: stock?.length || 0,
                newClients: clients?.length || 0
            });
            setLoading(false);
        };
        fetchStats();
    }, []);

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-6">
            <h2 className="text-2xl font-bold">Panel de Control</h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="Citas Hoy" value={stats.appointments} icon={<CalendarIcon />} color="blue" />
                <StatCard title="Ingresos Sem." value={`$${stats.revenue}`} icon={<InventoryIcon />} color="green" />
                <StatCard title="Stock Bajo" value={stats.lowStock} icon={<InventoryIcon />} color="red" />
                <StatCard title="Clientes" value={stats.newClients} icon={<UserIcon />} color="purple" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm">
                    <h3 className="font-bold mb-4 flex items-center gap-2"><CalendarIcon className="w-5 h-5"/> Próximas Sesiones</h3>
                    <p className="text-gray-500 text-sm">No hay citas críticas para las próximas 2 horas.</p>
                </div>
                <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl border border-gray-200 dark:border-gray-800 shadow-sm">
                    <h3 className="font-bold mb-4 flex items-center gap-2"><InventoryIcon className="w-5 h-5"/> Alertas de Stock</h3>
                    {stats.lowStock > 0 ? (
                        <div className="p-3 bg-red-100 dark:bg-red-900/20 text-red-600 rounded-lg text-sm">
                            Tienes {stats.lowStock} productos por debajo del mínimo.
                        </div>
                    ) : (
                        <p className="text-gray-500 text-sm">Inventario al día.</p>
                    )}
                </div>
            </div>
        </div>
    );
};

const StatCard = ({ title, value, icon, color }: any) => (
    <div className={`p-4 rounded-2xl border border-gray-100 dark:border-gray-800 bg-white dark:bg-gray-900 shadow-sm`}>
        <div className={`w-10 h-10 rounded-xl bg-${color}-100 dark:bg-${color}-900/20 flex items-center justify-center mb-3 text-${color}-600`}>
            {icon}
        </div>
        <p className="text-xs text-gray-500 uppercase tracking-tighter">{title}</p>
        <p className="text-2xl font-black mt-1">{value}</p>
    </div>
);

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { InventoryItem } from '../types';
import { Spinner, SaveIcon, PlusIcon, TrashIcon } from './Icons';

export const InventoryManager: React.FC = () => {
    const [items, setItems] = useState<InventoryItem[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchInventory = async () => {
        const { data } = await supabase.from('inventory').select('*').order('category');
        if (data) setItems(data);
        setLoading(false);
    };

    useEffect(() => { fetchInventory(); }, []);

    const updateStock = async (id: number, val: number) => {
        await supabase.from('inventory').update({ quantity: val }).eq('id', id);
        fetchInventory();
    };

    if (loading) return <Spinner />;

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold">Gestión de Insumos</h2>
                <button className="flex items-center gap-2 bg-purple-600 px-4 py-2 rounded-lg text-white font-bold"><PlusIcon /> Nuevo</button>
            </div>
            <div className="bg-white dark:bg-gray-900 rounded-2xl border border-gray-200 dark:border-gray-800 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 dark:bg-gray-800 text-xs uppercase text-gray-500">
                        <tr>
                            <th className="px-6 py-4">Item</th>
                            <th className="px-6 py-4">Stock</th>
                            <th className="px-6 py-4">Min.</th>
                            <th className="px-6 py-4 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
                        {items.map(item => (
                            <tr key={item.id} className={item.quantity < item.min_stock ? 'bg-red-50/50 dark:bg-red-900/5' : ''}>
                                <td className="px-6 py-4 font-medium">{item.item_name}</td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => updateStock(item.id, item.quantity - 1)} className="w-8 h-8 rounded bg-gray-100 dark:bg-gray-800">-</button>
                                        <span className="w-8 text-center font-bold">{item.quantity}</span>
                                        <button onClick={() => updateStock(item.id, item.quantity + 1)} className="w-8 h-8 rounded bg-gray-100 dark:bg-gray-800">+</button>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-gray-500">{item.min_stock}</td>
                                <td className="px-6 py-4 text-right"><button className="text-red-500"><TrashIcon /></button></td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

import React, { useState } from 'react';

export const BudgetCalculator: React.FC = () => {
    const [size, setSize] = useState(10);
    const [style, setStyle] = useState('Lineal');
    const [color, setColor] = useState(false);

    const calculate = () => {
        let base = size * 10;
        if (style === 'Realista') base *= 2.5;
        if (style === 'Sombreado') base *= 1.8;
        if (color) base += 50;
        return Math.round(base);
    };

    return (
        <div className="max-w-md mx-auto bg-white dark:bg-gray-900 p-8 rounded-3xl border border-gray-200 dark:border-gray-800 shadow-xl">
            <h2 className="text-2xl font-black mb-6 text-purple-600">Calculadora de Presupuesto</h2>
            <div className="space-y-6">
                <div>
                    <label className="block text-sm font-bold mb-3 uppercase tracking-wider text-gray-500">Tamaño aprox. ({size} cm)</label>
                    <input type="range" min="3" max="40" value={size} onChange={e => setSize(parseInt(e.target.value))} 
                           className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-purple-600" />
                </div>
                <div>
                    <label className="block text-sm font-bold mb-3 uppercase tracking-wider text-gray-500">Estilo Artístico</label>
                    <div className="grid grid-cols-3 gap-2">
                        {['Lineal', 'Sombreado', 'Realista'].map(s => (
                            <button key={s} onClick={() => setStyle(s)} 
                                    className={`py-2 text-sm rounded-xl border transition-all ${style === s ? 'bg-purple-600 text-white border-purple-600' : 'border-gray-200 dark:border-gray-800'}`}>
                                {s}
                            </button>
                        ))}
                    </div>
                </div>
                <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
                    <span className="font-bold text-gray-600">Incluye Color</span>
                    <button onClick={() => setColor(!color)} className={`w-12 h-6 rounded-full transition-colors relative ${color ? 'bg-purple-600' : 'bg-gray-300'}`}>
                        <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all ${color ? 'left-7' : 'left-1'}`} />
                    </button>
                </div>
                <div className="pt-6 border-t border-gray-100 dark:border-gray-800 text-center">
                    <p className="text-gray-500 text-sm mb-1 uppercase tracking-widest font-bold">Rango Estimado</p>
                    <h3 className="text-5xl font-black text-gray-900 dark:text-white">${calculate()} - ${Math.round(calculate() * 1.2)}</h3>
                    <p className="text-[10px] text-gray-400 mt-4 leading-tight italic">
                        *Este es un precio base orientativo. El costo final se confirma con el artista tras evaluar el diseño final.
                    </p>
                </div>
            </div>
        </div>
    );
};

