    const [navBarHeight, setNavBarHeight] = useState(0);

    // PWA Install State
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showInstallPopup, setShowInstallPopup] = useState(false);

    useEffect(() => {
        document.documentElement.classList.toggle('dark', theme === 'dark');
        localStorage.setItem('theme', theme);
    }, [theme]);

    useEffect(() => {
        localStorage.setItem('userRole', role);
        setActiveFeature('home');
    }, [role]);

    useEffect(() => {
        const handler = (e: any) => {
            e.preventDefault();
            setDeferredPrompt(e);
            // Mostrar el popup después de 3 segundos de inactividad o entrada
            setTimeout(() => setShowInstallPopup(true), 3000);
        };
        window.addEventListener('beforeinstallprompt', handler);
        return () => window.removeEventListener('beforeinstallprompt', handler);
    }, []);

    useLayoutEffect(() => {
        const updateHeight = () => setNavBarHeight(navBarRef.current?.offsetHeight || 0);
        updateHeight();
        window.addEventListener('resize', updateHeight);
        return () => window.removeEventListener('resize', updateHeight);
    }, []);

    const toggleRole = () => setRole(prev => prev === 'admin' ? 'client' : 'admin');

    const handleInstallClick = async () => {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;
        if (outcome === 'accepted') {
            setDeferredPrompt(null);
            setShowInstallPopup(false);
        }
    };

    const adminMenu = [
        { id: 'dashboard', icon: <DashboardIcon />, label: 'Panel' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Agenda' },
        { id: 'inventory', icon: <InventoryIcon />, label: 'Stock' },
        { id: 'flash', icon: <FlashIcon />, label: 'Flash' },
        { id: 'clients', icon: <ClientsIcon />, label: 'Clientes' },
    ];

    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Diseños' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Reservar' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Generador IA" desc="Crea diseños desde cero" icon={<DashboardIcon />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Mira el tattoo en tu piel" icon={<DashboardIcon />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Prepara tu plantilla" icon={<DashboardIcon />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
                </div>
            );
            case 'dashboard': return <AdminDashboard />;
            case 'inventory': return <InventoryManager />;
            case 'calendar': return <Calendar adminMode={role === 'admin'} />;
            case 'clients': return <Clients />;
            case 'gallery': return <Gallery />;
            case 'consultant': return <AiConsultant />;
            case 'flash': return <FlashCatalog isAdmin={role === 'admin'} />;
            case 'budget': return <BudgetCalculator />;
            case 'aftercare': return <AftercareGuide />;
            case 'generate': return <DesignGenerator />;
            case 'preview': return <TattooPreviewer />;
            case 'outline': return <OutlineCreator />;
            default: return <div className="text-center py-20">Próximamente...</div>;
        }
    };

    return (
        <div className="min-h-screen flex flex-col transition-colors duration-500 pb-safe">
            <header className="sticky top-0 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md z-40 p-4 border-b border-gray-200 dark:border-gray-800 safe-top">
                <div className="max-w-4xl mx-auto flex justify-between items-center">
                    <div className="flex items-center space-x-3">
                        <img src="https://appdesignmex.com/bribiescaicono.png" alt="Logo" className="w-8 h-8 rounded-lg shadow-lg" />
                        <h1 className="text-xl font-bold font-playfair tracking-tight">
                            {role === 'admin' ? 'Admin Portal' : 'Bribiesca Tattoo'}
                        </h1>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={toggleRole} className="p-2 rounded-full bg-purple-100 dark:bg-purple-900/30 text-purple-600 transition-all hover:scale-110" title="Cambiar Rol">
                            <UserRoleIcon />
                        </button>
                        <button onClick={() => setTheme(prev => prev === 'dark' ? 'light' : 'dark')} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-800 transition-colors">
                            {theme === 'dark' ? <SunIcon /> : <MoonIcon />}
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 overflow-x-hidden" style={{ paddingBottom: `${navBarHeight + 30}px` }}>
                <div className="max-w-4xl mx-auto animate-fade-in">
                    {renderFeature()}
                </div>
            </main>

            {/* Modern Install PWA Popup */}
            {showInstallPopup && (
                <div className="fixed bottom-24 left-4 right-4 z-[100] animate-fade-in">
                    <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-3xl p-5 shadow-2xl flex items-center justify-between">
                        <div className="flex items-center space-x-4">
                            <img src="https://appdesignmex.com/bribiescaicono.png" className="w-12 h-12 rounded-2xl shadow-lg" alt="App Icon" />
                            <div>
                                <h3 className="font-bold text-sm">Instalar Aplicación</h3>
                                <p className="text-xs text-gray-500">Acceso rápido y offline</p>
                            </div>
                        </div>
                        <div className="flex space-x-2">
                            <button onClick={() => setShowInstallPopup(false)} className="p-2 text-gray-400 hover:text-gray-600">
                                <CloseIcon className="w-5 h-5" />
                            </button>
                            <button onClick={handleInstallClick} className="bg-purple-600 text-white px-5 py-2 rounded-2xl text-sm font-bold shadow-lg shadow-purple-500/30 hover:bg-purple-700 transition-all">
                                Instalar
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <nav ref={navBarRef} className="fixed bottom-0 left-0 right-0 bg-white/90 dark:bg-gray-950/90 backdrop-blur-lg border-t border-gray-200 dark:border-gray-800 z-50 safe-bottom">
                <div className="max-w-4xl mx-auto grid grid-cols-5 h-20">
                    {currentMenu.map(item => (
                        <button key={item.id} onClick={() => setActiveFeature(item.id as Feature)} 
                                className={`flex flex-col items-center justify-center space-y-1 transition-all ${activeFeature === item.id ? 'text-purple-600 dark:text-purple-400 scale-110 font-bold' : 'text-gray-400'}`}>
                            <div className="w-6 h-6">{item.icon}</div>
                            <span className="text-[10px] uppercase tracking-widest">{item.label}</span>
                        </button>
                    ))}
                </div>
            </nav>
        </div>
    );
};

const FeatureCard = ({ title, desc, icon, onClick }: any) => (
    <button onClick={onClick} className="flex items-center p-6 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-2xl text-left hover:border-purple-500 transition-all group shadow-sm">
        <div className="p-4 bg-purple-50 dark:bg-purple-900/20 rounded-xl mr-4 group-hover:scale-110 transition-transform">{icon}</div>
        <div>
            <h4 className="font-bold text-lg">{title}</h4>
            <p className="text-sm text-gray-500">{desc}</p>
        </div>
    </button>
);

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { PencilIcon, TrashIcon, CheckIcon } from './Icons';
import { getAll, add, put, deleteItem, findOrAddClient } from '../utils/db';
import { Appointment } from '../types';

export const Calendar: React.FC<{ adminMode?: boolean }> = ({ adminMode = false }) => {
    const [currentDate, setCurrentDate] = useState(new Date());
    const [selectedDate, setSelectedDate] = useState<Date | null>(null);
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [showForm, setShowForm] = useState(false);
    const [formData, setFormData] = useState({ name: '', contact: '', idea: '', time: '14:00' });
    const [reminderMethod, setReminderMethod] = useState<'email' | 'sms'>('email');
    const [confirmation, setConfirmation] = useState('');
    const [contactError, setContactError] = useState('');
    const [activeAppointmentView, setActiveAppointmentView] = useState<'programadas' | 'pasadas'>('programadas');
    const [editingAppointmentId, setEditingAppointmentId] = useState<number | null>(null);
    const [pendingConfirmation, setPendingConfirmation] = useState<Appointment | null>(null);

    useEffect(() => {
        loadAppointments();
    }, []);

    const loadAppointments = async () => {
        try {
            const loadedAppointments = await getAll<Appointment>('appointments');
            setAppointments(loadedAppointments);
        } catch (error: any) {
            console.error("Error al cargar citas:", error.message);
        }
    };

    useEffect(() => {
        const checkInterval = setInterval(() => {
            if (pendingConfirmation) return;

            const now = new Date();
            const fourHoursAgo = new Date(now.getTime() - 4 * 60 * 60 * 1000);

            const appointmentToConfirm = appointments.find(app => {
                if (app.status !== 'scheduled') return false;
                const appointmentDateTime = new Date(`${app.date}T${app.time}`);
                return appointmentDateTime < fourHoursAgo;
            });

            if (appointmentToConfirm) {
                setPendingConfirmation(appointmentToConfirm);
            }
        }, 60000); 

        return () => clearInterval(checkInterval);
    }, [appointments, pendingConfirmation]);

    const daysOfWeek = ['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'];

    const firstDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
    const lastDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);
    const daysInMonth = lastDayOfMonth.getDate();
    const startingDay = firstDayOfMonth.getDay();

    const changeMonth = (offset: number) => {
        setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + offset, 1));
        setSelectedDate(null);
        setShowForm(false);
        setConfirmation('');
    };

    const handleDateClick = (day: number) => {
        const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
        if (!adminMode && date < new Date(new Date().toDateString())) return;

        setSelectedDate(date);
        setShowForm(true);
        setEditingAppointmentId(null);
        setConfirmation('');
        setFormData({ name: '', contact: '', idea: '', time: '14:00' });
        setReminderMethod('email');
        setContactError('');
    };

    const validateContact = (method: 'email' | 'sms', value: string): boolean => {
        if (method === 'email') {
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            return emailRegex.test(value);
        } else {
            const phoneRegex = /^\d[\d\s-]{8,}\d$/;
            return phoneRegex.test(value);
        }
    };

    const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
        if (name === 'contact') {
            if (!validateContact(reminderMethod, value)) {
                 setContactError(reminderMethod === 'email' ? 'Por favor, introduce un correo válido.' : 'Por favor, introduce un teléfono válido.');
            } else {
                setContactError('');
            }
        }
    };

    const handleReminderMethodChange = (method: 'email' | 'sms') => {
        setReminderMethod(method);
        if (formData.contact) {
            if (!validateContact(method, formData.contact)) {
                 setContactError(method === 'email' ? 'Por favor, introduce un correo válido.' : 'Por favor, introduce un teléfono válido.');
            } else {
                setContactError('');
            }
        }
    }

    const handleBooking = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!validateContact(reminderMethod, formData.contact)) {
            setContactError(reminderMethod === 'email' ? 'El formato del correo no es válido.' : 'El formato del teléfono no es válido.');
            return;
        }

        try {
            await findOrAddClient(formData.name, formData.contact);

            if (editingAppointmentId) {
                const appointmentToUpdate = appointments.find(app => app.id === editingAppointmentId);
                if (appointmentToUpdate) {
                    const updatedAppointment = {
                        ...appointmentToUpdate,
                        ...formData,
                        reminderMethod,
                        date: selectedDate?.toISOString().split('T')[0] || appointmentToUpdate.date
                    };
                    await put('appointments', updatedAppointment);
                    setConfirmation('¡Cita actualizada con éxito!');
                }
            } else if (selectedDate) {
                const newAppointmentData: Omit<Appointment, 'id'> = {
                    date: selectedDate.toISOString().split('T')[0],
                    reminderMethod,
                    status: 'scheduled',
                    ...formData
                };
                await add('appointments', newAppointmentData);
                const reminderTarget = reminderMethod === 'email' 
                    ? `a tu correo electrónico (${formData.contact})`
                    : `por SMS a tu teléfono (${formData.contact})`;
                setConfirmation(`¡Cita agendada! Se enviará un recordatorio ${reminderTarget} 24 horas antes.`);
            }

            await loadAppointments();
            setShowForm(false);
            setSelectedDate(null);
            setEditingAppointmentId(null);
        } catch (error: any) {
            console.error("Error al guardar la cita:", error.message);
            alert("No se pudo guardar la cita: " + error.message);
        }
    };

    const handleEditAppointment = (appointment: Appointment) => {
        setEditingAppointmentId(appointment.id);
        setFormData({ name: appointment.name, contact: appointment.contact, idea: appointment.idea, time: appointment.time });
        setReminderMethod(appointment.reminderMethod);
        setSelectedDate(new Date(appointment.date.replace(/-/g, '/')));
        setShowForm(true);
        setConfirmation('');
        setContactError('');
    };

    const handleDeleteAppointment = async (appointmentId: number) => {
        if (window.confirm('¿Estás seguro de que quieres eliminar esta cita?')) {
            await deleteItem('appointments', appointmentId);
            await loadAppointments();
        }
    };

    const handleMarkAsCompleted = async (appointmentId: number) => {
        const appointmentToUpdate = appointments.find(app => app.id === appointmentId);
        if (appointmentToUpdate) {
            await put('appointments', { ...appointmentToUpdate, status: 'completed' });
            await loadAppointments();
        }
        if (pendingConfirmation && pendingConfirmation.id === appointmentId) {
            setPendingConfirmation(null);
        }
    };

    const handleCancelForm = () => {
        setShowForm(false);
        setEditingAppointmentId(null);
        setSelectedDate(null);
    };

    const isDateBooked = (day: number) => {
        const dateStr = new Date(currentDate.getFullYear(), currentDate.getMonth(), day).toISOString().split('T')[0];
        return appointments.some(app => app.date === dateStr && app.status !== 'completed');
    };

    const isFormValid = useMemo(() => {
        return formData.name.trim() !== '' && formData.idea.trim() !== '' && formData.contact.trim() !== '' && formData.time.trim() !== '' && !contactError;
    }, [formData, contactError]);

    const { scheduledAppointments, pastAppointments } = useMemo(() => {
        const now = new Date();
        const scheduled: Appointment[] = [];
        const past: Appointment[] = [];

        [...appointments].forEach(app => {
            const appointmentDateTime = new Date(`${app.date}T${app.time || '00:00'}`);
            if (appointmentDateTime >= now && app.status === 'scheduled') {
                scheduled.push(app);
            } else {
                past.push(app);
            }
        });

        scheduled.sort((a, b) => new Date(`${a.date}T${a.time}`).getTime() - new Date(`${b.date}T${b.time}`).getTime());
        past.sort((a, b) => new Date(`${b.date}T${b.time}`).getTime() - new Date(`${a.date}T${a.time}`).getTime());

        return { scheduledAppointments: scheduled, pastAppointments: past };
    }, [appointments]);

    const renderCalendar = () => {
        const cells = [];
        for (let i = 0; i < startingDay; i++) {
            cells.push(<div key={`empty-${i}`} className="p-2 border border-transparent"></div>);
        }
        for (let day = 1; day <= daysInMonth; day++) {
            const currentDayDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
            const isPast = !adminMode && currentDayDate < new Date(new Date().toDateString());
            const isBooked = isDateBooked(day);
            const isSelected = selectedDate?.getDate() === day && selectedDate?.getMonth() === currentDate.getMonth();

            let cellClass = 'p-2 text-center border border-gray-200 dark:border-gray-700 transition-colors relative';
            if (isPast || isBooked) {
                cellClass += ' bg-gray-200 dark:bg-gray-800 text-gray-400 dark:text-gray-500 cursor-not-allowed line-through';
            } else {
                cellClass += ' cursor-pointer hover:bg-purple-100 dark:hover:bg-purple-900/50';
            }
            if (isSelected) {
                 cellClass += ' bg-purple-500 text-white font-bold rounded-xl z-10';
            }
            cells.push(
                <div key={day} className={cellClass} onClick={() => !isPast && !isBooked && handleDateClick(day)}>
                    {day}
                    {isBooked && !isSelected && <div className="absolute bottom-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-red-400 rounded-full"></div>}
                </div>
            );
        }
        return cells;
    };

    const AppointmentList: React.FC<{ 
        appointments: Appointment[]; 
        isPastList?: boolean;
        onEdit: (app: Appointment) => void;
        onDelete: (id: number) => void;
        onMarkAsCompleted: (id: number) => void;
    }> = ({ appointments, isPastList = false, onEdit, onDelete, onMarkAsCompleted }) => (
        <div className="space-y-4 mt-4 animate-fade-in">
            {appointments.length === 0 ? (
                <p className="text-center text-gray-500 dark:text-gray-400 py-4">No hay citas en esta categoría.</p>
            ) : (
                appointments.map((app) => {
                    const isCompleted = app.status === 'completed';
                    const isMissed = isPastList && app.status === 'scheduled';
                    let itemClass = "p-4 rounded-3xl border flex justify-between items-start transition-colors ";
                    if (isCompleted) {
                        itemClass += "bg-green-50 dark:bg-green-900/40 border-green-200 dark:border-green-800/60";
                    } else if (isMissed) {
                        itemClass += "bg-red-50 dark:bg-red-900/40 border-red-200 dark:border-red-800/60 opacity-80";
                    } else {
                        itemClass += "bg-white dark:bg-gray-900 border-gray-200 dark:border-gray-800 shadow-sm";
                    }

                    return (
                        <div key={app.id} className={itemClass}>
                            <div className="flex-grow">
                                <p className={`font-bold ${isCompleted ? 'text-green-700 dark:text-green-300' : isMissed ? 'text-red-700 dark:text-red-300' : 'text-purple-600 dark:text-purple-400'}`}>
                                    {new Date(app.date.replace(/-/g, '/')).toLocaleDateString('es-ES', { weekday: 'short', day: 'numeric', month: 'short' })} • {app.time}
                                </p>
                                <p className="text-sm font-bold mt-1">{app.name}</p>
                                <p className="text-xs text-gray-500">{app.idea}</p>
                            </div>
                            <div className="flex items-center gap-1 flex-shrink-0 ml-2">
                                {app.status === 'scheduled' && (
                                     <button onClick={() => onMarkAsCompleted(app.id)} className="p-2 text-gray-400 hover:text-green-600 transition-colors">
                                        <CheckIcon />
                                    </button>
                                )}
                                <button onClick={() => onEdit(app)} className="p-2 text-gray-400 hover:text-purple-600 transition-colors">
                                    <PencilIcon />
                                </button>
                                <button onClick={() => onDelete(app.id)} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
                                    <TrashIcon />
                                </button>
                            </div>
                        </div>
                    );
                })
            )}
        </div>
    );

    return (
        <div className="space-y-6">
            <div className="bg-white dark:bg-gray-900 rounded-3xl p-6 border border-gray-100 dark:border-gray-800 shadow-sm">
                <div className="flex justify-between items-center mb-6">
                    <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-colors">&lt;</button>
                    <h3 className="text-lg font-black uppercase tracking-widest">{currentDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' })}</h3>
                    <button onClick={() => changeMonth(1)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-colors">&gt;</button>
                </div>

                <div className="grid grid-cols-7 gap-2 mb-2">
                    {daysOfWeek.map(day => <div key={day} className="text-[10px] font-black uppercase text-center text-gray-400">{day}</div>)}
                </div>
                <div className="grid grid-cols-7 gap-2">
                    {renderCalendar()}
                </div>
            </div>

             {confirmation && <div className="p-4 bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400 rounded-2xl text-center text-sm font-bold animate-fade-in">{confirmation}</div>}

            {showForm && selectedDate && (
                <div className="p-6 bg-white dark:bg-gray-900 rounded-3xl border border-purple-100 dark:border-purple-900/30 shadow-xl animate-fade-in">
                    <h4 className="font-black text-xl mb-6">{editingAppointmentId ? 'Editar Cita' : 'Agendar Sesión'}</h4>
                    <form onSubmit={handleBooking} className="space-y-6">
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Nombre Completo</label>
                                <input type="text" name="name" value={formData.name} onChange={handleFormChange} required className="w-full p-4 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none"/>
                            </div>
                            <div>
                                <label className="block text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Hora sugerida</label>
                                <input type="time" name="time" value={formData.time} onChange={handleFormChange} required className="w-full p-4 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none"/>
                            </div>
                        </div>
                         <div>
                            <label className="block text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Método de aviso</label>
                            <div className="flex gap-2">
                                <button type="button" onClick={() => handleReminderMethodChange('email')} className={`flex-1 py-3 rounded-2xl text-sm font-bold transition-all ${ reminderMethod === 'email' ? 'bg-purple-600 text-white' : 'bg-gray-100 dark:bg-gray-800' }`} > Email </button>
                                <button type="button" onClick={() => handleReminderMethodChange('sms')} className={`flex-1 py-3 rounded-2xl text-sm font-bold transition-all ${ reminderMethod === 'sms' ? 'bg-purple-600 text-white' : 'bg-gray-100 dark:bg-gray-800' }`} > SMS </button>
                            </div>
                        </div>
                         <div>
                            <label className="block text-xs font-black uppercase tracking-widest text-gray-400 mb-2"> {reminderMethod === 'email' ? 'Email de contacto' : 'Teléfono Móvil'} </label>
                            <input type={reminderMethod === 'email' ? 'email' : 'tel'} name="contact" value={formData.contact} onChange={handleFormChange} required className={`w-full p-4 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none ${contactError ? 'ring-2 ring-red-500' : ''}`} />
                             {contactError && <p className="text-red-500 text-[10px] mt-1 font-bold">{contactError}</p>}
                        </div>
                        <div>
                            <label className="block text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Idea del tatuaje</label>
                            <textarea name="idea" rows={3} value={formData.idea} onChange={handleFormChange} required className="w-full p-4 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none"></textarea>
                        </div>
                        <div className="flex gap-4">
                            <button type="button" onClick={handleCancelForm} className="flex-1 py-4 bg-gray-100 dark:bg-gray-800 rounded-2xl font-bold">Cerrar</button>
                            <button type="submit" disabled={!isFormValid} className="flex-1 py-4 bg-purple-600 text-white rounded-2xl font-bold disabled:opacity-50">
                                {editingAppointmentId ? 'Guardar' : 'Confirmar'}
                            </button>
                        </div>
                    </form>
                </div>
            )}

            <div className="pt-6">
                <div className="flex justify-between items-center mb-6">
                     <h3 className="text-lg font-black uppercase tracking-widest">Mis Sesiones</h3>
                     <div className="flex p-1 bg-gray-100 dark:bg-gray-800 rounded-xl">
                        <button onClick={() => setActiveAppointmentView('programadas')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${ activeAppointmentView === 'programadas' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-400' }`} > Pendientes </button>
                        <button onClick={() => setActiveAppointmentView('pasadas')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${ activeAppointmentView === 'pasadas' ? 'bg-white dark:bg-gray-700 shadow-sm' : 'text-gray-400' }`} > Historial </button>
                    </div>
                </div>

                {activeAppointmentView === 'programadas' ? (
                    <AppointmentList appointments={scheduledAppointments} onEdit={handleEditAppointment} onDelete={handleDeleteAppointment} onMarkAsCompleted={handleMarkAsCompleted} />
                ) : (
                    <AppointmentList appointments={pastAppointments} isPastList={true} onEdit={handleEditAppointment} onDelete={handleDeleteAppointment} onMarkAsCompleted={handleMarkAsCompleted} />
                )}
            </div>
        </div>
    );
};

