import React, { useState, useEffect, useRef, useLayoutEffect } from 'react';
import type { Feature, UserRole } from './types';
import { OutlineCreator } from './components/OutlineCreator';
import { TattooPreviewer } from './components/TattooPreviewer';
import { DesignGenerator } from './components/DesignGenerator';
import { AiConsultant } from './components/AiConsultant';
import { DailyTips } from './components/DailyTips';
import { Gallery } from './components/Gallery';
import { Calendar } from './components/Calendar';
import { Clients } from './components/Clients';
import { AdminDashboard } from './components/AdminDashboard';
import { InventoryManager } from './components/InventoryManager';
import { FlashCatalog } from './components/FlashCatalog';
import { BudgetCalculator } from './components/BudgetCalculator';
import { AftercareGuide } from './components/AftercareGuide';
import { Auth } from './components/Auth';
import { 
    HomeIcon, 
    CalendarIcon, 
    ConsultantIcon, 
    ClientsIcon, 
    InventoryIcon, 
    FlashIcon, 
    BudgetIcon, 
    CareIcon, 
    DashboardIcon, 
    UserRoleIcon, 
    CloseIcon 
} from './components/Icons';

const App: React.FC = () => {
    const [user, setUser] = useState<{username: string, role: UserRole} | null>(() => {
        const saved = localStorage.getItem('bribiesca_user');
        return saved ? JSON.parse(saved) : null;
    });
    const [activeFeature, setActiveFeature] = useState<Feature>('home');
    const navBarRef = useRef<HTMLElement>(null);
    const [navBarHeight, setNavBarHeight] = useState(0);

    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showInstallPopup, setShowInstallPopup] = useState(false);

    useEffect(() => {
        if (user) {
            localStorage.setItem('bribiesca_user', JSON.stringify(user));
        } else {
            localStorage.removeItem('bribiesca_user');
        }
    }, [user]);

    useEffect(() => {
        const handler = (e: any) => {
            e.preventDefault();
            setDeferredPrompt(e);
            setTimeout(() => setShowInstallPopup(true), 5000);
        };
        window.addEventListener('beforeinstallprompt', handler);
        return () => window.removeEventListener('beforeinstallprompt', handler);
    }, []);

    useLayoutEffect(() => {
        const updateHeight = () => setNavBarHeight(navBarRef.current?.offsetHeight || 0);
        updateHeight();
        window.addEventListener('resize', updateHeight);
        return () => window.removeEventListener('resize', updateHeight);
    }, []);

    const handleInstallClick = async () => {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;
        if (outcome === 'accepted') {
            setDeferredPrompt(null);
            setShowInstallPopup(false);
        }
    };

    if (!user) {
        return <Auth onLogin={(username, role) => setUser({username, role})} />;
    }

    const adminMenu = [
        { id: 'dashboard', icon: <DashboardIcon />, label: 'Panel' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Agenda' },
        { id: 'inventory', icon: <InventoryIcon />, label: 'Stock' },
        { id: 'flash', icon: <FlashIcon />, label: 'Flash' },
        { id: 'clients', icon: <ClientsIcon />, label: 'Clientes' },
    ];

    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Diseños' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Reservar' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = user.role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Generador IA" desc="Crea diseños desde cero" icon={<DashboardIcon className="w-6 h-6 text-brand" />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Mira el tattoo en tu piel" icon={<DashboardIcon className="w-6 h-6 text-brand" />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Prepara tu plantilla" icon={<DashboardIcon className="w-6 h-6 text-brand" />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
                </div>
            );
            case 'dashboard': return <AdminDashboard />;
            case 'inventory': return <InventoryManager />;
            case 'calendar': return <Calendar adminMode={user.role === 'admin'} />;
            case 'clients': return <Clients />;
            case 'gallery': return <Gallery />;
            case 'consultant': return <AiConsultant />;
            case 'flash': return <FlashCatalog isAdmin={user.role === 'admin'} />;
            case 'budget': return <BudgetCalculator />;
            case 'aftercare': return <AftercareGuide />;
            case 'generate': return <DesignGenerator />;
            case 'preview': return <TattooPreviewer />;
            case 'outline': return <OutlineCreator />;
            default: return <div className="text-center py-20 opacity-50">Próximamente...</div>;
        }
    };

    return (
        <div className="min-h-screen flex flex-col transition-colors duration-500 pb-safe bg-black">
            <header className="sticky top-0 bg-black/80 backdrop-blur-xl z-40 p-3 border-b border-white/5 safe-top">
                <div className="max-w-4xl mx-auto flex justify-between items-center">
                    <div className="flex-1"></div>
                    <img 
                        src="https://appdesignmex.com/bribiesca.jpeg" 
                        alt="Bribiesca Logo" 
                        className="h-14 w-auto object-contain mx-auto rounded-lg" 
                    />
                    <div className="flex-1 flex justify-end">
                        <button 
                            onClick={() => setUser(null)} 
                            className="p-2 rounded-full bg-white/5 text-brand transition-all hover:scale-110" 
                            title="Cerrar Sesión"
                        >
                            <UserRoleIcon />
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 overflow-x-hidden" style={{ paddingBottom: `${navBarHeight + 30}px` }}>
                <div className="max-w-4xl mx-auto animate-fade-in">
                    {renderFeature()}
                </div>
            </main>

            {showInstallPopup && (
                <div className="fixed bottom-24 left-4 right-4 z-[100] animate-fade-in">
                    <div className="bg-[#111111] border border-white/10 rounded-3xl p-5 shadow-2xl flex items-center justify-between">
                        <div className="flex items-center space-x-4">
                            <img src="https://appdesignmex.com/bribiescaicono.png" className="w-12 h-12 rounded-2xl border border-brand/20 shadow-lg" alt="App Icon" />
                            <div>
