                                <CloseIcon className="w-5 h-5" />
                            </button>
                            <button onClick={handleInstallClick} className="bg-brand text-white px-5 py-2 rounded-2xl text-sm font-bold shadow-lg shadow-brand/20">
                                Instalar
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <nav ref={navBarRef} className="fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-xl border-t border-white/5 z-50 safe-bottom">
                <div className="max-w-4xl mx-auto grid grid-cols-5 h-20">
                    {currentMenu.map(item => (
                        <button key={item.id} onClick={() => setActiveFeature(item.id as Feature)} 
                                className={`flex flex-col items-center justify-center space-y-1 transition-all ${activeFeature === item.id ? 'text-brand scale-110 font-bold' : 'text-gray-500'}`}>
                            <div className="w-6 h-6">{item.icon}</div>
                            <span className="text-[10px] uppercase tracking-widest font-black">{item.label}</span>
                        </button>
                    ))}
                </div>
            </nav>
        </div>
    );
};

