import React, { useState } from 'react';
import { UserRole } from '../types';
import { Spinner } from './Icons';

interface AuthProps {
    onLogin: (username: string, role: UserRole) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const ADMIN_CREDENTIALS = [
        { user: 'johana_bribiesca', pass: '123_admin' },
        { user: 'harold_anguiano', pass: '123_admin' }
    ];

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        // Simular retardo de red
        await new Promise(r => setTimeout(r, 800));

        const adminUser = ADMIN_CREDENTIALS.find(c => c.user === username && c.pass === password);

        if (adminUser) {
            onLogin(username, 'admin');
        } else if (username && password) {
            // Permitir cualquier otro registro/login como cliente para la demo
            onLogin(username, 'client');
        } else {
            setError('Credenciales inválidas');
        }
        setLoading(false);
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-black p-6">
            <div className="w-full max-w-md space-y-8 animate-fade-in">
                <div className="text-center">
                    <img src="https://appdesignmex.com/bribiesca.jpeg" alt="Bribiesca Logo" className="mx-auto h-32 w-auto mb-8 rounded-2xl shadow-[0_0_40px_rgba(232,21,220,0.2)]" />
                    <h2 className="text-3xl font-black tracking-tighter text-white">
                        {isLogin ? 'BIENVENIDO' : 'ÚNETE'}
                    </h2>
                    <p className="mt-2 text-sm text-gray-500 uppercase tracking-widest font-bold">
                        Exclusivo Bribiesca Tattoo
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="mt-8 space-y-4">
                    <div className="space-y-4">
                        <div>
                            <input
                                type="text"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                placeholder="USUARIO"
                                className="w-full px-5 py-4 bg-[#111111] border border-white/10 rounded-2xl text-white font-bold placeholder-gray-600 focus:border-brand transition-all outline-none"
                                required
                            />
                        </div>
                        <div>
                            <input
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="CONTRASEÑA"
                                className="w-full px-5 py-4 bg-[#111111] border border-white/10 rounded-2xl text-white font-bold placeholder-gray-600 focus:border-brand transition-all outline-none"
                                required
                            />
                        </div>
                    </div>

                    {error && (
                        <p className="text-brand text-xs font-bold text-center animate-pulse">{error}</p>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-4 bg-brand text-white text-lg font-black rounded-2xl shadow-[0_0_30px_rgba(232,21,220,0.3)] hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50"
                    >
                        {loading ? <Spinner /> : (isLogin ? 'ACCEDER' : 'REGISTRARSE')}
                    </button>
                </form>

                <div className="text-center">
                    <button
                        onClick={() => setIsLogin(!isLogin)}
                        className="text-xs font-bold text-gray-500 hover:text-brand transition-colors uppercase tracking-widest"
                    >
                        {isLogin ? '¿No tienes cuenta? Regístrate' : '¿Ya tienes cuenta? Accede'}
                    </button>
                </div>
            </div>
        </div>
    );
};

