import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            const { data: apps } = await supabase.from('appointments').select('*');
            const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
            const { data: clients } = await supabase.from('clients').select('*');

            setStats({
                appointments: apps?.filter(a => a.status === 'scheduled').length || 0,
                revenue: apps?.filter(a => a.status === 'completed').length * 150 || 0,
                lowStock: stock?.length || 0,
                newClients: clients?.length || 0
            });
            setLoading(false);
        };
        fetchStats();
    }, []);

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-6">
            <h2 className="text-2xl font-black tracking-tighter text-brand">PANEL DE CONTROL</h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS HOY" value={stats.appointments} icon={<CalendarIcon />} color="#E815DC" />
                <StatCard title="INGRESOS" value={`$${stats.revenue}`} icon={<InventoryIcon />} color="#E815DC" />
                <StatCard title="STOCK BAJO" value={stats.lowStock} icon={<InventoryIcon />} color="#E815DC" />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} color="#E815DC" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-[#0a0a0a] p-6 rounded-3xl border border-white/5 shadow-xl">
                    <h3 className="font-bold mb-4 flex items-center gap-2 text-white uppercase tracking-widest text-xs">
                        <CalendarIcon className="w-5 h-5 text-brand"/> Próximas Sesiones
                    </h3>
                    <p className="text-gray-600 text-sm italic">Optimizado: No hay citas críticas próximas.</p>
                </div>
                <div className="bg-[#0a0a0a] p-6 rounded-3xl border border-white/5 shadow-xl">
                    <h3 className="font-bold mb-4 flex items-center gap-2 text-white uppercase tracking-widest text-xs">
                        <InventoryIcon className="w-5 h-5 text-brand"/> Alertas de Stock
                    </h3>
                    {stats.lowStock > 0 ? (
                        <div className="p-3 bg-brand/10 text-brand rounded-2xl text-xs font-bold border border-brand/20">
                            REVISIÓN NECESARIA: {stats.lowStock} PRODUCTOS.
                        </div>
                    ) : (
                        <p className="text-gray-600 text-sm italic">Inventario optimizado.</p>
                    )}
                </div>
            </div>
        </div>
    );
};

