import React, { useState } from 'react';
import { UserRole } from '../types';
import { Spinner, EyeIcon, EyeOffIcon } from './Icons';

interface AuthProps {
    onLogin: (username: string, role: UserRole) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const ADMIN_CREDENTIALS = [
        { user: 'johana_bribiesca', pass: '123_admin' },
        { user: 'harold_anguiano', pass: '123_admin' }
    ];

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        await new Promise(r => setTimeout(r, 800));

        const adminUser = ADMIN_CREDENTIALS.find(c => c.user === username && c.pass === password);

        if (adminUser) {
            onLogin(username, 'admin');
        } else if (username && password) {
            onLogin(username, 'client');
        } else {
            setError('Credenciales incorrectas');
        }
        setLoading(false);
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-black p-6">
            <div className="w-full max-w-md space-y-10 animate-fade-in">
                <div className="text-center">
                    <img 
                        src="https://appdesignmex.com/bribiesca.jpeg" 
                        alt="Bribiesca Logo" 
                        className="mx-auto h-32 w-auto mb-8 rounded-2xl shadow-[0_0_40px_rgba(232,21,220,0.25)]" 
                    />
                    <h2 className="text-3xl font-black tracking-tighter text-white uppercase italic">
                        {isLogin ? 'Acceso Privado' : 'Registro'}
                    </h2>
                    <p className="mt-2 text-[10px] text-brand uppercase tracking-[0.3em] font-black opacity-80">
                        Bribiesca Studio Exclusive
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-5">
                    <div className="space-y-4">
                        <div className="relative group">
                            <input
                                type="text"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                placeholder="USUARIO"
                                className="w-full px-6 py-5 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none"
                                required
                            />
                        </div>
                        <div className="relative group">
                            <input
                                type={showPassword ? "text" : "password"}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="CONTRASEÑA"
                                className="w-full px-6 py-5 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none pr-14"
                                required
                            />
                            <button 
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-600 hover:text-brand transition-colors"
                            >
                                {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                            </button>
                        </div>
                    </div>

                    {error && (
                        <p className="text-brand text-[10px] font-black uppercase text-center tracking-widest animate-pulse">{error}</p>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-5 bg-brand text-white text-sm font-black rounded-2xl shadow-[0_0_30px_rgba(232,21,220,0.3)] hover:shadow-[0_0_40px_rgba(232,21,220,0.5)] active:scale-95 transition-all disabled:opacity-50 tracking-widest"
                    >
                        {loading ? <Spinner /> : (isLogin ? 'ENTRAR' : 'CREAR CUENTA')}
                    </button>
                </form>

                <div className="text-center pt-4">
                    <button
                        onClick={() => setIsLogin(!isLogin)}
                        className="text-[10px] font-black text-gray-500 hover:text-brand transition-colors uppercase tracking-[0.2em]"
                    >
                        {isLogin ? '¿No tienes cuenta? Regístrate' : '¿Ya tienes cuenta? Accede'}
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { InventoryItem } from '../types';
import { Spinner, PlusIcon, TrashIcon } from './Icons';

export const InventoryManager: React.FC = () => {
    const [items, setItems] = useState<InventoryItem[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchInventory = async () => {
        const { data } = await supabase.from('inventory').select('*').order('category');
        if (data) setItems(data);
        setLoading(false);
    };

    useEffect(() => { fetchInventory(); }, []);

    const updateStock = async (id: number, val: number) => {
        if (val < 0) return;
        await supabase.from('inventory').update({ quantity: val }).eq('id', id);
        fetchInventory();
    };

    if (loading) return (
        <div className="flex justify-center items-center h-40">
            <Spinner />
        </div>
    );

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-[0.3em] text-brand">Gestión de Insumos</h2>
                <button className="flex items-center gap-2 bg-brand/10 border border-brand/40 px-5 py-2 rounded-xl text-white text-[10px] font-black uppercase tracking-widest shadow-lg shadow-brand/10 hover:bg-brand/20 transition-all">
                    <PlusIcon className="w-4 h-4" /> Nuevo
                </button>
            </div>

            <div className="bg-black border border-white/5 rounded-3xl overflow-hidden shadow-2xl">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-white/5 text-[9px] uppercase font-black text-gray-500 tracking-widest">
                            <tr>
                                <th className="px-6 py-5">Material</th>
                                <th className="px-6 py-5 text-center">Stock</th>
                                <th className="px-6 py-5 text-center">Mín.</th>
                                <th className="px-6 py-5 text-right">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {items.map(item => (
                                <tr key={item.id} className={`transition-colors hover:bg-white/[0.02] ${item.quantity < item.min_stock ? 'bg-brand/[0.03]' : ''}`}>
                                    <td className="px-6 py-6">
                                        <p className="font-bold text-white text-sm">{item.item_name}</p>
                                        <p className="text-[9px] text-gray-600 uppercase tracking-widest mt-1">{item.category}</p>
                                    </td>
                                    <td className="px-6 py-6">
                                        <div className="flex items-center justify-center gap-3">
                                            <button 
                                                onClick={() => updateStock(item.id, item.quantity - 1)} 
                                                className="w-8 h-8 rounded-lg border border-white/10 bg-black flex items-center justify-center text-gray-400 hover:border-brand hover:text-brand transition-all font-black"
                                            >-</button>
                                            <span className={`w-10 text-center font-black text-lg ${item.quantity < item.min_stock ? 'text-brand animate-pulse' : 'text-white'}`}>
                                                {item.quantity}
                                            </span>
                                            <button 
                                                onClick={() => updateStock(item.id, item.quantity + 1)} 
                                                className="w-8 h-8 rounded-lg border border-white/10 bg-black flex items-center justify-center text-gray-400 hover:border-brand hover:text-brand transition-all font-black"
                                            >+</button>
                                        </div>
                                    </td>
                                    <td className="px-6 py-6 text-center">
                                        <span className="text-[10px] font-black text-gray-500">{item.min_stock}</span>
                                    </td>
                                    <td className="px-6 py-6 text-right">
                                        <button className="text-gray-700 hover:text-brand transition-colors p-2">
                                            <TrashIcon />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
            {items.length === 0 && (
                <div className="text-center py-20 border border-dashed border-white/10 rounded-3xl">
                    <p className="text-gray-600 text-[10px] font-black uppercase tracking-widest">Sin materiales registrados</p>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef, useLayoutEffect } from 'react';
import type { Feature, UserRole } from './types';
import { OutlineCreator } from './components/OutlineCreator';
import { TattooPreviewer } from './components/TattooPreviewer';
import { DesignGenerator } from './components/DesignGenerator';
import { AiConsultant } from './components/AiConsultant';
import { DailyTips } from './components/DailyTips';
import { Gallery } from './components/Gallery';
import { Calendar } from './components/Calendar';
import { Clients } from './components/Clients';
import { AdminDashboard } from './components/AdminDashboard';
import { InventoryManager } from './components/InventoryManager';
import { FlashCatalog } from './components/FlashCatalog';
import { BudgetCalculator } from './components/BudgetCalculator';
import { AftercareGuide } from './components/AftercareGuide';
import { Auth } from './components/Auth';
import { 
    HomeIcon, 
    CalendarIcon, 
    ConsultantIcon, 
    ClientsIcon, 
    InventoryIcon, 
    FlashIcon, 
    BudgetIcon, 
    CareIcon, 
    DashboardIcon, 
    UserRoleIcon, 
    CloseIcon 
} from './components/Icons';

const App: React.FC = () => {
    const [user, setUser] = useState<{username: string, role: UserRole} | null>(() => {
        const saved = localStorage.getItem('bribiesca_user');
        return saved ? JSON.parse(saved) : null;
    });
    const [activeFeature, setActiveFeature] = useState<Feature>('home');
    const navBarRef = useRef<HTMLElement>(null);
    const [navBarHeight, setNavBarHeight] = useState(0);

    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showInstallPopup, setShowInstallPopup] = useState(false);

    useEffect(() => {
        if (user) {
            localStorage.setItem('bribiesca_user', JSON.stringify(user));
        } else {
            localStorage.removeItem('bribiesca_user');
        }
    }, [user]);

    // PWA Logic Improvement
    useEffect(() => {
        const handleBeforeInstallPrompt = (e: any) => {
            e.preventDefault();
            setDeferredPrompt(e);

            // Comprobar si ya está instalada (Standalone)
            const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;

            if (!isStandalone) {
                // Mostrar popup después de unos segundos
                setTimeout(() => setShowInstallPopup(true), 4000);
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

        // Listener secundario por si se pierde el evento inicial
        const timer = setTimeout(() => {
            if (!deferredPrompt && !window.matchMedia('(display-mode: standalone)').matches) {
                // Intentar forzar visibilidad en navegadores móviles si no se ha capturado el prompt
                setShowInstallPopup(true);
            }
        }, 10000);

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            clearTimeout(timer);
        };
    }, [deferredPrompt]);

    useLayoutEffect(() => {
        const updateHeight = () => setNavBarHeight(navBarRef.current?.offsetHeight || 0);
        updateHeight();
        window.addEventListener('resize', updateHeight);
        return () => window.removeEventListener('resize', updateHeight);
    }, []);

    const handleInstallClick = async () => {
        if (!deferredPrompt) {
            // Si no hay prompt nativo, informar al usuario (iOS / Safari)
            const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
            if (isIOS) {
                alert("Para instalar: Pulsa el botón de compartir y luego 'Añadir a pantalla de inicio'.");
            } else {
                alert("Usa el menú del navegador para instalar esta App.");
            }
            setShowInstallPopup(false);
            return;
        }
        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;
        if (outcome === 'accepted') {
            setDeferredPrompt(null);
            setShowInstallPopup(false);
        }
    };

    if (!user) {
        return <Auth onLogin={(username, role) => setUser({username, role})} />;
    }

    const adminMenu = [
        { id: 'dashboard', icon: <DashboardIcon />, label: 'Panel' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Agenda' },
        { id: 'inventory', icon: <InventoryIcon />, label: 'Stock' },
        { id: 'flash', icon: <FlashIcon />, label: 'Flash' },
        { id: 'clients', icon: <ClientsIcon />, label: 'Clientes' },
    ];

    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Diseños' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Reservar' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = user.role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8 animate-fade-in">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Generador IA" desc="Diseños exclusivos" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Previsualiza en piel" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Plantillas HD" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
                </div>
            );
            case 'dashboard': return <AdminDashboard />;
            case 'inventory': return <InventoryManager />;
            case 'calendar': return <Calendar adminMode={user.role === 'admin'} />;
            case 'clients': return <Clients />;
            case 'gallery': return <Gallery />;
            case 'consultant': return <AiConsultant />;
            case 'flash': return <FlashCatalog isAdmin={user.role === 'admin'} />;
            case 'budget': return <BudgetCalculator />;
            case 'aftercare': return <AftercareGuide />;
            case 'generate': return <DesignGenerator />;
            case 'preview': return <TattooPreviewer />;
            case 'outline': return <OutlineCreator />;
            default: return <div className="text-center py-20 opacity-50 uppercase tracking-widest text-[10px]">Cargando...</div>;
        }
    };

    return (
        <div className="min-h-screen flex flex-col bg-black text-white selection:bg-brand selection:text-white">
            <header className="sticky top-0 bg-black/95 backdrop-blur-2xl z-40 p-3 border-b border-white/5 safe-top">
                <div className="max-w-4xl mx-auto flex justify-between items-center">
                    <div className="flex-1"></div>
                    <img 
                        src="https://appdesignmex.com/bribiesca.jpeg" 
                        alt="Bribiesca Logo" 
                        className="h-10 w-auto object-contain mx-auto transition-transform active:scale-95" 
                    />
                    <div className="flex-1 flex justify-end">
                        <button 
                            onClick={() => setUser(null)} 
                            className="p-2 rounded-full text-brand transition-all hover:scale-110 active:opacity-50"
                        >
                            <UserRoleIcon />
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 overflow-x-hidden bg-black" style={{ paddingBottom: `${navBarHeight + 40}px` }}>
                <div className="max-w-4xl mx-auto">
                    {renderFeature()}
                </div>
            </main>

            {showInstallPopup && (
                <div className="fixed bottom-24 left-4 right-4 z-[100] animate-fade-in">
                    <div className="bg-[#050505] border border-brand/50 rounded-3xl p-5 shadow-[0_0_30px_rgba(232,21,220,0.3)] flex items-center justify-between">
                        <div className="flex items-center space-x-4">
                            <div className="relative">
                                <img src="https://appdesignmex.com/bribiescaicono.png" className="w-12 h-12 rounded-2xl border border-brand/20 shadow-lg" alt="App Icon" />
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-brand rounded-full animate-ping"></div>
                            </div>
                            <div>
                                <h3 className="font-black text-[11px] uppercase tracking-widest text-white">Bribiesca Studio</h3>
                                <p className="text-[9px] text-gray-500 uppercase tracking-widest font-bold">Instalar aplicación</p>
                            </div>
                        </div>
                        <div className="flex space-x-2">
                            <button onClick={() => setShowInstallPopup(false)} className="p-2 text-gray-600 hover:text-white">
                                <CloseIcon className="w-5 h-5" />
                            </button>
                            <button 
                                onClick={handleInstallClick} 
                                className="bg-brand text-white px-5 py-2.5 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] shadow-lg shadow-brand/30 active:scale-95 transition-all"
                            >
                                Instalar
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <nav ref={navBarRef} className="fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-3xl border-t border-white/5 z-50 safe-bottom">
                <div className="max-w-4xl mx-auto grid grid-cols-5 h-20">
                    {currentMenu.map(item => (
                        <button key={item.id} onClick={() => setActiveFeature(item.id as Feature)} 
                                className={`flex flex-col items-center justify-center space-y-1.5 transition-all ${activeFeature === item.id ? 'text-brand scale-110' : 'text-gray-600 hover:text-gray-400'}`}>
                            <div className="w-5 h-5">{item.icon}</div>
                            <span className="text-[8px] font-black uppercase tracking-[0.2em]">{item.label}</span>
                        </button>
                    ))}
                </div>
            </nav>
        </div>
    );
};

const FeatureCard = ({ title, desc, icon, onClick }: any) => (
    <button onClick={onClick} className="flex items-center p-6 bg-black border border-white/5 rounded-3xl text-left hover:border-brand/40 transition-all group shadow-2xl active:scale-[0.98]">
        <div className="p-4 bg-brand/[0.03] rounded-2xl mr-4 group-hover:bg-brand/[0.07] transition-colors shadow-[0_0_20px_rgba(232,21,220,0.03)] text-brand border border-white/5">
            {icon}
        </div>
        <div>
            <h4 className="font-black text-xs uppercase tracking-widest text-white mb-1 tracking-[0.1em]">{title}</h4>
            <p className="text-[10px] text-gray-500 uppercase tracking-tighter font-bold opacity-60">{desc}</p>
        </div>
    </button>
);

export default App;

