import { 
    HomeIcon, 
    CalendarIcon, 
    ConsultantIcon, 
    ClientsIcon, 
    InventoryIcon, 
    FlashIcon, 
    BudgetIcon, 
    CareIcon, 
    DashboardIcon, 
    UserRoleIcon, 
    CloseIcon 
} from './components/Icons';

const App: React.FC = () => {
    const [user, setUser] = useState<{username: string, role: UserRole} | null>(() => {
        const saved = localStorage.getItem('bribiesca_user');
        return saved ? JSON.parse(saved) : null;
    });
    const [activeFeature, setActiveFeature] = useState<Feature>('home');
    const navBarRef = useRef<HTMLElement>(null);
    const [navBarHeight, setNavBarHeight] = useState(0);

    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [showInstallPopup, setShowInstallPopup] = useState(false);

    useEffect(() => {
        if (user) {
            localStorage.setItem('bribiesca_user', JSON.stringify(user));
        } else {
            localStorage.removeItem('bribiesca_user');
        }
    }, [user]);

    // Enhanced PWA Logic
    useEffect(() => {
        const handleBeforeInstallPrompt = (e: any) => {
            console.log('Capture beforeinstallprompt');
            e.preventDefault();
            setDeferredPrompt(e);

            const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
            if (!isStandalone) {
                setTimeout(() => setShowInstallPopup(true), 3000);
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

        // Fallback for browsers that don't trigger the event immediately
        const timer = setTimeout(() => {
            const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
            if (!isStandalone && !showInstallPopup) {
                setShowInstallPopup(true);
            }
        }, 8000);

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            clearTimeout(timer);
        };
    }, [showInstallPopup]);

    useLayoutEffect(() => {
        const updateHeight = () => setNavBarHeight(navBarRef.current?.offsetHeight || 0);
        updateHeight();
        window.addEventListener('resize', updateHeight);
        return () => window.removeEventListener('resize', updateHeight);
    }, []);

    const handleInstallClick = async () => {
        if (!deferredPrompt) {
            const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
            if (isIOS) {
                alert("INSTALACIÓN EN IOS:\n1. Pulsa el botón de 'Compartir' (cuadrado con flecha).\n2. Selecciona 'Añadir a pantalla de inicio'.");
            } else {
                alert("Usa el menú del navegador para instalar esta App (Instalar o Añadir a pantalla de inicio).");
            }
            setShowInstallPopup(false);
            return;
        }
        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;
        if (outcome === 'accepted') {
            setDeferredPrompt(null);
            setShowInstallPopup(false);
        }
    };

    if (!user) {
        return <Auth onLogin={(username, role) => setUser({username, role})} />;
    }

    const adminMenu = [
        { id: 'dashboard', icon: <DashboardIcon />, label: 'Panel' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Agenda' },
        { id: 'inventory', icon: <InventoryIcon />, label: 'Stock' },
        { id: 'flash', icon: <FlashIcon />, label: 'Flash' },
        { id: 'clients', icon: <ClientsIcon />, label: 'Clientes' },
    ];

    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Diseños' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Reservar' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = user.role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8 animate-fade-in">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Generador IA" desc="Diseños exclusivos" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Previsualiza en piel" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Plantillas HD" icon={<DashboardIcon className="w-6 h-6" />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
                </div>
            );
            case 'dashboard': return <AdminDashboard />;
            case 'inventory': return <InventoryManager />;
            case 'calendar': return <Calendar adminMode={user.role === 'admin'} />;
            case 'clients': return <Clients />;
            case 'gallery': return <Gallery />;
            case 'consultant': return <AiConsultant />;
            case 'flash': return <FlashCatalog isAdmin={user.role === 'admin'} />;
            case 'budget': return <BudgetCalculator />;
            case 'aftercare': return <AftercareGuide />;
            case 'generate': return <DesignGenerator />;
            case 'preview': return <TattooPreviewer />;
            case 'outline': return <OutlineCreator />;
            default: return <div className="text-center py-20 opacity-50 uppercase tracking-widest text-[10px]">Cargando...</div>;
        }
    };

    return (
        <div className="min-h-screen flex flex-col bg-black text-white selection:bg-brand selection:text-white">
            <header className="sticky top-0 bg-black/95 backdrop-blur-2xl z-40 p-3 border-b border-white/5 safe-top">
                <div className="max-w-4xl mx-auto flex justify-between items-center">
                    <div className="flex-1"></div>
                    <img 
                        src="https://appdesignmex.com/bribiesca.jpeg" 
                        alt="Bribiesca Logo" 
                        className="h-10 w-auto object-contain mx-auto transition-transform active:scale-95" 
                    />
                    <div className="flex-1 flex justify-end">
                        <button 
                            onClick={() => setUser(null)} 
                            className="p-2 rounded-full text-brand transition-all hover:scale-110 active:opacity-50"
                        >
                            <UserRoleIcon />
                        </button>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 overflow-x-hidden bg-black" style={{ paddingBottom: `${navBarHeight + 40}px` }}>
                <div className="max-w-4xl mx-auto">
                    {renderFeature()}
                </div>
            </main>

            {showInstallPopup && (
                <div className="fixed bottom-24 left-4 right-4 z-[100] animate-fade-in">
                    <div className="bg-[#050505] border border-brand/50 rounded-3xl p-5 shadow-[0_0_40px_rgba(232,21,220,0.4)] flex items-center justify-between">
                        <div className="flex items-center space-x-4">
                            <div className="relative">
                                <img src="https://appdesignmex.com/bribiescaicono.png" className="w-12 h-12 rounded-2xl border border-brand/40 shadow-[0_0_15px_rgba(232,21,220,0.2)]" alt="App Icon" />
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-brand rounded-full animate-ping"></div>
                            </div>
                            <div>
                                <h3 className="font-black text-[11px] uppercase tracking-widest text-white">Bribiesca Studio</h3>
                                <p className="text-[9px] text-brand uppercase tracking-widest font-black opacity-60">Instalar App Oficial</p>
                            </div>
                        </div>
                        <div className="flex space-x-2">
                            <button onClick={() => setShowInstallPopup(false)} className="p-2 text-gray-600 hover:text-white">
                                <CloseIcon className="w-5 h-5" />
                            </button>
                            <button 
                                onClick={handleInstallClick} 
                                className="bg-brand text-white px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.1em] shadow-lg shadow-brand/30 active:scale-95 transition-all"
                            >
                                Instalar
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <nav ref={navBarRef} className="fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-3xl border-t border-white/5 z-50 safe-bottom">
                <div className="max-w-4xl mx-auto grid grid-cols-5 h-20">
                    {currentMenu.map(item => (
                        <button key={item.id} onClick={() => setActiveFeature(item.id as Feature)} 
                                className={`flex flex-col items-center justify-center space-y-1.5 transition-all ${activeFeature === item.id ? 'text-brand scale-110' : 'text-gray-600 hover:text-gray-400'}`}>
                            <div className="w-5 h-5">{item.icon}</div>
                            <span className="text-[8px] font-black uppercase tracking-[0.2em]">{item.label}</span>
                        </button>
                    ))}
                </div>
            </nav>
        </div>
    );
};

