import React, { useState, useRef } from 'react';
import { jsPDF } from 'jspdf';
import { CheckIcon, Spinner, CloseIcon } from './Icons';

export const ConsentForms: React.FC = () => {
    const [clientName, setClientName] = useState('');
    const [isSigned, setIsSigned] = useState(false);
    const [signing, setSigning] = useState(false);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const clearSignature = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx && canvasRef.current) {
            ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
            setIsSigned(false);
        }
    };

    const handleSign = () => {
        setIsSigned(true);
    };

    const generatePDF = async () => {
        setSigning(true);
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.text('CONSENTIMIENTO INFORMADO', 20, 20);
        doc.setFontSize(12);
        doc.text(`Cliente: ${clientName}`, 20, 40);
        doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 20, 50);
        doc.text('El cliente declara no padecer enfermedades infectocontagiosas y acepta los riesgos del procedimiento...', 20, 70, { maxWidth: 170 });

        if (canvasRef.current) {
            const sigData = canvasRef.current.toDataURL('image/png');
            doc.text('Firma del Cliente:', 20, 150);
            doc.addImage(sigData, 'PNG', 20, 160, 50, 20);
        }

        doc.save(`consentimiento-${clientName}.pdf`);
        setSigning(false);
        alert("Documento generado y guardado.");
    };

    return (
        <div className="space-y-6 animate-fade-in max-w-2xl mx-auto pb-10">
            <header className="text-center">
                <h2 className="text-2xl font-black text-brand italic tracking-tighter">CONSENTIMIENTO DIGITAL</h2>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">Validez Legal Studio & Beauty Artist</p>
            </header>

            <div className="bg-[#050505] border border-white/5 p-8 rounded-3xl space-y-6 shadow-2xl">
                <div>
                    <label className="block text-[10px] font-black uppercase text-gray-500 mb-2 tracking-widest">Nombre Completo del Cliente</label>
                    <input 
                        type="text" 
                        value={clientName} 
                        onChange={(e) => setClientName(e.target.value)}
                        placeholder="EJ. MARÍA GARCÍA"
                        className="w-full p-5 rounded-2xl bg-black border border-white/10 text-white font-bold"
                    />
                </div>

                <div className="prose prose-invert max-h-48 overflow-y-auto bg-black p-6 rounded-2xl border border-white/5 text-[11px] leading-relaxed text-gray-400 font-medium">
                    <p className="font-bold text-white mb-2">CLÁUSULAS IMPORTANTES:</p>
                    <p>1. Confirmo que soy mayor de edad y estoy en pleno uso de mis facultades mentales.</p>
                    <p>2. No he consumido alcohol ni drogas en las últimas 24 horas.</p>
                    <p>3. Entiendo que un tatuaje es permanente y los riesgos de infección si no sigo los cuidados.</p>
                    <p>4. Libero a Bribiesca Studio de cualquier responsabilidad legal derivada de reacciones alérgicas no reportadas.</p>
                </div>

                <div className="space-y-2">
                    <label className="block text-[10px] font-black uppercase text-gray-500 mb-2 tracking-widest text-center">Firma Táctil Aquí</label>
                    <div className="relative bg-white rounded-2xl h-40 overflow-hidden cursor-crosshair">
                        <canvas 
                            ref={canvasRef}
                            width={500}
                            height={160}
                            onMouseDown={handleSign}
                            onTouchStart={handleSign}
                            className="w-full h-full"
                        ></canvas>
                        {!isSigned && <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-300 text-[10px] uppercase font-black">Área de Firma</div>}
                    </div>
                    <button onClick={clearSignature} className="w-full text-[9px] font-black text-brand uppercase tracking-widest pt-2">Limpiar Firma</button>
                </div>

                <button 
                    onClick={generatePDF}
                    disabled={!clientName || !isSigned || signing}
                    className="w-full py-5 bg-brand text-white font-black rounded-2xl shadow-[0_0_30px_rgba(232,21,220,0.3)] disabled:opacity-30 tracking-widest uppercase flex justify-center items-center"
                >
                    {signing ? <Spinner /> : 'Finalizar y Generar PDF'}
                </button>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
