    );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Client } from '../types';
import { getAll, add, put, deleteItem } from '../utils/db';
import { PlusIcon, UserIcon, CloseIcon, PencilIcon, TrashIcon, SearchIcon, CheckIcon } from './Icons';

export const Clients: React.FC = () => {
    const [clients, setClients] = useState<Client[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedClient, setSelectedClient] = useState<Client | null>(null);
    const [formData, setFormData] = useState({ name: '', contact: '', notes: '', allergies: '' });
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => { loadClients(); }, []);

    const loadClients = async () => {
        try {
            const allClients = await getAll<Client>('clients');
            setClients(allClients.sort((a, b) => a.name.localeCompare(b.name)));
        } catch (error) { console.error(error); } finally { setIsLoading(false); }
    };

    const handleSaveClient = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (selectedClient) {
                await put('clients', { ...selectedClient, ...formData });
            } else {
                await add('clients', { ...formData, createdAt: new Date().toISOString() });
            }
            await loadClients();
            setIsModalOpen(false);
        } catch (error) { alert("Error al guardar."); }
    };

    const filteredClients = useMemo(() => {
        return clients.filter(client => client.name.toLowerCase().includes(searchTerm.toLowerCase()));
