import React, { useState, useRef, useEffect } from 'react';
import { jsPDF } from 'jspdf';
import { supabase } from '../utils/supabase';
import { Consent, Client } from '../types';
import { CheckIcon, Spinner, CloseIcon, PencilIcon, SaveIcon, SendIcon } from './Icons';

interface ConsentFormsProps {
    userRole: 'admin' | 'client';
    username: string;
}

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [consentText, setConsentText] = useState(`Yo, [NOMBRE_CLIENTE], declaro estar en pleno uso de mis facultades y acepto realizarme un procedimiento de tatuaje/belleza en Bribiesca Studio. 

Entiendo los riesgos de infección, alergias y cicatrización. Me comprometo a seguir las instrucciones de cuidado posterior proporcionadas.`);

    const [isSaving, setIsSaving] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchMyPendingConsents();
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*');
        if (data) setClients(data);
    };

    const fetchMyPendingConsents = async () => {
        // En un escenario real buscaríamos por un ID vinculado al usuario, 
        // aquí simulamos por nombre para la demo
        const { data } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'pending');
        if (data) setPendingConsents(data);
    };

    const handlePrepareConsent = async () => {
        if (!selectedClientId || !consentText) return;
        setIsSaving(true);
        const client = clients.find(c => c.id === Number(selectedClientId));

        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_name: client?.name,
            content: finalizedText,
            status: 'pending',
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert(`Consentimiento enviado a ${client?.name}`);
            setSelectedClientId('');
        }
        setIsSaving(false);
    };

    // Signature Logic
    const startDrawing = (e: any) => {
        setIsDrawing(true);
        draw(e);
    };

    const stopDrawing = () => {
        setIsDrawing(false);
        const canvas = canvasRef.current;
        if (canvas) {
            const ctx = canvas.getContext('2d');
            ctx?.beginPath();
        }
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current) return;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const rect = canvas.getBoundingClientRect();
        const x = (e.clientX || e.touches[0].clientX) - rect.left;
        const y = (e.clientY || e.touches[0].clientY) - rect.top;

        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';

        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSignSubmit = async () => {
        if (!activeConsent || !canvasRef.current) return;
        setIsSaving(true);

        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            // Notificar al admin (esto se reflejará en su dashboard)
            alert("¡Documento firmado con éxito! Gracias por tu confianza.");
            setActiveConsent(null);
            fetchMyPendingConsents();
        }
        setIsSaving(false);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in max-w-4xl mx-auto">
                <header>
                    <h2 className="text-2xl font-black text-white italic tracking-tighter uppercase">Preparar Documentación</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest opacity-80">Generación de Consentimientos</p>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-1 space-y-4">
                        <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">1. Seleccionar Cliente</label>
                        <select 
                            value={selectedClientId} 
                            onChange={(e) => setSelectedClientId(e.target.value)}
                            className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold"
                        >
                            <option value="">ELEGIR CLIENTE...</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <div className="p-5 bg-brand/5 border border-brand/20 rounded-2xl">
                            <p className="text-[9px] text-brand font-black uppercase tracking-widest leading-relaxed">
                                Tip: Usa [NOMBRE_CLIENTE] en el texto para que la App lo complete automáticamente.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-4">
                        <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">2. Personalizar Texto Legal</label>
                        <textarea 
                            value={consentText}
                            onChange={(e) => setConsentText(e.target.value)}
                            className="w-full h-64 bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none"
                        ></textarea>
                        <button 
                            onClick={handlePrepareConsent}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-5 bg-brand text-white font-black rounded-2xl uppercase tracking-widest shadow-xl shadow-brand/20 flex items-center justify-center gap-3"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> Enviar al Cliente</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    // VISTA CLIENTE
    return (
        <div className="space-y-6 animate-fade-in max-w-2xl mx-auto">
            {!activeConsent ? (
                <div className="space-y-4">
                    <h2 className="text-xl font-black text-white italic tracking-tighter uppercase text-center">Tus Documentos</h2>
                    {pendingConsents.length === 0 ? (
                        <div className="p-12 text-center border border-dashed border-white/10 rounded-3xl bg-black">
                            <p className="text-gray-600 text-[10px] font-black uppercase tracking-widest">No tienes firmas pendientes</p>
                        </div>
                    ) : (
                        pendingConsents.map(c => (
                            <div key={c.id} onClick={() => setActiveConsent(c)} className="p-6 bg-brand/5 border border-brand/30 rounded-3xl flex justify-between items-center cursor-pointer hover:scale-[1.02] transition-all">
                                <div>
                                    <p className="text-[10px] text-brand font-black uppercase tracking-widest">PENDIENTE DE FIRMA</p>
                                    <h3 className="text-white font-black uppercase text-sm mt-1">Consentimiento Procedimiento</h3>
                                </div>
                                <PencilIcon className="text-brand w-6 h-6" />
                            </div>
                        ))
                    )}
                </div>
            ) : (
                <div className="bg-[#050505] p-8 rounded-3xl border border-brand/50 shadow-2xl space-y-8">
                    <div className="flex justify-between items-start">
                        <h3 className="text-lg font-black text-brand italic uppercase">Firma de Consentimiento</h3>
                        <button onClick={() => setActiveConsent(null)}><CloseIcon /></button>
                    </div>

                    <div className="prose prose-invert bg-black p-6 rounded-2xl border border-white/5 max-h-64 overflow-y-auto text-sm leading-relaxed text-gray-400">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-3">
                        <p className="text-[10px] font-black uppercase text-gray-500 tracking-widest text-center">Firma Táctil Aquí</p>
                        <div className="relative bg-white rounded-2xl h-48 overflow-hidden touch-none border-4 border-brand/20">
                            <canvas 
                                ref={canvasRef}
                                width={600}
                                height={200}
                                className="w-full h-full cursor-crosshair"
                                onMouseDown={startDrawing}
                                onMouseMove={draw}
                                onMouseUp={stopDrawing}
                                onMouseOut={stopDrawing}
                                onTouchStart={startDrawing}
                                onTouchMove={draw}
                                onTouchEnd={stopDrawing}
                            ></canvas>
                        </div>
                        <button onClick={() => {
                            const ctx = canvasRef.current?.getContext('2d');
                            ctx?.clearRect(0, 0, 600, 200);
                        }} className="w-full text-[9px] font-black text-brand uppercase tracking-widest text-center">Limpiar y Reintentar</button>
                    </div>

                    <button 
                        onClick={handleSignSubmit}
                        disabled={isSaving}
                        className="w-full py-5 bg-brand text-white font-black rounded-2xl uppercase tracking-widest shadow-xl shadow-brand/30 flex justify-center items-center"
                    >
                        {isSaving ? <Spinner /> : 'Finalizar y Guardar en App'}
                    </button>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ 
        appointments: 0, 
        revenue: 0, 
        lowStock: 0, 
        newClients: 0,
        confirmedRatio: 0
    });
    const [recentConsents, setRecentConsents] = useState<Consent[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            const { data: apps } = await supabase.from('appointments').select('*');
            const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
            const { data: clients } = await supabase.from('clients').select('*');
            const { data: consents } = await supabase
                .from('consents')
                .select('*')
                .eq('status', 'signed')
                .order('signed_at', { ascending: false })
                .limit(3);

            const confirmed = apps?.filter(a => a.deposit_paid).length || 0;
            const total = apps?.length || 1;

            if (consents) setRecentConsents(consents);

            setStats({
                appointments: apps?.filter(a => a.status === 'scheduled').length || 0,
                revenue: apps?.filter(a => a.status === 'completed').reduce((acc, curr) => acc + (curr.price_total || 150), 0) || 0,
                lowStock: stock?.length || 0,
                newClients: clients?.length || 0,
                confirmedRatio: Math.round((confirmed / total) * 100)
            });
            setLoading(false);
        };
        fetchStats();
    }, []);

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black tracking-tighter text-white italic">DASHBOARD</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em] opacity-80">Rendimiento en tiempo real</p>
                </div>
                <div className="text-right">
                    <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">Estado del Studio</p>
                    <p className="text-xs font-black text-green-500 uppercase">● Operativo Pro</p>
                </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS ACTIVAS" value={stats.appointments} icon={<CalendarIcon />} trend="+12%" />
                <StatCard title="INGRESOS MES" value={`$${stats.revenue}`} icon={<CheckIcon />} trend="+5%" />
                <StatCard title="CONFIRMACIÓN" value={`${stats.confirmedRatio}%`} icon={<CheckIcon />} trend="PAGOS" />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} trend="ACTIVOS" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-[#050505] p-8 rounded-3xl border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-6 flex items-center gap-3 text-white uppercase tracking-widest text-[11px]">
                        <CheckIcon className="w-5 h-5 text-brand"/> Firmas de Clientes (Notificaciones)
                    </h3>
                    <div className="space-y-4">
                        {recentConsents.length === 0 ? (
                            <p className="text-[10px] text-gray-600 font-black uppercase tracking-widest text-center py-10">Sin firmas recientes</p>
                        ) : (
                            recentConsents.map(c => (
                                <div key={c.id} className="p-4 bg-white/5 rounded-2xl border border-white/5 flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand">
                                            <PencilIcon className="w-5 h-5"/>
                                        </div>
                                        <div>
                                            <p className="text-xs font-black text-white uppercase">{c.client_name}</p>
                                            <p className="text-[9px] text-gray-500 uppercase">Firmado el {new Date(c.signed_at!).toLocaleDateString()}</p>
                                        </div>
                                    </div>
                                    <div className="bg-black p-2 rounded-lg border border-white/10">
                                        <img src={c.signature} className="h-6 w-auto invert" alt="Firma" />
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>

                <div className={`bg-[#050505] p-8 rounded-3xl border ${stats.lowStock > 0 ? 'border-brand/40 animate-pulse' : 'border-white/5'} shadow-2xl`}>
                    <h3 className="font-black mb-6 flex items-center gap-3 text-white uppercase tracking-widest text-[11px]">
                        <InventoryIcon className="w-5 h-5 text-brand"/> Monitor de Insumos
                    </h3>
                    {stats.lowStock > 0 ? (
                        <div className="space-y-4">
                            <div className="p-4 bg-brand/10 text-brand rounded-2xl text-[10px] font-black border border-brand/20 uppercase tracking-widest text-center shadow-[0_0_20px_rgba(232,21,220,0.2)]">
                                ¡ALERTA! REVISIÓN NECESARIA: {stats.lowStock} PRODUCTOS.
                            </div>
                            <button className="w-full py-4 bg-white/5 rounded-2xl text-[9px] font-black text-white uppercase hover:bg-brand transition-all">Ver Inventario Crítico</button>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-40 text-center">
                            <div className="w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center text-green-500 mb-4">
                                <CheckIcon />
                            </div>
                            <p className="text-gray-500 text-[10px] font-black uppercase tracking-widest">Stock Optimizado</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

