    const clientMenu = [
        { id: 'home', icon: <HomeIcon />, label: 'Inicio' },
        { id: 'flash', icon: <FlashIcon />, label: 'Catálogo' },
        { id: 'calendar', icon: <CalendarIcon />, label: 'Citas' },
        { id: 'budget', icon: <BudgetIcon />, label: 'Precio' },
        { id: 'aftercare', icon: <CareIcon />, label: 'Cuidados' },
    ];

    const currentMenu = user.role === 'admin' ? adminMenu : clientMenu;

    const renderFeature = () => {
        switch (activeFeature) {
            case 'home': return (
                <div className="space-y-8 animate-fade-in">
                    <DailyTips />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FeatureCard title="Documentación Legal" desc="Consentimiento Digital" icon={<CheckIcon />} onClick={() => setActiveFeature('consent')} />
                        <FeatureCard title="Generador IA" desc="Diseños exclusivos" icon={<DashboardIcon />} onClick={() => setActiveFeature('generate')} />
                        <FeatureCard title="Probador AR" desc="Previsualiza en piel" icon={<DashboardIcon />} onClick={() => setActiveFeature('preview')} />
                        <FeatureCard title="Trazo Maestro" desc="Plantillas HD" icon={<DashboardIcon />} onClick={() => setActiveFeature('outline')} />
                        <FeatureCard title="Asistente PRO" desc="Consultas técnicas" icon={<ConsultantIcon />} onClick={() => setActiveFeature('consultant')} />
                    </div>
