import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, Client } from '../types';
import { CheckIcon, Spinner, CloseIcon, SendIcon, PencilIcon } from './Icons';

interface ConsentFormsProps {
    userRole: 'admin' | 'client';
    username: string;
}

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [isSaving, setIsSaving] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const [consentText, setConsentText] = useState(`Yo, [NOMBRE_CLIENTE], acepto los términos y condiciones de Bribiesca Studio para el procedimiento de tatuaje. He sido informado de los riesgos y cuidados posteriores.`);

    // Canvas para firma
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchMyPendingConsents();
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*');
        if (data) setClients(data);
    };

    const fetchMyPendingConsents = async () => {
        // En una app real filtraríamos por ID de usuario. 
        // Aquí buscamos documentos pendientes de firma.
        const { data } = await supabase.from('consents').select('*').eq('status', 'pending');
        if (data) setPendingConsents(data);
    };

    const handleSendToClient = async () => {
        if (!selectedClientId) return alert("Selecciona un cliente");
        setIsSaving(true);
        const client = clients.find(c => c.id === Number(selectedClientId));
        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_name: client?.name,
            content: finalizedText,
            status: 'pending'
        }]);

        if (!error) {
            alert(`Documento enviado a ${client?.name}`);
            setSelectedClientId('');
        }
        setIsSaving(false);
    };

    // Lógica de Firma (Canvas)
    const startDrawing = (e: any) => {
        setIsDrawing(true);
        draw(e);
    };

    const stopDrawing = () => {
        setIsDrawing(false);
        const ctx = canvasRef.current?.getContext('2d');
        ctx?.beginPath();
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current) return;
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const x = (e.clientX || e.touches[0].clientX) - rect.left;
        const y = (e.clientY || e.touches[0].clientY) - rect.top;

        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';

        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSaveSignature = async () => {
        if (!activeConsent || !canvasRef.current) return;
        setIsSaving(true);

        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            alert("¡Consentimiento firmado y guardado!");
            setActiveConsent(null);
            fetchMyPendingConsents();
        }
        setIsSaving(false);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in">
                <header>
                    <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Preparar Consentimiento</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Editor de Documentación</p>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-1 space-y-4">
                        <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Elegir Cliente</label>
                        <select 
                            value={selectedClientId} 
                            onChange={(e) => setSelectedClientId(e.target.value)}
                            className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold"
                        >
                            <option value="">SELECCIONAR...</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                        <div className="p-4 bg-brand/5 border border-brand/20 rounded-2xl">
                            <p className="text-[9px] text-brand font-black uppercase tracking-tighter leading-relaxed">
                                El cliente verá este documento al iniciar sesión en su cuenta.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-4">
                        <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Contenido Legal</label>
                        <textarea 
                            value={consentText}
                            onChange={(e) => setConsentText(e.target.value)}
                            className="w-full h-48 bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed"
                        ></textarea>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-5 bg-brand text-white font-black rounded-2xl uppercase tracking-widest shadow-xl flex justify-center items-center gap-3"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> Enviar al Dashboard del Cliente</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto space-y-6 animate-fade-in">
            {!activeConsent ? (
                <div className="space-y-4">
                    <h2 className="text-xl font-black text-white italic uppercase text-center">Firma de Documentos</h2>
                    {pendingConsents.length === 0 ? (
                        <div className="p-12 text-center border border-dashed border-white/10 rounded-3xl opacity-50">
                            <p className="text-[10px] font-black uppercase tracking-widest">No tienes firmas pendientes</p>
                        </div>
                    ) : (
                        pendingConsents.map(c => (
                            <button key={c.id} onClick={() => setActiveConsent(c)} className="w-full p-6 bg-brand/10 border border-brand/30 rounded-3xl flex justify-between items-center group transition-all">
                                <div className="text-left">
                                    <p className="text-[9px] text-brand font-black uppercase tracking-widest">Pendiente de Firma</p>
                                    <h3 className="text-white font-black uppercase text-sm">Consentimiento Estudio</h3>
                                </div>
                                <PencilIcon className="text-brand w-6 h-6 group-hover:scale-125 transition-transform" />
                            </button>
                        ))
                    )}
                </div>
            ) : (
                <div className="bg-[#050505] p-8 rounded-[2.5rem] border border-brand/40 shadow-2xl space-y-8">
                    <div className="flex justify-between items-center">
                        <h3 className="text-lg font-black text-brand italic uppercase">Firma Digital</h3>
                        <button onClick={() => setActiveConsent(null)}><CloseIcon /></button>
                    </div>

                    <div className="bg-black p-6 rounded-2xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-48 overflow-y-auto">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-3">
                        <p className="text-[10px] font-black uppercase text-gray-500 tracking-widest text-center">Firma aquí con tu dedo</p>
                        <div className="bg-white rounded-2xl h-48 overflow-hidden touch-none border-4 border-brand/20">
                            <canvas 
                                ref={canvasRef}
                                width={600}
                                height={200}
                                className="w-full h-full cursor-crosshair"
                                onMouseDown={startDrawing}
                                onMouseMove={draw}
                                onMouseUp={stopDrawing}
                                onMouseOut={stopDrawing}
                                onTouchStart={startDrawing}
                                onTouchMove={draw}
                                onTouchEnd={stopDrawing}
                            ></canvas>
                        </div>
                        <button onClick={() => canvasRef.current?.getContext('2d')?.clearRect(0,0,600,200)} className="w-full text-[9px] font-black text-brand uppercase tracking-widest">Borrar y Reintentar</button>
                    </div>

                    <button 
                        onClick={handleSaveSignature}
                        disabled={isSaving}
                        className="w-full py-5 bg-brand text-white font-black rounded-2xl uppercase tracking-widest shadow-xl flex justify-center items-center"
                    >
                        {isSaving ? <Spinner /> : 'Guardar Firma en Bribiesca Studio'}
                    </button>
                </div>
            )}
        </div>
    );
};

