import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, Client } from '../types';
import { CheckIcon, Spinner, CloseIcon, SendIcon, PencilIcon, SaveIcon } from './Icons';

interface ConsentFormsProps {
    userRole: 'admin' | 'client';
    username: string;
}

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [isSaving, setIsSaving] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const [consentText, setConsentText] = useState(`Yo, [NOMBRE_CLIENTE], acepto los términos y condiciones de Bribiesca Studio para el procedimiento de tatuaje. He sido informado de los riesgos y cuidados posteriores.`);

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchMyPendingConsents();
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*');
        if (data) setClients(data);
    };

    const fetchMyPendingConsents = async () => {
        // Buscamos documentos donde el nombre del cliente coincida con el username logueado
        const { data } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'pending')
            .eq('client_name', username);
        if (data) setPendingConsents(data);
    };

    const handleSendToClient = async () => {
        if (!selectedClientId) return alert("Selecciona un cliente");
        setIsSaving(true);
        const client = clients.find(c => c.id === Number(selectedClientId));
        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_name: client?.name,
            content: finalizedText,
            status: 'pending',
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert(`¡Documento enviado con éxito a ${client?.name}!`);
            setSelectedClientId('');
        } else {
            alert("Error al enviar: " + error.message);
        }
        setIsSaving(false);
    };

    // --- Lógica de Firma Canvas ---
    const startDrawing = (e: any) => {
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(e);
    };

    const stopDrawing = () => {
        setIsDrawing(false);
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current) return;
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);

        const x = clientX - rect.left;
        const y = clientY - rect.top;

        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC'; // Color de marca

        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSaveSignature = async () => {
        if (!activeConsent || !canvasRef.current) return;

        // Verificar si el canvas está vacío (opcional, pero recomendado)
        setIsSaving(true);
        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            alert("Tu consentimiento ha sido firmado y guardado correctamente.");
            setActiveConsent(null);
            fetchMyPendingConsents();
        } else {
            alert("Error al guardar firma: " + error.message);
        }
        setIsSaving(false);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in">
                <header className="flex justify-between items-center">
                    <div>
                        <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Editor de Consentimiento</h2>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Configuración y Envío</p>
                    </div>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-1 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">1. Destinatario</label>
                            <select 
                                value={selectedClientId} 
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold text-sm focus:border-brand transition-all"
                            >
                                <option value="">SELECCIONAR CLIENTE...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                        <div className="p-6 bg-brand/5 border border-brand/20 rounded-3xl">
                            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest mb-2 flex items-center gap-2">
                                <CheckIcon className="w-4 h-4" /> Instrucciones PRO
                            </h4>
                            <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
                                Redacta el contrato. El sistema reemplazará automáticamente <span className="text-brand font-bold">[NOMBRE_CLIENTE]</span> por el nombre real del cliente seleccionado.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">2. Texto Personalizado</label>
                            <textarea 
                                value={consentText}
                                onChange={(e) => setConsentText(e.target.value)}
                                className="w-full h-64 bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none focus:border-brand transition-all"
                                placeholder="Escribe las cláusulas legales aquí..."
                            ></textarea>
                        </div>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-[0_0_30px_rgba(232,21,220,0.3)] hover:scale-[1.01] active:scale-95 transition-all flex justify-center items-center gap-4 text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> Enviar Firma al Dashboard</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    // VISTA PARA ROL CLIENTE
    return (
        <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
            {!activeConsent ? (
                <div className="space-y-6">
                    <div className="text-center">
                        <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Documentos de {username}</h2>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Pendientes de Aceptación</p>
                    </div>

                    {pendingConsents.length === 0 ? (
                        <div className="p-16 text-center border-2 border-dashed border-white/5 rounded-[3rem] bg-black/40">
                            <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CheckIcon className="text-gray-700 w-8 h-8" />
                            </div>
                            <p className="text-gray-600 text-[10px] font-black uppercase tracking-[0.3em]">No hay documentos para firmar</p>
                        </div>
                    ) : (
                        <div className="grid gap-4">
                            {pendingConsents.map(c => (
                                <button 
                                    key={c.id} 
                                    onClick={() => setActiveConsent(c)} 
                                    className="w-full p-8 bg-brand/5 border border-brand/20 rounded-[2.5rem] flex justify-between items-center group transition-all hover:bg-brand/10 hover:border-brand/40"
                                >
                                    <div className="text-left">
                                        <p className="text-[10px] text-brand font-black uppercase tracking-[0.2em] mb-1">Requiere tu Firma</p>
                                        <h3 className="text-white font-black uppercase text-base tracking-tight">Consentimiento Legal del Studio</h3>
                                    </div>
                                    <div className="w-12 h-12 bg-brand/20 rounded-2xl flex items-center justify-center text-brand group-hover:scale-110 transition-transform">
                                        <PencilIcon />
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl space-y-8 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8">
                        <button onClick={() => setActiveConsent(null)} className="text-gray-500 hover:text-white transition-colors">
                            <CloseIcon className="w-6 h-6" />
                        </button>
                    </div>

                    <div>
                        <h3 className="text-xl font-black text-brand italic uppercase tracking-tighter mb-2">Firmar Documento</h3>
                        <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">Procedimiento Seguro Bribiesca</p>
                    </div>

                    <div className="bg-black p-8 rounded-3xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-64 overflow-y-auto custom-scrollbar italic">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-4">
                        <p className="text-[10px] font-black uppercase text-gray-600 tracking-[0.3em] text-center">Firma aquí (con tu dedo o mouse)</p>
                        <div className="bg-white rounded-[2rem] h-56 overflow-hidden touch-none border-4 border-brand/10 relative">
                            <canvas 
                                ref={canvasRef}
                                width={600}
                                height={224}
                                className="w-full h-full cursor-crosshair"
                                onMouseDown={startDrawing}
                                onMouseMove={draw}
                                onMouseUp={stopDrawing}
                                onMouseOut={stopDrawing}
                                onTouchStart={startDrawing}
                                onTouchMove={draw}
                                onTouchEnd={stopDrawing}
                            ></canvas>
                        </div>
                        <div className="flex justify-center">
                            <button 
                                onClick={() => {
                                    const ctx = canvasRef.current?.getContext('2d');
                                    if (canvasRef.current && ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                                }} 
                                className="text-[9px] font-black text-brand/60 uppercase tracking-widest border-b border-brand/20 hover:text-brand transition-colors"
                            >
                                Limpiar Lienzo
                            </button>
                        </div>
                    </div>

                    <button 
                        onClick={handleSaveSignature}
                        disabled={isSaving}
                        className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl shadow-brand/20 flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                    >
                        {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> Aceptar y Firmar</>}
                    </button>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [notifications, setNotifications] = useState<Consent[]>([]);
    const [newSignatureAlert, setNewSignatureAlert] = useState<string | null>(null);
