        fetchDashboardData();

        // --- Suscripción en Tiempo Real ---
        // Escuchamos actualizaciones en la tabla 'consents' para detectar cuando alguien firma
        const subscription = supabase
            .channel('consents_realtime')
            .on('postgres_changes', { 
                event: 'UPDATE', 
                schema: 'public', 
                table: 'consents',
                filter: 'status=eq.signed'
            }, (payload) => {
                const updatedConsent = payload.new as Consent;
                setNewSignatureAlert(updatedConsent.client_name);
                fetchDashboardData();

                // Limpiar alerta después de 5 segundos
                setTimeout(() => setNewSignatureAlert(null), 5000);
            })
            .subscribe();

        return () => { supabase.removeChannel(subscription); };
    }, []);

    const fetchDashboardData = async () => {
        const { data: apps } = await supabase.from('appointments').select('*');
        const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
        const { data: clients } = await supabase.from('clients').select('*');
        const { data: signs } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'signed')
            .order('signed_at', { ascending: false })
            .limit(5);

        if (signs) setNotifications(signs);
        setStats({
            appointments: apps?.length || 0,
            revenue: apps?.reduce((acc, curr) => acc + (curr.price_total || 0), 0) || 0,
