            {newSignatureAlert && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-4 rounded-full shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce font-black text-[10px] uppercase tracking-widest border-2 border-white/20">
                    🔔 ¡NUEVA FIRMA DE: {newSignatureAlert}!
                </div>
            )}

            <header className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Admin Panel</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em]">Control de Estudio Profesional</p>
                </div>
                <div className="bg-brand/10 border border-brand/30 px-5 py-2 rounded-full hidden md:block">
                    <p className="text-[9px] font-black text-brand uppercase tracking-widest">Sincronización Activa</p>
                </div>
            </header>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS" value={stats.appointments} icon={<CalendarIcon />} />
                <StatCard title="INGRESOS" value={`$${stats.revenue}`} icon={<CheckIcon />} />
                <StatCard title="STOCK BAJO" value={stats.lowStock} icon={<InventoryIcon />} color={stats.lowStock > 0 ? 'text-brand' : 'text-white'} />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Panel de Notificaciones de Firma */}
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-10">
                        <CheckIcon className="w-16 h-16" />
                    </div>
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <div className="w-2.5 h-2.5 bg-brand rounded-full animate-ping"></div> Historial de Firmas
                    </h3>
                    <div className="space-y-4">
                        {notifications.length === 0 ? (
                            <div className="p-12 text-center opacity-30">
                                <p className="text-[10px] font-black uppercase tracking-widest">Sin actividad reciente</p>
