import React, { useState } from 'react';
import { UserRole } from '../types';
import { Spinner, EyeIcon, EyeOffIcon, UserIcon, SendIcon } from './Icons';
import { supabase } from '../utils/supabase';

interface AuthProps {
    onLogin: (username: string, role: UserRole) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [showPassword, setShowPassword] = useState(false);

    // Form States
    const [fullName, setFullName] = useState('');
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [whatsapp, setWhatsapp] = useState('');
    const [password, setPassword] = useState('');

    const ADMIN_CREDENTIALS = [
        { user: 'johana_bribiesca', pass: '123_admin' },
        { user: 'harold_anguiano', pass: '123_admin' }
    ];

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            if (isLogin) {
                // Lógica de Login
                const adminUser = ADMIN_CREDENTIALS.find(c => c.user === username && c.pass === password);
                if (adminUser) {
                    onLogin(username, 'admin');
                } else if (username && password) {
                    onLogin(username, 'client');
                } else {
                    setError('Credenciales incorrectas');
                }
            } else {
                // Lógica de Registro
                // 1. Crear registro en la tabla de clientes de Supabase
                const { error: dbError } = await supabase.from('clients').insert([{
                    name: fullName,
                    contact: email,
                    notes: `Usuario: ${username} | WhatsApp: ${whatsapp}`,
                    createdAt: new Date().toISOString()
                }]);

                if (dbError) throw dbError;

                // 2. Simular login tras registro exitoso
                onLogin(username, 'client');
            }
        } catch (err: any) {
            setError(err.message || 'Error en el proceso');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-black p-6 overflow-y-auto">
            <div className="w-full max-w-md space-y-8 animate-fade-in py-10">
                <div className="text-center">
                    <img 
                        src="https://appdesignmex.com/bribiesca.jpeg" 
                        alt="Bribiesca Logo" 
                        className="mx-auto h-24 w-auto mb-6 rounded-2xl shadow-[0_0_30px_rgba(232,21,220,0.2)]" 
                    />
                    <h2 className="text-2xl font-black tracking-tighter text-white uppercase italic">
                        {isLogin ? 'Acceso Bribiesca' : 'Registro de Cliente'}
                    </h2>
                    <p className="mt-1 text-[10px] text-brand font-black uppercase tracking-[0.3em] opacity-80">
                        Studio & Beauty Artist
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {!isLogin && (
                        <div className="animate-fade-in space-y-4">
                            <div className="relative">
                                <input
                                    type="text"
                                    value={fullName}
                                    onChange={(e) => setFullName(e.target.value)}
                                    placeholder="NOMBRE COMPLETO"
                                    className="w-full px-6 py-4 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none text-sm"
                                    required
                                />
                            </div>
                        </div>
                    )}

                    <div className="relative">
                        <input
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            placeholder="NOMBRE DE USUARIO"
                            className="w-full px-6 py-4 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none text-sm"
                            required
                        />
                    </div>

                    {!isLogin && (
                        <div className="animate-fade-in space-y-4">
                            <div className="relative">
                                <input
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    placeholder="CORREO ELECTRÓNICO"
                                    className="w-full px-6 py-4 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none text-sm"
                                    required
                                />
                            </div>
                            <div className="relative">
                                <input
                                    type="tel"
                                    value={whatsapp}
                                    onChange={(e) => setWhatsapp(e.target.value)}
                                    placeholder="WHATSAPP"
                                    className="w-full px-6 py-4 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none text-sm"
                                    required
                                />
                            </div>
                        </div>
                    )}

                    <div className="relative">
                        <input
                            type={showPassword ? "text" : "password"}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            placeholder="CONTRASEÑA"
                            className="w-full px-6 py-4 bg-black border border-white/10 rounded-2xl text-white font-bold placeholder-gray-700 focus:border-brand transition-all outline-none pr-14 text-sm"
                            required
                        />
                        <button 
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-600 hover:text-brand transition-colors"
                        >
                            {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                        </button>
                    </div>

                    {error && (
                        <p className="text-brand text-[9px] font-black uppercase text-center tracking-widest bg-brand/5 py-2 rounded-lg border border-brand/20">
                            {error}
                        </p>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-5 bg-brand text-white text-[11px] font-black rounded-2xl shadow-[0_0_20px_rgba(232,21,220,0.3)] hover:shadow-[0_0_30px_rgba(232,21,220,0.5)] active:scale-95 transition-all disabled:opacity-50 tracking-[0.2em] uppercase"
                    >
                        {loading ? <Spinner /> : (isLogin ? 'INICIAR SESIÓN' : 'REGISTRARME')}
                    </button>
                </form>

                <div className="text-center">
                    <button
                        onClick={() => {
                            setIsLogin(!isLogin);
                            setError('');
                        }}
                        className="text-[10px] font-black text-gray-500 hover:text-brand transition-colors uppercase tracking-[0.2em]"
                    >
                        {isLogin ? '¿Nuevo aquí? Crea tu cuenta' : '¿Ya eres cliente? Identifícate'}
                    </button>
                </div>
            </div>
        </div>
    );
};

