import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Review } from '../types';
import { Spinner, CheckIcon } from './Icons';

export const Reviews: React.FC<{ username: string, isAdmin?: boolean }> = ({ username, isAdmin }) => {
    const [reviews, setReviews] = useState<Review[]>([]);
    const [isWriting, setIsWriting] = useState(false);
    const [loading, setLoading] = useState(true);
    const [formData, setFormData] = useState({ rating: 5, comment: '' });

    useEffect(() => {
        fetchReviews();
    }, []);

    const fetchReviews = async () => {
        const { data } = await supabase.from('reviews').select('*').order('date', { ascending: false });
        if (data) setReviews(data);
        setLoading(false);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        const { error } = await supabase.from('reviews').insert([{
            client_name: username,
            rating: formData.rating,
            comment: formData.comment,
            date: new Date().toISOString()
        }]);

        if (!error) {
            setIsWriting(false);
            setFormData({ rating: 5, comment: '' });
            fetchReviews();
        }
    };

    if (loading) return <div className="flex justify-center p-10"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in">
            <header className="flex justify-between items-center">
                <div>
                    <h2 className="text-xl font-black text-white italic uppercase tracking-tighter">Testimonios</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Experiencia Bribiesca</p>
                </div>
                {!isAdmin && !isWriting && (
                    <button onClick={() => setIsWriting(true)} className="bg-brand text-white px-5 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Dejar Reseña</button>
                )}
            </header>

            {isWriting && (
                <form onSubmit={handleSave} className="bg-[#050505] p-8 rounded-[2.5rem] border border-brand/30 shadow-2xl space-y-6 animate-fade-in">
                    <div className="text-center">
                        <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-4">Califica tu experiencia</label>
                        <div className="flex justify-center gap-2">
                            {[1, 2, 3, 4, 5].map(star => (
                                <button 
                                    key={star} 
                                    type="button" 
                                    onClick={() => setFormData({ ...formData, rating: star })}
                                    className={`text-2xl transition-all ${formData.rating >= star ? 'scale-125 grayscale-0' : 'grayscale opacity-30'}`}
                                >
                                    ⭐
                                </button>
                            ))}
                        </div>
                    </div>
                    <textarea 
                        value={formData.comment} 
                        onChange={e => setFormData({ ...formData, comment: e.target.value })} 
                        placeholder="CUÉNTANOS TU EXPERIENCIA..."
                        className="w-full bg-black p-6 rounded-2xl border border-white/5 text-sm font-medium h-32"
                        required
                    ></textarea>
                    <div className="flex gap-4">
                        <button type="button" onClick={() => setIsWriting(false)} className="flex-1 py-4 bg-white/5 rounded-2xl text-[9px] font-black uppercase">Cancelar</button>
                        <button type="submit" className="flex-1 py-4 bg-brand text-white rounded-2xl text-[9px] font-black uppercase shadow-xl">Publicar</button>
                    </div>
                </form>
            )}

            <div className="space-y-4">
                {reviews.map(review => (
                    <div key={review.id} className="p-6 bg-[#050505] border border-white/5 rounded-3xl shadow-2xl group transition-all hover:border-brand/20">
                        <div className="flex justify-between items-start mb-3">
                            <div>
                                <h4 className="font-black text-white text-sm uppercase tracking-tight">{review.client_name}</h4>
                                <p className="text-[8px] text-gray-600 font-bold uppercase">{new Date(review.date).toLocaleDateString()}</p>
                            </div>
                            <div className="flex gap-1">
                                {Array.from({ length: review.rating }).map((_, i) => <span key={i} className="text-[10px]">⭐</span>)}
                            </div>
                        </div>
                        <p className="text-sm text-gray-400 leading-relaxed italic">"{review.comment}"</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { FlashSet } from '../types';
import { Spinner, PlusIcon, CloseIcon, UploadIcon, CheckIcon } from './Icons';

export const FlashCatalog: React.FC<{ isAdmin: boolean }> = ({ isAdmin }) => {
    const [items, setItems] = useState<FlashSet[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const [reservingId, setReservingId] = useState<number | null>(null);

    const fetchFlash = async () => {
        const { data } = await supabase.from('flash_sets').select('*').order('created_at', { ascending: false });
        if (data) setItems(data);
        setLoading(false);
    };

    useEffect(() => { fetchFlash(); }, []);

    const handleReserve = async (item: FlashSet) => {
        setReservingId(item.id);
        // Simulación de proceso de pago/apartado
        setTimeout(async () => {
            const { error } = await supabase
                .from('flash_sets')
                .update({ is_available: false })
                .eq('id', item.id);

            if (!error) {
                alert(`¡Diseño "${item.title}" apartado con éxito! Pronto te contactaremos para agendar la cita.`);
                fetchFlash();
            }
            setReservingId(null);
        }, 1500);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-black text-white italic tracking-tighter uppercase">Flash Designs</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest opacity-80">Diseños Exclusivos</p>
                </div>
                {isAdmin && (
                    <button 
                        onClick={() => setShowAddModal(true)}
                        className="bg-brand text-white px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg"
                    >
                        <PlusIcon className="w-4 h-4 inline mr-2" /> Nuevo
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 lg:grid-cols-3 gap-6">
                {items.length === 0 && <p className="col-span-full text-center text-gray-500 py-20 uppercase font-black tracking-widest text-[10px]">Explora el portafolio en Galería...</p>}
                {items.map(item => (
                    <div key={item.id} className="group relative bg-[#050505] rounded-3xl border border-white/5 overflow-hidden shadow-2xl transition-all hover:border-brand/40">
                        <div className="relative aspect-square bg-white/5">
                            <img src={item.image_url} alt={item.title} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                            {!item.is_available && (
                                <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-10">
                                    <span className="text-[10px] font-black text-brand uppercase tracking-[0.3em] border-2 border-brand px-4 py-2 rotate-[-15deg]">VENDIDO</span>
                                </div>
                            )}
                        </div>
                        <div className="p-5">
                            <h4 className="font-black text-white text-[11px] uppercase tracking-tight truncate mb-2">{item.title}</h4>
                            <div className="flex justify-between items-center">
                                <span className="text-brand font-black text-lg italic">${item.price}</span>
                                <span className="text-[8px] text-gray-600 uppercase font-black tracking-widest">{item.size_cm}cm</span>
                            </div>
                            {item.is_available && !isAdmin && (
                                <button 
                                    onClick={() => handleReserve(item)}
                                    disabled={reservingId !== null}
                                    className="w-full mt-4 py-3 bg-brand/10 border border-brand/30 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-brand transition-all flex justify-center items-center gap-2"
                                >
                                    {reservingId === item.id ? <Spinner /> : 'Apartar Diseño'}
                                </button>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

