            if (selectedClient) {
                await put('clients', { ...selectedClient, ...formData });
            } else {
                await add('clients', { ...formData, created_at: new Date().toISOString() });
            }
            await loadClients();
            setIsModalOpen(false);
        } catch (error) { alert("Error al guardar."); }
