    deposit_amount?: number;
    deposit_paid: boolean;
    price_total?: number;
    has_consent: boolean;
}

export interface Review {
    id: number;
    client_name: string;
    rating: number;
    comment: string;
    date: string;
}

export interface FlashSet {
    id: number;
