import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { MedicalHistory, Client } from '../types';
import { Spinner, CheckIcon, CloseIcon, SaveIcon, PrintIcon, DownloadIcon, MedicalIcon } from './Icons';
import { jsPDF } from 'jspdf';

interface MedicalHistoryProps {
    userRole: 'admin' | 'client';
    username: string;
}

const CONDITIONS = [
    'Diabetes', 'Hipertensión', 'VIH / Hepatitis', 'Problemas de Coagulación', 
    'Enfermedades Cardíacas', 'Epilepsia', 'Alergia al Látex', 'Embarazo'
];

export const MedicalHistorySection: React.FC<MedicalHistoryProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [histories, setHistories] = useState<MedicalHistory[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [viewingHistory, setViewingHistory] = useState<MedicalHistory | null>(null);

    // Form State
    const [formData, setFormData] = useState({
        client_name: username,
        birth_date: '',
        blood_type: 'O+',
        allergies: '',
        medications: '',
        conditions: [] as string[]
    });

    // Signature Pads
    const clientCanvasRef = useRef<HTMLCanvasElement>(null);
    const witnessCanvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawingClient, setIsDrawingClient] = useState(false);
    const [isDrawingWitness, setIsDrawingWitness] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
            fetchHistories();
        } else {
            fetchMyHistory();
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*');
        if (data) setClients(data);
    };

    const fetchHistories = async () => {
        const { data } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        if (data) setHistories(data);
        setLoading(false);
    };

    const fetchMyHistory = async () => {
        const { data } = await supabase.from('medical_histories').select('*').eq('client_name', username).single();
        if (data) setViewingHistory(data);
        setLoading(false);
    };

    const handleToggleCondition = (condition: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(condition) 
                ? prev.conditions.filter(c => c !== condition) 
                : [...prev.conditions, condition]
        }));
    };

    // --- Drawing Logic ---
    const startDrawing = (ref: React.RefObject<HTMLCanvasElement>, setter: (v: boolean) => void) => (e: any) => {
        setter(true);
        const ctx = ref.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(ref, true)(e);
    };

    const draw = (ref: React.RefObject<HTMLCanvasElement>, isDrawing: boolean) => (e: any) => {
        if (!isDrawing || !ref.current) return;
        const ctx = ref.current.getContext('2d');
        if (!ctx) return;
        const rect = ref.current.getBoundingClientRect();
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);
        const x = clientX - rect.left;
        const y = clientY - rect.top;
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';
        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSave = async () => {
        if (!clientCanvasRef.current || !witnessCanvasRef.current) return;
        setIsSaving(true);

        const clientSig = clientCanvasRef.current.toDataURL('image/png');
        const witnessSig = witnessCanvasRef.current.toDataURL('image/png');

        const { error } = await supabase.from('medical_histories').insert([{
            ...formData,
            signature_client: clientSig,
            signature_witness: witnessSig,
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert("¡Expediente enviado con éxito!");
            fetchMyHistory();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const generatePDF = (h: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFillColor(0, 0, 0);
        doc.rect(0, 0, 210, 40, 'F');
        doc.setTextColor(232, 21, 220);
        doc.setFontSize(22);
        doc.text("BRIBIESCA STUDIO PRO", 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.text("EXPEDIENTE CLÍNICO DIGITAL", 105, 30, { align: 'center' });

        doc.setTextColor(0, 0, 0);
        doc.setFontSize(12);
        doc.text(`PACIENTE: ${h.client_name}`, 20, 60);
        doc.text(`FECHA NACIMIENTO: ${h.birth_date}`, 20, 70);
        doc.text(`TIPO SANGRE: ${h.blood_type}`, 20, 80);

        doc.text("ANTECEDENTES:", 20, 100);
        doc.setFontSize(10);
        doc.text(h.conditions.length > 0 ? h.conditions.join(', ') : 'Ninguno reportado', 30, 110);

        doc.setFontSize(12);
        doc.text("ALERGIAS:", 20, 130);
        doc.text(h.allergies || 'Ninguna', 20, 140);

        doc.text("FIRMA CLIENTE:", 20, 180);
        doc.addImage(h.signature_client, 'PNG', 20, 190, 50, 20);

        doc.text("FIRMA TESTIGO:", 120, 180);
        doc.addImage(h.signature_witness, 'PNG', 120, 190, 50, 20);

        doc.save(`Expediente_${h.client_name}.pdf`);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in max-w-4xl mx-auto pb-20">
            <header className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Historial Clínico</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Seguridad Dérmica Avanzada</p>
                </div>
            </header>

            {userRole === 'admin' ? (
                <div className="space-y-4">
                    {histories.map(h => (
                        <div key={h.id} className="p-6 bg-[#050505] border border-white/5 rounded-3xl flex items-center justify-between group hover:border-brand/40 transition-all shadow-xl">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-white/5 rounded-2xl flex items-center justify-center text-brand border border-white/5">
                                    <MedicalIcon />
                                </div>
                                <div>
                                    <h4 className="font-black text-white text-sm uppercase">{h.client_name}</h4>
                                    <p className="text-[9px] text-gray-500 uppercase font-bold tracking-widest">{new Date(h.created_at).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => generatePDF(h)} className="p-3 bg-white/5 rounded-xl text-gray-500 hover:text-brand transition-colors"><DownloadIcon /></button>
                                <button onClick={() => { generatePDF(h); window.print(); }} className="p-3 bg-white/5 rounded-xl text-gray-500 hover:text-white transition-colors"><PrintIcon /></button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                viewingHistory ? (
                    <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl text-center space-y-6">
                        <div className="w-20 h-20 bg-brand/10 rounded-full flex items-center justify-center mx-auto text-brand">
                            <CheckIcon className="w-10 h-10" />
                        </div>
                        <h3 className="text-xl font-black text-white uppercase">Expediente Registrado</h3>
                        <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest leading-relaxed">Tu información médica ha sido guardada de forma segura en nuestro servidor encriptado.</p>
                        <div className="flex gap-4 pt-4">
                            <button onClick={() => generatePDF(viewingHistory)} className="flex-1 py-4 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-white/5">Descargar PDF</button>
                            <button onClick={() => window.print()} className="flex-1 py-4 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl">Imprimir</button>
                        </div>
                    </div>
                ) : (
                    <div className="bg-[#050505] p-8 rounded-[3rem] border border-white/5 shadow-2xl space-y-8">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-2 block">Fecha de Nacimiento</label>
                                <input type="date" value={formData.birth_date} onChange={e => setFormData({...formData, birth_date: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold" />
                            </div>
                            <div>
                                <label className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-2 block">Tipo de Sangre</label>
                                <select value={formData.blood_type} onChange={e => setFormData({...formData, blood_type: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold">
                                    <option>A+</option><option>A-</option><option>B+</option><option>B-</option><option>O+</option><option>O-</option><option>AB+</option><option>AB-</option>
                                </select>
                            </div>
                        </div>

                        <div>
                            <label className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-3 block">Antecedentes Médicos (Marca los que apliquen)</label>
                            <div className="grid grid-cols-2 gap-3">
                                {CONDITIONS.map(c => (
                                    <button 
                                        key={c} 
                                        type="button" 
                                        onClick={() => handleToggleCondition(c)}
                                        className={`p-4 rounded-xl text-[10px] font-black uppercase text-left transition-all border ${formData.conditions.includes(c) ? 'bg-brand text-white border-brand' : 'bg-white/5 text-gray-500 border-white/5'}`}
                                    >
                                        {c}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-4">
                                <p className="text-[9px] font-black uppercase text-gray-600 tracking-widest text-center">Firma del Paciente</p>
                                <div className="bg-white rounded-2xl h-40 overflow-hidden border-4 border-brand/10">
                                    <canvas 
                                        ref={clientCanvasRef} width={400} height={160} className="w-full h-full"
                                        onMouseDown={startDrawing(clientCanvasRef, setIsDrawingClient)}
                                        onMouseMove={draw(clientCanvasRef, isDrawingClient)}
                                        onMouseUp={() => setIsDrawingClient(false)}
                                        onTouchStart={startDrawing(clientCanvasRef, setIsDrawingClient)}
                                        onTouchMove={draw(clientCanvasRef, isDrawingClient)}
                                        onTouchEnd={() => setIsDrawingClient(false)}
                                    ></canvas>
                                </div>
                            </div>
                            <div className="space-y-4">
                                <p className="text-[9px] font-black uppercase text-gray-600 tracking-widest text-center">Firma Testigo / Tutor</p>
                                <div className="bg-white rounded-2xl h-40 overflow-hidden border-4 border-white/10">
                                    <canvas 
                                        ref={witnessCanvasRef} width={400} height={160} className="w-full h-full"
                                        onMouseDown={startDrawing(witnessCanvasRef, setIsDrawingWitness)}
                                        onMouseMove={draw(witnessCanvasRef, isDrawingWitness)}
                                        onMouseUp={() => setIsDrawingWitness(false)}
                                        onTouchStart={startDrawing(witnessCanvasRef, setIsDrawingWitness)}
                                        onTouchMove={draw(witnessCanvasRef, isDrawingWitness)}
                                        onTouchEnd={() => setIsDrawingWitness(false)}
                                    ></canvas>
                                </div>
                            </div>
                        </div>

                        <button 
                            onClick={handleSave}
                            disabled={isSaving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl flex justify-center items-center gap-3 active:scale-95 transition-all"
                        >
                            {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> Enviar Expediente Clínico</>}
                        </button>
                    </div>
                )
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, MedicalHistory } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon, MedicalIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [notifications, setNotifications] = useState<Consent[]>([]);
    const [newAlert, setNewAlert] = useState<{ type: 'firma' | 'historial', name: string } | null>(null);
    const [loading, setLoading] = useState(true);

    // Audio Notification (Professional Ping)
    const audioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        fetchDashboardData();

        // --- Suscripción en Tiempo Real para Consentimientos ---
        const consentSub = supabase
            .channel('consents_realtime')
            .on('postgres_changes', { 
                event: 'UPDATE', 
                schema: 'public', 
                table: 'consents',
                filter: 'status=eq.signed'
            }, (payload) => {
                const updatedConsent = payload.new as Consent;
                triggerAlert('firma', updatedConsent.client_name);
                fetchDashboardData();
            })
            .subscribe();

        // --- Suscripción en Tiempo Real para Historiales Médicos ---
        const medicalSub = supabase
            .channel('medical_realtime')
            .on('postgres_changes', { 
                event: 'INSERT', 
                schema: 'public', 
                table: 'medical_histories'
            }, (payload) => {
                const newHistory = payload.new as MedicalHistory;
                triggerAlert('historial', newHistory.client_name);
                fetchDashboardData();
            })
            .subscribe();

        return () => { 
            supabase.removeChannel(consentSub);
            supabase.removeChannel(medicalSub);
        };
    }, []);

    const triggerAlert = (type: 'firma' | 'historial', name: string) => {
        setNewAlert({ type, name });
        playPing();
        setTimeout(() => setNewAlert(null), 8000);
    };

    const playPing = () => {
        // Sonido de notificación pro (Short high-pitched ping)
        const pingBase64 = "data:audio/wav;base64,_";
        const audio = new Audio(pingBase64);
        audio.play().catch(e => console.warn("Audio play blocked by browser. Interaction required."));
    };

    const fetchDashboardData = async () => {
        const { data: apps } = await supabase.from('appointments').select('*');
        const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
        const { data: clients } = await supabase.from('clients').select('*');
        const { data: signs } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'signed')
            .order('signed_at', { ascending: false })
            .limit(5);

        if (signs) setNotifications(signs);
        setStats({
            appointments: apps?.length || 0,
            revenue: apps?.reduce((acc, curr) => acc + (curr.price_total || 0), 0) || 0,
            lowStock: stock?.length || 0,
            newClients: clients?.length || 0
        });
        setLoading(false);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in relative">
            {/* Alerta de Notificación Flotante con Sonido */}
            {newAlert && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-4 rounded-full shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce font-black text-[10px] uppercase tracking-widest border-2 border-white/20 flex items-center gap-3">
                    <div className="w-2 h-2 bg-white rounded-full animate-ping"></div>
                    ¡NUEVO {newAlert.type === 'firma' ? 'CONSENTIMIENTO' : 'HISTORIAL MÉDICO'} DE: {newAlert.name}!
                </div>
            )}

            <header className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Admin Panel</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em]">Control de Estudio Profesional</p>
                </div>
                <div className="bg-brand/10 border border-brand/30 px-5 py-2 rounded-full hidden md:block">
                    <p className="text-[9px] font-black text-brand uppercase tracking-widest">Sincronización Activa</p>
                </div>
            </header>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS" value={stats.appointments} icon={<CalendarIcon />} />
                <StatCard title="INGRESOS" value={`$${stats.revenue}`} icon={<CheckIcon />} />
                <StatCard title="STOCK BAJO" value={stats.lowStock} icon={<InventoryIcon />} color={stats.lowStock > 0 ? 'text-brand' : 'text-white'} />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Panel de Notificaciones de Firma */}
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-10">
                        <CheckIcon className="w-16 h-16" />
                    </div>
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <div className="w-2.5 h-2.5 bg-brand rounded-full animate-ping"></div> Historial de Firmas
                    </h3>
                    <div className="space-y-4">
                        {notifications.length === 0 ? (
                            <div className="p-12 text-center opacity-30">
                                <p className="text-[10px] font-black uppercase tracking-widest">Sin actividad reciente</p>
                            </div>
                        ) : (
                            notifications.map(n => (
                                <div key={n.id} className="p-5 bg-white/5 rounded-2xl border border-brand/10 flex items-center justify-between group hover:border-brand/40 transition-all">
                                    <div className="flex items-center gap-4">
                                        <div className="w-11 h-11 rounded-full bg-brand/10 flex items-center justify-center text-brand">
                                            <PencilIcon className="w-5 h-5"/>
                                        </div>
                                        <div>
                                            <p className="text-xs font-black text-white uppercase tracking-tight">{n.client_name}</p>
                                            <p className="text-[9px] text-gray-500 uppercase font-bold mt-0.5">Firmado: {new Date(n.signed_at!).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                                        </div>
                                    </div>
                                    <div className="bg-black p-3 rounded-xl border border-white/10 group-hover:bg-white group-hover:scale-110 transition-all cursor-zoom-in">
                                        <img src={n.signature} className="h-8 w-auto invert group-hover:invert-0 transition-all" alt="Firma" />
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </section>

                {/* Accesos Rápidos Médicos */}
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <MedicalIcon className="w-6 h-6 text-brand"/> Expedientes Recientes
                    </h3>
                    <div className="p-8 text-center space-y-5 border-2 border-brand/10 rounded-[2rem] bg-brand/[0.02]">
                        <p className="text-brand font-black text-[11px] uppercase tracking-[0.2em] leading-relaxed italic">Monitoreo de seguridad dérmica habilitado.</p>
                        <button className="w-full text-[9px] font-black text-white uppercase bg-brand px-8 py-4 rounded-2xl shadow-lg shadow-brand/20 active:scale-95 transition-all">Ir a Fichas Clínicas</button>
                    </div>
                </section>
            </div>
        </div>
    );
};

