import { Spinner, CheckIcon, CloseIcon, SaveIcon, PrintIcon, DownloadIcon, MedicalIcon } from './Icons';
import { jsPDF } from 'jspdf';

interface MedicalHistoryProps {
    userRole: 'admin' | 'client';
    username: string;
}

const HEALTH_CHECKLIST = [
    { id: 'diabetes', label: 'Diabetes' },
    { id: 'hipertension', label: 'Hipertensión' },
    { id: 'epilepsia', label: 'Epilepsia' },
    { id: 'covid', label: 'COVID-19' },
    { id: 'hepatitis', label: 'Hepatitis A, B o C' },
    { id: 'influenza', label: 'Influenza' },
    { id: 'vih', label: 'VIH/SIDA' },
];

export const MedicalHistorySection: React.FC<MedicalHistoryProps> = ({ userRole, username }) => {
    const [histories, setHistories] = useState<MedicalHistory[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [myHistory, setMyHistory] = useState<MedicalHistory | null>(null);

    const [formData, setFormData] = useState<Omit<MedicalHistory, 'signature_client' | 'signature_witness' | 'created_at'>>({
        client_name: username,
        birth_date: '',
        age: '',
        sex: 'M',
        address: '',
        phone: '',
        occupation: '',
        residence: '',
        schooling: '',
        email: '',
        conditions: [],
        allergies_detail: '',
        appointment_motive: ''
    });

    const clientCanvasRef = useRef<HTMLCanvasElement>(null);
    const witnessCanvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawingClient, setIsDrawingClient] = useState(false);
    const [isDrawingWitness, setIsDrawingWitness] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchHistories();
        } else {
            fetchMyHistory();
        }
    }, [userRole, username]);

    const fetchHistories = async () => {
        const { data } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        if (data) setHistories(data);
        setLoading(false);
    };

    const fetchMyHistory = async () => {
        const { data } = await supabase.from('medical_histories').select('*').eq('client_name', username).maybeSingle();
        if (data) setMyHistory(data);
        setLoading(false);
    };

    const handleConditionChange = (id: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(id) 
                ? prev.conditions.filter(c => c !== id) 
                : [...prev.conditions, id]
        }));
    };

    const startDrawing = (ref: React.RefObject<HTMLCanvasElement>, setter: (v: boolean) => void) => (e: any) => {
        setter(true);
        const ctx = ref.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(ref, true)(e);
    };

    const draw = (ref: React.RefObject<HTMLCanvasElement>, isDrawing: boolean) => (e: any) => {
        if (!isDrawing || !ref.current) return;
        const ctx = ref.current.getContext('2d');
        if (!ctx) return;
        const rect = ref.current.getBoundingClientRect();
        const clientX = (e.clientX || e.touches?.[0]?.clientX) - rect.left;
        const clientY = (e.clientY || e.touches?.[0]?.clientY) - rect.top;
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';
        ctx.lineTo(clientX, clientY);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(clientX, clientY);
    };

    const handleSave = async () => {
        if (!clientCanvasRef.current || !witnessCanvasRef.current) return;
        if (!formData.birth_date || !formData.phone) return alert("Por favor completa los campos obligatorios");

        setIsSaving(true);
        const clientSig = clientCanvasRef.current.toDataURL('image/png');
        const witnessSig = witnessCanvasRef.current.toDataURL('image/png');

        const { error } = await supabase.from('medical_histories').insert([{
            ...formData,
            signature_client: clientSig,
            signature_witness: witnessSig,
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert("¡Ficha Clínica enviada al estudio!");
            fetchMyHistory();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const generatePDF = (h: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFillColor(0, 0, 0);
        doc.rect(0, 0, 210, 30, 'F');
        doc.setTextColor(232, 21, 220);
        doc.setFontSize(18);
        doc.text("BRIBIESCA STUDIO PRO", 105, 15, { align: 'center' });
        doc.setFontSize(8);
        doc.text("EXPEDIENTE CLÍNICO DE TATUAJE PROFESIONAL", 105, 22, { align: 'center' });

        doc.setTextColor(0, 0, 0);
        doc.setFontSize(10);
        let y = 45;
        doc.text(`NOMBRE: ${h.client_name}`, 20, y);
        doc.text(`FECHA NAC: ${h.birth_date}`, 120, y); y+=8;
        doc.text(`EDAD: ${h.age}`, 20, y);
        doc.text(`SEXO: ${h.sex}`, 70, y);
        doc.text(`TEL: ${h.phone}`, 120, y); y+=8;
        doc.text(`DIRECCIÓN: ${h.address}`, 20, y); y+=8;
        doc.text(`OCUPACIÓN: ${h.occupation}`, 20, y);
        doc.text(`RESIDENCIA: ${h.residence}`, 100, y); y+=8;
        doc.text(`ESCOLARIDAD: ${h.schooling}`, 20, y);
        doc.text(`EMAIL: ${h.email}`, 100, y); y+=15;

        doc.setFont("helvetica", "bold");
        doc.text("INFORMACIÓN DE SALUD:", 20, y); y+=8;
        doc.setFont("helvetica", "normal");
        doc.text(`CONDICIONES: ${h.conditions.join(', ') || 'Ninguna'}`, 20, y); y+=8;
        doc.text(`ALERGIAS: ${h.allergies_detail || 'Ninguna'}`, 20, y); y+=15;

        doc.setFont("helvetica", "bold");
        doc.text("MOTIVO DE LA CITA:", 20, y); y+=8;
        doc.setFont("helvetica", "normal");
        const motiveLines = doc.splitTextToSize(h.appointment_motive, 170);
        doc.text(motiveLines, 20, y); y += (motiveLines.length * 6) + 10;

        doc.setFontSize(9);
        doc.text("Yo, " + h.client_name + ", declaro que he sido informado sobre los riesgos...", 20, y); y+=20;

        doc.addImage(h.signature_client, 'PNG', 20, y, 60, 25);
        doc.addImage(h.signature_witness, 'PNG', 120, y, 60, 25);
        y+=30;
        doc.text("FIRMA CLIENTE", 35, y);
        doc.text("FIRMA TESTIGO", 135, y);

        doc.save(`Expediente_${h.client_name}.pdf`);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in max-w-4xl mx-auto pb-20">
            <header>
                <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Historial Clínico</h2>
                <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Gestión Sanitaria Bribiesca</p>
            </header>

            {userRole === 'admin' ? (
                <div className="grid gap-4">
                    {histories.map(h => (
                        <div key={h.id} className="p-6 bg-[#050505] border border-white/5 rounded-3xl flex items-center justify-between group hover:border-brand/40 transition-all">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-white/5 rounded-2xl flex items-center justify-center text-brand border border-white/5">
                                    <MedicalIcon />
                                </div>
                                <div>
                                    <h4 className="font-black text-white text-sm uppercase">{h.client_name}</h4>
