                            <SignaturePad label="Firma Testigo / Tutor" canvasRef={witnessCanvasRef} isDrawing={isDrawingWitness} setIsDrawing={setIsDrawingWitness} onDraw={draw(witnessCanvasRef, isDrawingWitness)} onStart={startDrawing(witnessCanvasRef, setIsDrawingWitness)} />
