const FormInput = ({ label, value, onChange, type = "text", disabled = false }: any) => (
    <div className="space-y-2">
        <label className="text-[9px] font-black text-gray-500 uppercase tracking-widest block">{label}</label>
        <input 
            type={type} 
            value={value} 
            onChange={e => onChange && onChange(e.target.value)} 
            disabled={disabled}
            className={`w-full bg-black p-4 rounded-2xl border border-white/10 font-bold text-white text-sm ${disabled ? 'opacity-40 grayscale cursor-not-allowed' : 'focus:border-brand'}`}
        />
    </div>
);

const SignaturePad = ({ label, canvasRef, onDraw, onStart, setIsDrawing }: any) => (
    <div className="space-y-4">
        <p className="text-[10px] font-black uppercase text-gray-600 tracking-widest text-center">{label}</p>
        <div className="bg-white rounded-[2rem] h-48 overflow-hidden touch-none border-4 border-white/5 relative">
            <canvas 
                ref={canvasRef} width={400} height={192} className="w-full h-full cursor-crosshair"
                onMouseDown={onStart} onMouseMove={onDraw} onMouseUp={() => setIsDrawing(false)}
                onTouchStart={onStart} onTouchMove={onDraw} onTouchEnd={() => setIsDrawing(false)}
            ></canvas>
        </div>
        <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
        }} className="text-[9px] font-black text-brand/40 uppercase block mx-auto hover:text-brand transition-colors">Limpiar Firma</button>
    </div>
);

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Spinner, SaveIcon, ShieldIcon } from './Icons';

export const PrivacyPolicy: React.FC<{ userRole: 'admin' | 'client' }> = ({ userRole }) => {
    const [content, setContent] = useState('');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        fetchPolicy();
    }, []);

    const fetchPolicy = async () => {
        const { data } = await supabase.from('privacy_settings').select('content').eq('id', 1).maybeSingle();
        if (data) setContent(data.content);
        setLoading(false);
    };

    const handleSave = async () => {
        setSaving(true);
        const { error } = await supabase.from('privacy_settings').upsert({ id: 1, content, updated_at: new Date().toISOString() });
        if (!error) alert("¡Aviso de Privacidad actualizado!");
        setSaving(false);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="max-w-3xl mx-auto space-y-8 animate-fade-in pb-20">
            <header className="text-center">
                <div className="inline-block p-4 bg-brand/10 rounded-full mb-4">
                    <ShieldIcon />
                </div>
                <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Políticas de Privacidad</h2>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1">Marco Legal y Protección de Datos</p>
            </header>

            <div className="bg-[#050505] p-10 rounded-[3rem] border border-white/5 shadow-2xl">
                {userRole === 'admin' ? (
                    <div className="space-y-6">
                        <label className="text-[10px] font-black text-brand uppercase tracking-widest block italic">Editor de Texto Legal</label>
                        <textarea 
                            value={content}
                            onChange={e => setContent(e.target.value)}
                            className="w-full h-[50vh] bg-black p-8 rounded-3xl border border-white/10 text-sm leading-relaxed text-gray-400 font-medium font-mono focus:border-brand transition-all resize-none"
                        />
                        <button 
                            onClick={handleSave}
                            disabled={saving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl flex justify-center items-center gap-3 active:scale-95 transition-all"
                        >
                            {saving ? <Spinner /> : <><SaveIcon /> Guardar y Publicar</>}
                        </button>
                    </div>
                ) : (
                    <div className="text-sm text-gray-400 leading-relaxed space-y-4 whitespace-pre-wrap italic">
                        {content || 'Cargando políticas...'}
                    </div>
                )}
            </div>

            <div className="text-center opacity-40">
                <p className="text-[9px] font-black uppercase tracking-[0.2em]">Última actualización: {new Date().toLocaleDateString()}</p>
            </div>
        </div>
    );
};

