import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Spinner, SaveIcon, CareIcon, DownloadIcon, PrintIcon } from './Icons';
import { jsPDF } from 'jspdf';

interface AftercareGuideProps {
    userRole: 'admin' | 'client';
}

const DEFAULT_AFTERCARE = `Cuidados Posteriores (Para entregar al cliente)
Durante el proceso de cicatrización:

Higiene: Lavar la zona con jabón neutro y agua tibia 2-3 veces al día.
Protección: No exponer la zona al sol, piscinas, saunas o playas durante los primeros 15 días.
Manipulación: No rascar, ni quitar las costras. No tocar con las manos sucias.
Producto: Aplicar la crema recomendada en capa fina (solo para tatuajes).
Piercing: Mover la pieza suavemente durante la limpieza y evitar ropa ajustada que roce la zona.`;

export const AftercareGuide: React.FC<AftercareGuideProps> = ({ userRole }) => {
    const [content, setContent] = useState('');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        fetchAftercare();
    }, []);

    const fetchAftercare = async () => {
        const { data } = await supabase.from('aftercare_settings').select('content').eq('id', 1).maybeSingle();
        if (data) {
            setContent(data.content);
        } else {
            setContent(DEFAULT_AFTERCARE);
        }
        setLoading(false);
    };

    const handleSave = async () => {
        setSaving(true);
        const { error } = await supabase.from('aftercare_settings').upsert({ 
            id: 1, 
            content, 
            updated_at: new Date().toISOString() 
        });
        if (!error) alert("¡Cuidados Actualizados Correctamente!");
        setSaving(false);
    };

    const generatePDF = () => {
        const doc = new jsPDF();

        // Estilo visual del PDF
        doc.setFillColor(0, 0, 0);
        doc.rect(0, 0, 210, 40, 'F');
        doc.setTextColor(232, 21, 220); // Brand color #E815DC
        doc.setFontSize(22);
        doc.text("BRIBIESCA STUDIO PRO", 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.text("GUÍA PROFESIONAL DE CUIDADOS POSTERIORES", 105, 30, { align: 'center' });

        doc.setTextColor(0, 0, 0);
        doc.setFontSize(12);
        const lines = doc.splitTextToSize(content, 170);
        doc.text(lines, 20, 60);

        doc.setFontSize(8);
        doc.setTextColor(150, 150, 150);
        doc.text("Generado desde la App Oficial de Bribiesca Studio", 105, 285, { align: 'center' });

        doc.save('Cuidados_Posteriores_Bribiesca.pdf');
    };

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (printWindow) {
            printWindow.document.write(`
                <html>
                    <head>
                        <title>Bribiesca Studio - Cuidados</title>
                        <style>
                            body { font-family: sans-serif; padding: 40px; line-height: 1.6; }
                            h1 { color: #E815DC; text-align: center; border-bottom: 2px solid #E815DC; padding-bottom: 10px; }
                            pre { white-space: pre-wrap; font-size: 14px; color: #333; }
                        </style>
                    </head>
                    <body>
                        <h1>BRIBIESCA STUDIO PRO</h1>
                        <pre>${content}</pre>
                        <script>window.print(); window.close();</script>
                    </body>
                </html>
            `);
            printWindow.document.close();
        }
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="max-w-3xl mx-auto space-y-8 animate-fade-in pb-20">
            <header className="text-center">
                <div className="inline-block p-4 bg-brand/10 rounded-full mb-4 border border-brand/20 shadow-lg">
                    <CareIcon />
                </div>
                <h2 className="text-3xl font-black italic text-white uppercase tracking-tighter">Guía de Cuidados</h2>
                <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Garantiza la perfección de tu pieza</p>
            </header>

            <div className="bg-[#050505] p-8 md:p-12 rounded-[3rem] border border-white/5 shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-brand/20"></div>

                {userRole === 'admin' ? (
                    <div className="space-y-6">
                        <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-brand uppercase tracking-widest italic">Panel de Edición Directa</label>
                            <span className="text-[8px] text-gray-600 font-bold uppercase tracking-widest">Autosync Activo</span>
                        </div>
                        <textarea 
                            value={content}
                            onChange={e => setContent(e.target.value)}
                            className="w-full h-[50vh] bg-black p-8 rounded-3xl border border-white/10 text-sm leading-relaxed text-gray-300 font-medium focus:border-brand transition-all resize-none shadow-inner"
                        />
                        <button 
                            onClick={handleSave}
                            disabled={saving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.3em] shadow-[0_0_30px_rgba(232,21,220,0.3)] flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                        >
                            {saving ? <Spinner /> : <><SaveIcon /> PUBLICAR CAMBIOS</>}
                        </button>
                    </div>
                ) : (
                    <div className="space-y-8">
                        <div className="text-sm text-gray-300 leading-loose whitespace-pre-wrap italic font-medium">
                            {content}
                        </div>

                        <div className="grid grid-cols-2 gap-4 pt-6 border-t border-white/5">
                            <button 
                                onClick={generatePDF}
                                className="flex items-center justify-center gap-3 py-5 bg-white/5 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-brand/10 hover:border-brand/40 transition-all"
                            >
                                <DownloadIcon className="w-4 h-4 text-brand" /> Descargar PDF
                            </button>
                            <button 
                                onClick={handlePrint}
                                className="flex items-center justify-center gap-3 py-5 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all"
                            >
                                <PrintIcon className="w-4 h-4" /> Imprimir Guía
                            </button>
                        </div>
                    </div>
                )}
            </div>

            <div className="p-8 bg-brand/[0.02] border border-brand/10 rounded-[2.5rem] text-center">
                <p className="text-[9px] text-gray-600 font-black uppercase tracking-[0.3em]">
                    Cualquier duda o anomalía, contacta a tu artista de inmediato.
                </p>
            </div>
        </div>
    );
};

