import React, { useState } from 'react';
import { UserRole } from '../types';
import { Spinner, EyeIcon, EyeOffIcon } from './Icons';
import { supabase } from '../utils/supabase';

interface AuthProps {
    onLogin: (username: string, role: UserRole) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
    const [authMode, setAuthMode] = useState<'login' | 'register' | 'recover'>('login');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');
    const [showPassword, setShowPassword] = useState(false);

    // Form States
    const [fullName, setFullName] = useState('');
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [whatsapp, setWhatsapp] = useState('');
    const [password, setPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');

    const resetMessages = () => {
        setError('');
        setSuccessMessage('');
    };

    const handleRecoverPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        resetMessages();

        try {
            const { data: user, error: fetchError } = await supabase
                .from('clients')
                .select('id, username')
                .eq('contact', email.toLowerCase().trim())
                .single();

            if (fetchError || !user) {
                throw new Error('CORREO NO REGISTRADO EN EL SISTEMA');
            }

            const { error: updateError } = await supabase
                .from('clients')
                .update({ password: newPassword })
                .eq('id', user.id);

            if (updateError) throw new Error('ERROR AL ACTUALIZAR CONTRASEÑA');

            setSuccessMessage('¡CONTRASEÑA ACTUALIZADA CON ÉXITO!');
            setTimeout(() => {
                setAuthMode('login');
                resetMessages();
            }, 2000);

        } catch (err: any) {
            setError(err.message.toUpperCase());
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (authMode === 'recover') return handleRecoverPassword(e);

        setLoading(true);
        resetMessages();

        const cleanUsername = username.toLowerCase().trim();

        // --- CREDENCIALES SOLICITADAS ---
        if (cleanUsername === 'cliente' && password === '123_cliente') {
            onLogin('cliente', 'client');
            return;
        }

        // Admin default (opcional para desarrollo)
        if (cleanUsername === 'admin' && password === 'admin123') {
            onLogin('admin', 'admin');
            return;
        }

        try {
            if (authMode === 'login') {
                const { data: user, error: fetchError } = await supabase
                    .from('clients')
                    .select('username, password, role')
                    .eq('username', cleanUsername)
                    .single();

                if (fetchError || !user) {
                    throw new Error('USUARIO NO ENCONTRADO');
                }

                if (user.password !== password) {
                    throw new Error('CONTRASEÑA INCORRECTA');
                }

                onLogin(user.username, user.role as UserRole);
            } else {
                if (!fullName || !username || !email || !whatsapp || !password) {
                    throw new Error('TODOS LOS CAMPOS SON OBLIGATORIOS');
                }

                const { error: dbError } = await supabase
                    .from('clients')
                    .insert([{
                        name: fullName.trim(),
                        username: cleanUsername,
                        contact: email.toLowerCase().trim(),
                        whatsapp: whatsapp.trim(),
                        password: password,
                        role: 'client',
                        notes: `Registro vía App`
                    }]);

                if (dbError) {
                    if (dbError.code === '23505') throw new Error('EL USUARIO O CORREO YA EXISTEN');
                    throw new Error(dbError.message);
                }

                onLogin(cleanUsername, 'client');
            }
        } catch (err: any) {
            setError(err.message.toUpperCase());
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-black relative overflow-hidden">
            <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-brand/10 blur-[120px] rounded-full pointer-events-none"></div>

            <div className="w-full max-w-md space-y-8 animate-fade-in py-10 px-6 relative z-10">
                <div className="text-center mb-10">
                    <img src="https://appdesignmex.com/bribiesca.jpeg" alt="Logo" className="relative h-28 w-auto mx-auto mb-6 rounded-3xl shadow-2xl border border-white/10" />
                    <h2 className="text-3xl font-black text-white uppercase italic leading-none">
                        {authMode === 'login' ? 'Acceso Pro' : authMode === 'register' ? 'Registro' : 'Recuperar'}
                    </h2>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {authMode === 'recover' ? (
                        <>
                            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="CORREO REGISTRADO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                            <div className="relative">
                                <input type={showPassword ? "text" : "password"} value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="NUEVA CONTRASEÑA" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold pr-14" required />
                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-600">
                                    {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                                </button>
                            </div>
                        </>
                    ) : (
                        <>
                            {authMode === 'register' && (
                                <input type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} placeholder="NOMBRE COMPLETO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                            )}
                            <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="USUARIO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                            {authMode === 'register' && (
                                <>
                                    <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="CORREO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                                    <input type="tel" value={whatsapp} onChange={(e) => setWhatsapp(e.target.value)} placeholder="WHATSAPP" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                                </>
                            )}
                            <div className="relative">
                                <input type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="CONTRASEÑA" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold pr-14" required />
                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-600">
                                    {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                                </button>
                            </div>
                        </>
                    )}

                    {error && <p className="text-brand text-[10px] font-black uppercase text-center tracking-widest bg-brand/10 p-3 rounded-xl animate-shake">{error}</p>}
                    {successMessage && <p className="text-green-500 text-[10px] font-black uppercase text-center tracking-widest bg-green-500/10 p-3 rounded-xl">{successMessage}</p>}

                    <button type="submit" disabled={loading} className="w-full py-5 bg-brand text-white text-[11px] font-black rounded-2xl shadow-xl active:scale-95 transition-all">
                        {loading ? <Spinner /> : (authMode === 'login' ? 'ENTRAR' : authMode === 'register' ? 'REGISTRARME' : 'ACTUALIZAR')}
                    </button>
                </form>

                <div className="flex flex-col gap-4 text-center">
                    {authMode === 'login' && (
                        <button onClick={() => { setAuthMode('recover'); resetMessages(); }} className="text-[9px] font-black text-brand/60 hover:text-brand uppercase tracking-widest transition-colors">¿Olvidaste tu contraseña?</button>
                    )}
                    <button onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); resetMessages(); }} className="text-[10px] font-black text-gray-500 hover:text-white uppercase tracking-widest">
                        {authMode === 'login' ? '¿No tienes cuenta? Regístrate' : '¿Ya tienes cuenta? Inicia sesión'}
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { MedicalHistory } from '../types';
import { Spinner, CheckIcon, SaveIcon, PrintIcon, DownloadIcon, MedicalIcon } from './Icons';
import { jsPDF } from 'jspdf';

interface MedicalHistoryProps {
    userRole: 'admin' | 'client';
    username: string;
}

const HEALTH_CHECKLIST = [
    { id: 'diabetes', label: 'Diabetes' },
    { id: 'hipertension', label: 'Hipertensión' },
    { id: 'epilepsia', label: 'Epilepsia' },
    { id: 'covid', label: 'COVID-19' },
    { id: 'hepatitis', label: 'Hepatitis A, B o C' },
    { id: 'influenza', label: 'Influenza' },
    { id: 'vih', label: 'VIH/SIDA' },
];

export const MedicalHistorySection: React.FC<MedicalHistoryProps> = ({ userRole, username }) => {
    const [histories, setHistories] = useState<MedicalHistory[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [myHistory, setMyHistory] = useState<MedicalHistory | null>(null);

    const [formData, setFormData] = useState({
        client_name: '',
        birth_date: '',
        age: '',
        sex: 'M',
        address: '',
        phone: '',
        occupation: '',
        residence: '',
        schooling: '',
        email: '',
        conditions: [] as string[],
        allergies_detail: '',
        appointment_motive: ''
    });

    const clientCanvasRef = useRef<HTMLCanvasElement>(null);
    const witnessCanvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawingClient, setIsDrawingClient] = useState(false);
    const [isDrawingWitness, setIsDrawingWitness] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') fetchHistories();
        else fetchMyHistory();
    }, [userRole, username]);

    const fetchHistories = async () => {
        const { data } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        if (data) setHistories(data);
        setLoading(false);
    };

    const fetchMyHistory = async () => {
        const { data } = await supabase.from('medical_histories').select('*').eq('client_name', username).maybeSingle();
        if (data) setMyHistory(data);
        setLoading(false);
    };

    const handleConditionChange = (id: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(id) ? prev.conditions.filter(c => c !== id) : [...prev.conditions, id]
        }));
    };

    const startDrawing = (ref: React.RefObject<HTMLCanvasElement>, setter: (v: boolean) => void) => (e: any) => {
        setter(true);
        const ctx = ref.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(ref, true)(e);
    };

    const draw = (ref: React.RefObject<HTMLCanvasElement>, isDrawing: boolean) => (e: any) => {
        if (!isDrawing || !ref.current) return;
        const ctx = ref.current.getContext('2d');
        if (!ctx) return;
        const rect = ref.current.getBoundingClientRect();
        const clientX = (e.clientX || e.touches?.[0]?.clientX) - rect.left;
        const clientY = (e.clientY || e.touches?.[0]?.clientY) - rect.top;
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';
        ctx.lineTo(clientX, clientY);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(clientX, clientY);
    };

    const handleSave = async () => {
        if (!clientCanvasRef.current || !witnessCanvasRef.current) return;
        setIsSaving(true);
        const clientSig = clientCanvasRef.current.toDataURL('image/png');
        const witnessSig = witnessCanvasRef.current.toDataURL('image/png');

        const { error } = await supabase.from('medical_histories').insert([{
            ...formData,
            signature_client: clientSig,
            signature_witness: witnessSig,
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert("¡Ficha Clínica enviada al estudio!");
            fetchMyHistory();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const generatePDF = (h: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFillColor(0, 0, 0);
        doc.rect(0, 0, 210, 30, 'F');
        doc.setTextColor(232, 21, 220);
        doc.setFontSize(18);
        doc.text("BRIBIESCA STUDIO PRO", 105, 15, { align: 'center' });
        doc.setFontSize(8);
        doc.text("FICHA CLÍNICA / HISTORIA CLÍNICA (TATUAJE)", 105, 22, { align: 'center' });

        doc.setTextColor(0, 0, 0);
        doc.setFontSize(10);
        let y = 45;
        doc.text(`Nombre del Paciente: ${h.client_name}`, 20, y);
        doc.text(`Fecha Nac: ${h.birth_date}`, 130, y); y+=8;
        doc.text(`Edad: ${h.age}`, 20, y);
        doc.text(`Sexo: ${h.sex}`, 60, y);
        doc.text(`Teléfono: ${h.phone}`, 120, y); y+=8;
        doc.text(`Dirección: ${h.address}`, 20, y); y+=8;
        doc.text(`Ocupación: ${h.occupation}`, 20, y);
        doc.text(`Lugar de Residencia: ${h.residence}`, 100, y); y+=8;
        doc.text(`Escolaridad: ${h.schooling}`, 20, y);
        doc.text(`Correo electrónico: ${h.email}`, 100, y); y+=15;

        doc.setFont("helvetica", "bold");
        doc.text("Información de Salud:", 20, y); y+=8;
        doc.setFont("helvetica", "normal");
        doc.text(`Antecedentes: ${h.conditions.join(', ') || 'Ninguno'}`, 20, y); y+=8;
        doc.text(`Alergias (especificar): ${h.allergies_detail || 'Ninguna'}`, 20, y); y+=15;

        doc.setFont("helvetica", "bold");
        doc.text("Motivo de la Cita:", 20, y); y+=8;
        doc.setFont("helvetica", "normal");
        const motiveLines = doc.splitTextToSize(h.appointment_motive, 170);
        doc.text(motiveLines, 20, y); y += (motiveLines.length * 6) + 15;

        doc.setFontSize(9);
        doc.setFont("helvetica", "bold");
        doc.text("Consentimiento Informado (Resumen)", 20, y); y+=6;
        doc.setFont("helvetica", "normal");
        const legalText = `Yo, ${h.client_name}, declaro que he sido informado sobre los riesgos y cuidados del procedimiento. Entiendo que un tatuaje/piercing es una herida punzante y acepto las condiciones de higiene y materiales utilizados.`;
        const legalLines = doc.splitTextToSize(legalText, 170);
        doc.text(legalLines, 20, y); y += (legalLines.length * 5) + 5;
