import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, Client } from '../types';
import { CheckIcon, Spinner, CloseIcon, SendIcon, PencilIcon, SaveIcon } from './Icons';

interface ConsentFormsProps {
    userRole: 'admin' | 'client';
    username: string;
}

const DEFAULT_CONSENT_TEXT = `Yo, [NOMBRE_CLIENTE], acepto los términos y condiciones de Bribiesca Studio para el procedimiento de tatuaje. He sido informado de los riesgos y cuidados posteriores.

1. SOBRE LA INFORMACIÓN RECIBIDA
He sido informado(a) detalladamente por el profesional sobre la técnica, el diseño, la zona de aplicación y el proceso de cicatrización. He tenido la oportunidad de hacer preguntas y todas mis dudas han sido resueltas de manera satisfactoria.

2. DECLARACIÓN DE SALUD Y RESPONSABILIDAD
Confirmo que he respondido con veracidad al cuestionario médico previo. Declaro que:

No estoy bajo los efectos del alcohol, drogas o medicamentos que alteren mi juicio o la coagulación de mi sangre.

No padezco enfermedades infectocontagiosas que no hayan sido comunicadas.

No estoy embarazada ni en periodo de lactancia (en caso de mujeres).

3. ACEPTACIÓN DE RIESGOS (Cláusula de Exención)
Entiendo que el tatuaje o piercing es una herida punzante y conlleva riesgos que acepto voluntariamente, incluyendo pero no limitándose a:

Infecciones: Derivadas de un mal cuidado posterior o factores externos.

Cicatrización: Riesgo de queloides (cicatriz gruesa), pérdida de pigmento o migración de tinta/joya.

Alergias: Reacciones inesperadas a los pigmentos, metales de la joyería, látex o antisépticos.

Desmayos: Mareos o fatiga durante el procedimiento debido al estrés físico.

4. IRREVERSIBILIDAD Y ESTÉTICA
Permanencia: Entiendo que un tatuaje debe considerarse permanente. Los métodos de eliminación son costosos y no garantizan el retorno a la piel original.

Resultado: Comprendo que el resultado final depende del tipo de piel y de seguir rigurosamente las instrucciones de curación.

5. CONFORMIDAD CON HIGIENE
He verificado que el material utilizado es nuevo, estéril y desechable, y que el área de trabajo cumple con las condiciones de higiene necesarias.

DECLARACIÓN FINAL: "Entiendo que la omisión de los cuidados posteriores recomendados es mi exclusiva responsabilidad. Con este conocimiento, autorizo al profesional a realizar el procedimiento."`;

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [isSaving, setIsSaving] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const [consentText, setConsentText] = useState(DEFAULT_CONSENT_TEXT);
    const [newDocAlert, setNewDocAlert] = useState(false);

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchMyPendingConsents();

            // Suscripción en tiempo real para el cliente
            const channel = supabase
                .channel('client_consents')
                .on('postgres_changes', { 
                    event: 'INSERT', 
                    schema: 'public', 
                    table: 'consents',
                    filter: `client_username=eq.${username}`
                }, () => {
                    setNewDocAlert(true);
                    fetchMyPendingConsents();
                })
                .subscribe();

            return () => { supabase.removeChannel(channel); };
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*').order('name');
        if (data) setClients(data);
    };

    const fetchMyPendingConsents = async () => {
        const { data } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'pending')
            .eq('client_username', username);
        if (data) setPendingConsents(data);
    };

    const handleSendToClient = async () => {
        if (!selectedClientId) return alert("Selecciona un cliente");
        setIsSaving(true);
        const client = clients.find(c => c.id === Number(selectedClientId));
        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_username: client?.username, // Crucial para que el cliente lo vea
            client_name: client?.name,
            content: finalizedText,
            status: 'pending',
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert(`¡Documento enviado con éxito a ${client?.name}!`);
            setSelectedClientId('');
        } else {
            alert("Error al enviar: " + error.message);
        }
        setIsSaving(false);
    };

    const startDrawing = (e: any) => {
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(e);
    };

    const stopDrawing = () => {
        setIsDrawing(false);
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current) return;
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);

        const x = clientX - rect.left;
        const y = clientY - rect.top;

        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';

        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSaveSignature = async () => {
        if (!activeConsent || !canvasRef.current) return;

        setIsSaving(true);
        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            alert("Tu consentimiento ha sido firmado y guardado correctamente.");
            setActiveConsent(null);
            fetchMyPendingConsents();
        } else {
            alert("Error al guardar firma: " + error.message);
        }
        setIsSaving(false);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in pb-20">
                <header>
                    <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Editor de Consentimiento</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Envío de Documentación Legal</p>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-1 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">1. Destinatario</label>
                            <select 
                                value={selectedClientId} 
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold text-sm focus:border-brand transition-all"
                            >
                                <option value="">SELECCIONAR CLIENTE...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name} (@{c.username})</option>)}
                            </select>
                        </div>
                        <div className="p-6 bg-brand/5 border border-brand/20 rounded-3xl">
                            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest mb-2 flex items-center gap-2">
                                <CheckIcon className="w-4 h-4" /> Crucial
                            </h4>
                            <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
                                Al enviar, el cliente recibirá una notificación en tiempo real en su panel personal. Asegúrate de que el cliente tenga un <span className="text-brand font-bold">@usuario</span> asignado.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">2. Cuerpo del Documento</label>
                            <textarea 
                                value={consentText}
                                onChange={(e) => setConsentText(e.target.value)}
                                className="w-full h-[500px] bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none focus:border-brand transition-all custom-scrollbar"
                            ></textarea>
                        </div>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-[0_0_30px_rgba(232,21,220,0.3)] flex justify-center items-center gap-4 text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> ENVIAR A FIRMAR</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto space-y-8 animate-fade-in pb-20">
            {newDocAlert && (
                <div className="bg-brand text-white p-4 rounded-2xl text-center text-[10px] font-black uppercase tracking-widest animate-bounce border-2 border-white/20">
                    🔔 ¡HAS RECIBIDO UN NUEVO DOCUMENTO PARA FIRMAR!
                </div>
            )}

            {!activeConsent ? (
                <div className="space-y-6">
                    <div className="text-center">
                        <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Documentos Pendientes</h2>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Seguridad y Salud Bribiesca</p>
                    </div>

                    {pendingConsents.length === 0 ? (
                        <div className="p-16 text-center border-2 border-dashed border-white/5 rounded-[3rem] bg-black/40">
                            <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CheckIcon className="text-gray-700 w-8 h-8" />
                            </div>
                            <p className="text-gray-600 text-[10px] font-black uppercase tracking-[0.3em]">Todo en orden. No tienes firmas pendientes.</p>
                        </div>
                    ) : (
                        <div className="grid gap-4">
                            {pendingConsents.map(c => (
                                <button 
                                    key={c.id} 
                                    onClick={() => { setActiveConsent(c); setNewDocAlert(false); }} 
                                    className="w-full p-8 bg-brand/10 border border-brand/40 rounded-[2.5rem] flex justify-between items-center group transition-all hover:bg-brand/20 shadow-[0_0_30px_rgba(232,21,220,0.1)]"
                                >
                                    <div className="text-left">
                                        <p className="text-[10px] text-brand font-black uppercase tracking-[0.2em] mb-1">Recibido {new Date(c.created_at).toLocaleDateString()}</p>
                                        <h3 className="text-white font-black uppercase text-base tracking-tight">Consentimiento para Procedimiento</h3>
                                    </div>
                                    <div className="w-12 h-12 bg-brand text-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                                        <PencilIcon className="w-6 h-6" />
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl space-y-8 relative animate-fade-in">
                    <button onClick={() => setActiveConsent(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors">
                        <CloseIcon className="w-6 h-6" />
                    </button>

                    <div>
                        <h3 className="text-xl font-black text-white italic uppercase tracking-tighter mb-2">Consentimiento Informado</h3>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest">Procedimiento Seguro Bribiesca Studio</p>
                    </div>

                    <div className="bg-black p-8 rounded-3xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-[400px] overflow-y-auto custom-scrollbar italic shadow-inner">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-4">
                        <p className="text-[10px] font-black uppercase text-gray-600 tracking-[0.3em] text-center">Dibuja tu firma en el recuadro blanco</p>
                        <div className="bg-white rounded-[2rem] h-56 overflow-hidden touch-none border-4 border-brand/10 shadow-2xl">
                            <canvas 
                                ref={canvasRef}
                                width={600}
                                height={224}
                                className="w-full h-full cursor-crosshair"
                                onMouseDown={startDrawing}
                                onMouseMove={draw}
                                onMouseUp={stopDrawing}
                                onMouseOut={stopDrawing}
                                onTouchStart={startDrawing}
                                onTouchMove={draw}
                                onTouchEnd={stopDrawing}
                            ></canvas>
                        </div>
                        <div className="flex justify-center">
                            <button 
                                onClick={() => {
                                    const ctx = canvasRef.current?.getContext('2d');
                                    if (canvasRef.current && ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                                }} 
                                className="text-[9px] font-black text-brand/60 uppercase tracking-widest border-b border-brand/20 hover:text-brand transition-colors"
                            >
                                Limpiar Firma
                            </button>
                        </div>
                    </div>

                    <button 
                        onClick={handleSaveSignature}
                        disabled={isSaving}
                        className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl shadow-brand/20 flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                    >
                        {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> ACEPTAR Y FIRMAR</>}
                    </button>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, MedicalHistory } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon, MedicalIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [notifications, setNotifications] = useState<Consent[]>([]);
    const [alert, setAlert] = useState<{ type: 'firma' | 'historial', name: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchDashboardData();

        // Canal para Firmas (Updates en consents)
        const consentSub = supabase
            .channel('consents_signs')
            .on('postgres_changes', { 
                event: 'UPDATE', 
                schema: 'public', 
                table: 'consents',
                filter: 'status=eq.signed'
            }, (payload) => {
                const updated = payload.new as Consent;
                triggerAlert('firma', updated.client_name);
                fetchDashboardData();
            })
            .subscribe();

        // Canal para Historiales Médicos (Nuevos envíos)
        const medicalSub = supabase
            .channel('medical_alerts')
            .on('postgres_changes', { 
                event: 'INSERT', 
                schema: 'public', 
                table: 'medical_histories' 
            }, (payload) => {
                const newHistory = payload.new as MedicalHistory;
                triggerAlert('historial', newHistory.client_name);
                fetchDashboardData();
            })
            .subscribe();

        return () => { 
            supabase.removeChannel(consentSub);
            supabase.removeChannel(medicalSub);
        };
    }, []);

    const triggerAlert = (type: 'firma' | 'historial', name: string) => {
        setAlert({ type, name });
        // Intentar reproducir un sonido sutil si el navegador lo permite
        try { new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3').play(); } catch(e) {}
        setTimeout(() => setAlert(null), 8000);
    };

    const fetchDashboardData = async () => {
        const { data: apps } = await supabase.from('appointments').select('*');
        const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
        const { data: clients } = await supabase.from('clients').select('*');
        const { data: signs } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'signed')
            .order('signed_at', { ascending: false })
            .limit(5);

        if (signs) setNotifications(signs);
        setStats({
            appointments: apps?.length || 0,
            revenue: apps?.reduce((acc, curr) => acc + (curr.price_total || 0), 0) || 0,
            lowStock: stock?.length || 0,
            newClients: clients?.length || 0
        });
        setLoading(false);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in relative pb-20">
            {/* Notificación de Alerta Dinámica */}
            {alert && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-5 rounded-3xl shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce border-2 border-white/20 flex items-center gap-4">
                    <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                        {alert.type === 'firma' ? <PencilIcon className="w-4 h-4" /> : <MedicalIcon className="w-4 h-4" />}
                    </div>
                    <div>
                        <p className="text-[10px] font-black uppercase tracking-widest">
                            {alert.type === 'firma' ? 'NUEVA FIRMA RECIBIDA' : 'NUEVO HISTORIAL CLÍNICO'}
                        </p>
                        <p className="text-xs font-bold">{alert.name.toUpperCase()}</p>
                    </div>
                </div>
            )}

            <header className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Studio Control</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em]">Panel Central Administrativo</p>
                </div>
            </header>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS TOTALES" value={stats.appointments} icon={<CalendarIcon />} />
                <StatCard title="EST. VENTAS" value={`$${stats.revenue}`} icon={<CheckIcon />} />
                <StatCard title="STOCK ALERTA" value={stats.lowStock} icon={<InventoryIcon />} color={stats.lowStock > 0 ? 'text-brand' : 'text-white'} />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl relative">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <div className="w-2.5 h-2.5 bg-brand rounded-full animate-pulse shadow-[0_0_10px_#E815DC]"></div> Últimas Firmas Digitales
                    </h3>
                    <div className="space-y-4">
                        {notifications.length === 0 ? (
                            <div className="p-12 text-center opacity-20 border border-dashed border-white/10 rounded-3xl">
                                <p className="text-[10px] font-black uppercase tracking-widest">Esperando actividad...</p>
                            </div>
                        ) : (
                            notifications.map(n => (
                                <div key={n.id} className="p-5 bg-white/[0.03] rounded-2xl border border-white/5 flex items-center justify-between group hover:border-brand/40 transition-all">
                                    <div className="flex items-center gap-4">
                                        <div className="w-11 h-11 rounded-full bg-brand/10 flex items-center justify-center text-brand border border-brand/20">
                                            <PencilIcon className="w-4 h-4"/>
                                        </div>
                                        <div>
                                            <p className="text-xs font-black text-white uppercase tracking-tight">{n.client_name}</p>
                                            <p className="text-[9px] text-gray-500 uppercase font-bold mt-0.5">{new Date(n.signed_at!).toLocaleString()}</p>
                                        </div>
                                    </div>
                                    <div className="bg-black p-2.5 rounded-xl border border-white/10 group-hover:bg-white group-hover:scale-110 transition-all">
                                        <img src={n.signature} className="h-7 w-auto invert group-hover:invert-0" alt="Sig" />
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </section>

                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <InventoryIcon className="w-5 h-5 text-brand"/> Almacén de Insumos
                    </h3>
                    {stats.lowStock > 0 ? (
                        <div className="p-8 text-center space-y-5 border-2 border-brand/20 rounded-[2rem] bg-brand/[0.03] animate-pulse">
                            <p className="text-brand font-black text-[11px] uppercase tracking-widest">¡CRÍTICO! {stats.lowStock} PRODUCTOS AGOTÁNDOSE</p>
                            <button className="w-full text-[9px] font-black text-white uppercase bg-brand px-8 py-4 rounded-2xl shadow-xl shadow-brand/20">Gestionar Stock</button>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-56 border border-dashed border-white/5 rounded-3xl opacity-20">
                            <CheckIcon className="w-10 h-10 mb-4" />
                            <p className="text-[10px] font-black uppercase tracking-widest">Todo en Orden</p>
                        </div>
                    )}
                </section>
            </div>
        </div>
    );
};

const StatCard = ({ title, value, icon, color = 'text-white' }: any) => (
    <div className="p-6 rounded-[2rem] border border-white/5 bg-[#050505] shadow-2xl group hover:border-brand/30 transition-all">
        <div className="text-gray-700 mb-4 group-hover:text-brand transition-colors">{icon}</div>
        <p className="text-[9px] text-gray-500 font-black uppercase tracking-widest mb-1">{title}</p>
        <p className={`text-2xl font-black ${color} tracking-tighter italic`}>{value}</p>
    </div>
);

