3. ACEPTACIÓN DE RIESGOS (Cláusula de Exención)
Entiendo que el tatuaje o piercing es una herida punzante y conlleva riesgos que acepto voluntariamente, incluyendo pero no limitándose a:

Infecciones: Derivadas de un mal cuidado posterior o factores externos.

Cicatrización: Riesgo de queloides (cicatriz gruesa), pérdida de pigmento o migración de tinta/joya.

Alergias: Reacciones inesperadas a los pigmentos, metales de la joyería, látex o antisépticos.

Desmayos: Mareos o fatiga durante el procedimiento debido al estrés físico.

4. IRREVERSIBILIDAD Y ESTÉTICA
Permanencia: Entiendo que un tatuaje debe considerarse permanente. Los métodos de eliminación son costosos y no garantizan el retorno a la piel original.

Resultado: Comprendo que el resultado final depende del tipo de piel y de seguir rigurosamente las instrucciones de curación.

5. CONFORMIDAD CON HIGIENE
He verificado que el material utilizado es nuevo, estéril y desechable, y que el área de trabajo cumple con las condiciones de higiene necesarias.

DECLARACIÓN FINAL: "Entiendo que la omisión de los cuidados posteriores recomendados es mi exclusiva responsabilidad. Con este conocimiento, autorizo al profesional a realizar el procedimiento."`;

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [signedConsents, setSignedConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [isSaving, setIsSaving] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const [consentText, setConsentText] = useState(DEFAULT_CONSENT_TEXT);
    const [newDocAlert, setNewDocAlert] = useState(false);
    const [viewOnlyMode, setViewOnlyMode] = useState(false);

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchAllConsents();

            const channel = supabase
                .channel('client_consents')
                .on('postgres_changes', { 
                    event: 'INSERT', 
                    schema: 'public', 
                    table: 'consents',
                    filter: `client_username=eq.${username}`
                }, () => {
                    setNewDocAlert(true);
                    fetchAllConsents();
                })
                .subscribe();

            return () => { supabase.removeChannel(channel); };
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*').order('name');
        if (data) setClients(data);
    };

    const fetchAllConsents = async () => {
        const { data } = await supabase
            .from('consents')
            .select('*')
            .eq('client_username', username)
            .order('created_at', { ascending: false });

        if (data) {
            setPendingConsents(data.filter(c => c.status === 'pending'));
            setSignedConsents(data.filter(c => c.status === 'signed'));
        }
    };

    const handleSendToClient = async () => {
        if (!selectedClientId) return alert("Selecciona un cliente");
        setIsSaving(true);
        const client = clients.find(c => c.id === Number(selectedClientId));
        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_username: client?.username,
            client_name: client?.name,
            content: finalizedText,
            status: 'pending',
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert(`¡Documento enviado con éxito a ${client?.name}!`);
            setSelectedClientId('');
        } else {
            alert("Error al enviar: " + error.message);
        }
        setIsSaving(false);
    };

    const startDrawing = (e: any) => {
        if (viewOnlyMode) return;
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) ctx.beginPath();
        draw(e);
    };

    const stopDrawing = () => {
        setIsDrawing(false);
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current || viewOnlyMode) return;
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);

        const x = clientX - rect.left;
        const y = clientY - rect.top;

        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';

        ctx.lineTo(x, y);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const handleSaveSignature = async () => {
        if (!activeConsent || !canvasRef.current) return;

        setIsSaving(true);
        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            alert("Tu consentimiento ha sido firmado y guardado correctamente.");
            setActiveConsent(null);
            fetchAllConsents();
        } else {
            alert("Error al guardar firma: " + error.message);
        }
        setIsSaving(false);
    };

    const openConsent = (consent: Consent, isHistory: boolean = false) => {
        setActiveConsent(consent);
        setViewOnlyMode(isHistory);
        setNewDocAlert(false);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in pb-20">
                <header>
                    <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Editor de Consentimiento</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Envío de Documentación Legal</p>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-1 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">1. Destinatario</label>
                            <select 
                                value={selectedClientId} 
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold text-sm focus:border-brand transition-all"
                            >
                                <option value="">SELECCIONAR CLIENTE...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name} (@{c.username})</option>)}
                            </select>
                        </div>
                        <div className="p-6 bg-brand/5 border border-brand/20 rounded-3xl">
                            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest mb-2 flex items-center gap-2">
                                <CheckIcon className="w-4 h-4" /> Crucial
                            </h4>
                            <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
                                Al enviar, el cliente recibirá una notificación en tiempo real.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">2. Texto Personalizado</label>
                            <textarea 
                                value={consentText}
                                onChange={(e) => setConsentText(e.target.value)}
                                className="w-full h-[500px] bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none focus:border-brand transition-all custom-scrollbar"
                            ></textarea>
                        </div>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl flex justify-center items-center gap-4 text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> ENVIAR PARA FIRMA</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto space-y-12 animate-fade-in pb-20">
            {newDocAlert && (
                <div className="bg-brand text-white p-5 rounded-3xl text-center text-[10px] font-black uppercase tracking-[0.2em] animate-pulse border-2 border-white/20 shadow-[0_0_30px_rgba(232,21,220,0.4)]">
                    🔔 ¡TIENES UN NUEVO DOCUMENTO POR FIRMAR!
                </div>
            )}

            {!activeConsent ? (
                <>
                    {/* SECCIÓN: PENDIENTES */}
                    <div className="space-y-6">
                        <header className="flex items-center gap-4">
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                            <h2 className="text-sm font-black text-white uppercase tracking-[0.3em] italic">Firmas Pendientes</h2>
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                        </header>

                        {pendingConsents.length === 0 ? (
                            <div className="p-16 text-center border-2 border-dashed border-white/5 rounded-[3rem] bg-[#050505] opacity-40">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.3em]">No tienes firmas solicitadas</p>
                            </div>
                        ) : (
                            <div className="grid gap-4">
                                {pendingConsents.map(c => (
                                    <button 
                                        key={c.id} 
                                        onClick={() => openConsent(c)} 
                                        className="w-full p-8 bg-brand/10 border border-brand/40 rounded-[2.5rem] flex justify-between items-center group transition-all hover:bg-brand/20 shadow-2xl"
                                    >
                                        <div className="text-left">
                                            <p className="text-[9px] text-brand font-black uppercase tracking-[0.2em] mb-1">REQUERIDO URGENTE</p>
                                            <h3 className="text-white font-black uppercase text-base tracking-tight">Consentimiento Legal</h3>
                                        </div>
                                        <div className="w-12 h-12 bg-brand text-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                                            <PencilIcon className="w-6 h-6" />
                                        </div>
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* SECCIÓN: HISTORIAL */}
                    <div className="space-y-6">
                        <header className="flex items-center gap-4">
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                            <h2 className="text-sm font-black text-gray-600 uppercase tracking-[0.3em] italic">Historial de Contratos</h2>
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                        </header>

                        {signedConsents.length === 0 ? (
                            <p className="text-center text-[9px] font-black uppercase text-gray-700 tracking-widest py-10">Aún no has firmado ningún documento</p>
                        ) : (
                            <div className="grid gap-3">
                                {signedConsents.map(c => (
                                    <div 
                                        key={c.id} 
                                        onClick={() => openConsent(c, true)}
                                        className="p-6 bg-white/[0.02] border border-white/5 rounded-3xl flex justify-between items-center hover:bg-white/[0.05] cursor-pointer transition-all"
                                    >
                                        <div>
                                            <h4 className="text-xs font-black text-white uppercase tracking-tight">Documento Firmado</h4>
                                            <p className="text-[9px] text-gray-500 font-bold uppercase mt-1">Finalizado el {new Date(c.signed_at!).toLocaleDateString()}</p>
                                        </div>
                                        <EyeIcon className="text-gray-700 w-5 h-5" />
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </>
            ) : (
                <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl space-y-8 relative animate-fade-in">
                    <button onClick={() => setActiveConsent(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors">
                        <CloseIcon className="w-6 h-6" />
                    </button>

                    <div>
                        <h3 className="text-xl font-black text-white italic uppercase tracking-tighter mb-2">
                            {viewOnlyMode ? 'Documento Firmado' : 'Firmar Consentimiento'}
                        </h3>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest">Procedimiento Seguro Bribiesca Studio</p>
                    </div>

                    <div className="bg-black p-8 rounded-3xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-[400px] overflow-y-auto custom-scrollbar italic shadow-inner">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-4">
                        <p className="text-[10px] font-black uppercase text-gray-600 tracking-[0.3em] text-center">
                            {viewOnlyMode ? 'Tu firma registrada' : 'Dibuja tu firma en el recuadro blanco'}
                        </p>
                        <div className={`bg-white rounded-[2rem] h-56 overflow-hidden touch-none border-4 border-brand/10 shadow-2xl ${viewOnlyMode ? 'pointer-events-none opacity-90' : ''}`}>
                            {viewOnlyMode && activeConsent.signature ? (
                                <img src={activeConsent.signature} className="w-full h-full object-contain p-4" alt="Firma" />
                            ) : (
                                <canvas 
                                    ref={canvasRef}
                                    width={600}
                                    height={224}
                                    className="w-full h-full cursor-crosshair"
                                    onMouseDown={startDrawing}
                                    onMouseMove={draw}
                                    onMouseUp={stopDrawing}
                                    onMouseOut={stopDrawing}
                                    onTouchStart={startDrawing}
                                    onTouchMove={draw}
                                    onTouchEnd={stopDrawing}
                                ></canvas>
                            )}
                        </div>
                        {!viewOnlyMode && (
                            <div className="flex justify-center">
                                <button 
                                    onClick={() => {
                                        const ctx = canvasRef.current?.getContext('2d');
                                        if (canvasRef.current && ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                                    }} 
                                    className="text-[9px] font-black text-brand/60 uppercase tracking-widest border-b border-brand/20 hover:text-brand transition-colors"
                                >
                                    Limpiar Firma
                                </button>
                            </div>
                        )}
                    </div>

                    {!viewOnlyMode && (
                        <button 
                            onClick={handleSaveSignature}
                            disabled={isSaving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl shadow-brand/20 flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> ACEPTAR Y FINALIZAR</>}
                        </button>
                    )}
                </div>
            )}
        </div>
    );
};

