                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">Seleccionar Destinatario</label>
                            <select 
                                value={selectedClientId} 
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold text-sm focus:border-brand transition-all"
                            >
                                <option value="">ELIGE UN CLIENTE...</option>
                                {clients.map(c => (
                                    <option key={c.id} value={c.id}>
                                        {c.name} {c.username ? `(@${c.username})` : '(SIN USUARIO)'}
                                    </option>
                                ))}
                            </select>
                            {!clients.find(c => c.id === Number(selectedClientId))?.username && selectedClientId && (
                                <p className="text-[9px] text-red-500 font-black uppercase mt-3 animate-pulse">
                                    ⚠️ ESTE CLIENTE NO TIENE USUARIO. NO PODRÁ RECIBIR EL CONTRATO.
                                </p>
                            )}
                        </div>
                        <div className="p-6 bg-brand/5 border border-brand/20 rounded-3xl">
                            <h4 className="text-[10px] font-black text-brand uppercase tracking-widest mb-2 flex items-center gap-2">
                                <CheckIcon className="w-4 h-4" /> Importante
                            </h4>
                            <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
                                Solo los clientes con un usuario (@username) creado podrán ver y firmar digitalmente desde su aplicación.
                            </p>
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">Contenido del Consentimiento</label>
                            <textarea 
                                value={consentText}
                                onChange={(e) => setConsentText(e.target.value)}
                                className="w-full h-[400px] bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none focus:border-brand transition-all custom-scrollbar"
                            ></textarea>
                        </div>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl flex justify-center items-center gap-4 text-xs disabled:opacity-20"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> ENVIAR CONTRATO AL CLIENTE</>}
                        </button>
