                                            <h3 className="text-white font-black uppercase text-base tracking-tight">Contrato de Consentimiento</h3>
                                            <p className="text-[9px] text-gray-500 uppercase mt-1">Enviado el {new Date(c.created_at).toLocaleDateString()}</p>
                                        </div>
                                        <div className="w-14 h-14 bg-brand text-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                                            <PencilIcon className="w-6 h-6" />
                                        </div>
