                                    >
                                        <div>
                                            <h4 className="text-xs font-black text-white uppercase tracking-tight group-hover:text-brand transition-colors">Contrato Finalizado</h4>
                                            <p className="text-[9px] text-gray-500 font-bold uppercase mt-1">Firmado el {new Date(c.signed_at!).toLocaleDateString()}</p>
                                        </div>
                                        <EyeIcon className="text-gray-700 w-5 h-5 group-hover:text-white transition-colors" />
                                    </div>
