            ) : (
                <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl space-y-8 relative animate-fade-in">
                    <button onClick={() => setActiveConsent(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors">
                        <CloseIcon className="w-6 h-6" />
                    </button>

                    <div className="text-center md:text-left">
                        <h3 className="text-xl font-black text-white italic uppercase tracking-tighter mb-2">
                            {viewOnlyMode ? 'Documento de Archivo' : 'Firmar Digitalmente'}
                        </h3>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest">Bribiesca Studio • Legal & Salud</p>
                    </div>

                    <div className="bg-black p-8 rounded-3xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-[400px] overflow-y-auto custom-scrollbar italic shadow-inner">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-4">
                        <p className="text-[10px] font-black uppercase text-gray-600 tracking-[0.3em] text-center">
                            {viewOnlyMode ? 'FIRMA REGISTRADA' : 'DIBUJA TU FIRMA AQUÍ'}
                        </p>
                        <div className={`bg-white rounded-[2rem] h-64 overflow-hidden touch-none border-4 border-brand/10 shadow-2xl ${viewOnlyMode ? 'pointer-events-none opacity-90' : 'cursor-crosshair'}`}>
                            {viewOnlyMode && activeConsent.signature ? (
                                <img src={activeConsent.signature} className="w-full h-full object-contain p-6" alt="Firma Registrada" />
                            ) : (
                                <canvas 
                                    ref={canvasRef}
                                    width={600}
                                    height={256}
                                    className="w-full h-full"
                                    onMouseDown={startDrawing}
                                    onMouseMove={draw}
                                    onMouseUp={stopDrawing}
                                    onMouseOut={stopDrawing}
                                    onTouchStart={startDrawing}
                                    onTouchMove={draw}
                                    onTouchEnd={stopDrawing}
                                ></canvas>
                            )}
                        </div>
                        {!viewOnlyMode && (
                            <div className="flex justify-center">
                                <button 
                                    onClick={() => {
                                        const ctx = canvasRef.current?.getContext('2d');
                                        if (canvasRef.current && ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                                    }} 
                                    className="text-[9px] font-black text-brand/60 uppercase tracking-widest border-b border-brand/20 hover:text-brand transition-colors"
                                >
                                    BORRAR Y REINTENTAR
                                </button>
                            </div>
                        )}
                    </div>

                    {!viewOnlyMode && (
                        <button 
                            onClick={handleSaveSignature}
                            disabled={isSaving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl shadow-brand/20 flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> VALIDAR Y FIRMAR DOCUMENTO</>}
                        </button>
                    )}
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, Client } from '../types';
import { CheckIcon, Spinner, CloseIcon, SendIcon, PencilIcon, SaveIcon, EyeIcon } from './Icons';

interface ConsentFormsProps {
    userRole: 'admin' | 'client';
    username: string;
}

const DEFAULT_CONSENT_TEXT = `Yo, [NOMBRE_CLIENTE], acepto los términos y condiciones de Bribiesca Studio para el procedimiento de tatuaje. He sido informado de los riesgos y cuidados posteriores.

1. SOBRE LA INFORMACIÓN RECIBIDA
He sido informado(a) detalladamente por el profesional sobre la técnica, el diseño, la zona de aplicación y el proceso de cicatrización. He tenido la oportunidad de hacer preguntas y todas mis dudas han sido resueltas de manera satisfactoria.

2. DECLARACIÓN DE SALUD Y RESPONSABILIDAD
Confirmo que he respondido con veracidad al cuestionario médico previo. Declaro que:

No estoy bajo los efectos del alcohol, drogas o medicamentos que alteren mi juicio o la coagulación de mi sangre.

No padezco enfermedades infectocontagiosas que no hayan sido comunicadas.

No estoy embarazada ni en periodo de lactancia (en caso de mujeres).

3. ACEPTACIÓN DE RIESGOS (Cláusula de Exención)
Entiendo que el tatuaje o piercing es una herida punzante y conlleva riesgos que acepto voluntariamente, incluyendo pero no limitándose a:

Infecciones: Derivadas de un mal cuidado posterior o factores externos.

Cicatrización: Riesgo de queloides (cicatriz gruesa), pérdida de pigmento o migración de tinta/joya.

Alergias: Reacciones inesperadas a los pigmentos, metales de la joyería, látex o antisépticos.

4. IRREVERSIBILIDAD Y ESTÉTICA
Permanencia: Entiendo que un tatuaje debe considerarse permanente. Los métodos de eliminación son costosos y no garantizan el retorno a la piel original.

DECLARACIÓN FINAL: "Entiendo que la omisión de los cuidados posteriores recomendados es mi exclusiva responsabilidad. Con este conocimiento, autorizo al profesional a realizar el procedimiento."`;

export const ConsentForms: React.FC<ConsentFormsProps> = ({ userRole, username }) => {
    const [clients, setClients] = useState<Client[]>([]);
    const [pendingConsents, setPendingConsents] = useState<Consent[]>([]);
    const [signedConsents, setSignedConsents] = useState<Consent[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | string>('');
    const [isSaving, setIsSaving] = useState(false);
    const [isLoadingData, setIsLoadingData] = useState(false);
    const [activeConsent, setActiveConsent] = useState<Consent | null>(null);
    const [consentText, setConsentText] = useState(DEFAULT_CONSENT_TEXT);
    const [toast, setToast] = useState<string | null>(null);
    const [viewOnlyMode, setViewOnlyMode] = useState(false);

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    useEffect(() => {
        if (userRole === 'admin') {
            fetchClients();
        } else {
            fetchAllConsents();

            // Suscripción en tiempo real para el cliente
            const channel = supabase
                .channel(`realtime_consents_${username}`)
                .on('postgres_changes', { 
                    event: 'INSERT', 
                    schema: 'public', 
                    table: 'consents',
                    filter: `client_username=eq.${username}`
                }, () => {
                    setToast("¡HAS RECIBIDO UN NUEVO DOCUMENTO!");
                    fetchAllConsents();
                    setTimeout(() => setToast(null), 5000);
                })
                .subscribe();

            return () => { supabase.removeChannel(channel); };
        }
    }, [userRole, username]);

    const fetchClients = async () => {
        const { data } = await supabase.from('clients').select('*').order('name');
        if (data) setClients(data);
    };

    const fetchAllConsents = async () => {
        setIsLoadingData(true);
        // Usamos ilike para evitar problemas de mayúsculas/minúsculas en el username
        const { data, error } = await supabase
            .from('consents')
            .select('*')
            .ilike('client_username', username)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("Error al obtener consentimientos:", error);
        }

        if (data) {
            setPendingConsents(data.filter(c => c.status === 'pending'));
            setSignedConsents(data.filter(c => c.status === 'signed'));
        }
        setIsLoadingData(false);
    };

    const handleSendToClient = async () => {
        if (!selectedClientId) return alert("Selecciona un cliente");

        const client = clients.find(c => c.id === Number(selectedClientId));

        if (!client?.username) {
            return alert(`ERROR: El cliente ${client?.name} no tiene un @usuario asignado en su ficha. Para que pueda firmar desde la app, primero edita su perfil y asígnale un nombre de usuario.`);
        }

        setIsSaving(true);
        const finalizedText = consentText.replace('[NOMBRE_CLIENTE]', client?.name || '');

        const { error } = await supabase.from('consents').insert([{
            client_id: client?.id,
            client_username: client?.username,
            client_name: client?.name,
            content: finalizedText,
            status: 'pending',
            created_at: new Date().toISOString()
        }]);

        if (!error) {
            alert(`¡Contrato enviado correctamente a @${client?.username}!`);
            setSelectedClientId('');
        } else {
            alert("Error de base de datos: " + error.message);
        }
        setIsSaving(false);
    };

    const startDrawing = (e: any) => {
        if (viewOnlyMode) return;
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) {
            ctx.beginPath();
            const rect = canvasRef.current?.getBoundingClientRect();
            const x = (e.clientX || (e.touches && e.touches[0].clientX)) - rect.left;
            const y = (e.clientY || (e.touches && e.touches[0].clientY)) - rect.top;
            ctx.moveTo(x, y);
        }
    };

    const draw = (e: any) => {
        if (!isDrawing || !canvasRef.current || viewOnlyMode) return;
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);

        const x = clientX - rect.left;
        const y = clientY - rect.top;

        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#E815DC';
        ctx.lineTo(x, y);
        ctx.stroke();
    };

    const stopDrawing = () => {
        setIsDrawing(false);
    };

    const handleSaveSignature = async () => {
        if (!activeConsent || !canvasRef.current) return;

        setIsSaving(true);
        const signatureBase64 = canvasRef.current.toDataURL('image/png');

        const { error } = await supabase
            .from('consents')
            .update({ 
                signature: signatureBase64, 
                status: 'signed',
                signed_at: new Date().toISOString()
            })
            .eq('id', activeConsent.id);

        if (!error) {
            alert("Firma guardada con éxito.");
            setActiveConsent(null);
            fetchAllConsents();
        } else {
            alert("Error al guardar: " + error.message);
        }
        setIsSaving(false);
    };

    const openConsent = (consent: Consent, isHistory: boolean = false) => {
        setActiveConsent(consent);
        setViewOnlyMode(isHistory);
        setToast(null);
    };

    if (userRole === 'admin') {
        return (
            <div className="space-y-8 animate-fade-in pb-20">
                <header>
                    <h2 className="text-2xl font-black italic text-white uppercase tracking-tighter">Envío de Documentación</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Gestión de Consentimientos Legales</p>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-1 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">Paso 1: Destinatario</label>
                            <select 
                                value={selectedClientId} 
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                className="w-full bg-black p-5 rounded-2xl border border-white/10 text-white font-bold text-sm focus:border-brand transition-all"
                            >
                                <option value="">LISTA DE CLIENTES...</option>
                                {clients.map(c => (
                                    <option key={c.id} value={c.id}>
                                        {c.name} {c.username ? `(@${c.username})` : '(SIN USUARIO)'}
                                    </option>
                                ))}
                            </select>
                            {selectedClientId && !clients.find(c => c.id === Number(selectedClientId))?.username && (
                                <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl">
                                    <p className="text-[9px] text-red-500 font-black uppercase leading-tight">
                                        ⚠️ ATENCIÓN: Este cliente no tiene usuario vinculado. Debes ir a la sección "Fichas" y asignarle un nombre de usuario antes de enviarle documentos.
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-[#050505] p-6 rounded-3xl border border-white/5 shadow-2xl">
                            <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest mb-3">Paso 2: Contenido del Contrato</label>
                            <textarea 
                                value={consentText}
                                onChange={(e) => setConsentText(e.target.value)}
                                className="w-full h-[350px] bg-black p-6 rounded-2xl border border-white/10 text-gray-300 font-medium leading-relaxed resize-none focus:border-brand transition-all custom-scrollbar italic"
                            ></textarea>
                        </div>
                        <button 
                            onClick={handleSendToClient}
                            disabled={isSaving || !selectedClientId || !clients.find(c => c.id === Number(selectedClientId))?.username}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl flex justify-center items-center gap-4 text-xs disabled:opacity-20"
                        >
                            {isSaving ? <Spinner /> : <><SendIcon className="w-5 h-5"/> ENVIAR A LA APP DEL CLIENTE</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto space-y-12 animate-fade-in pb-20 relative">
            {toast && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-5 rounded-3xl shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce border-2 border-white/20 flex items-center gap-4">
                    <CheckIcon className="w-6 h-6" />
                    <span className="text-[10px] font-black uppercase tracking-widest">{toast}</span>
                </div>
            )}

            {!activeConsent ? (
                <>
                    <div className="space-y-6">
                        <header className="flex items-center justify-between gap-4">
                            <h2 className="text-sm font-black text-white uppercase tracking-[0.3em] italic">Firmas Pendientes</h2>
                            <button 
                                onClick={fetchAllConsents} 
                                className="text-[8px] font-black text-brand uppercase border border-brand/20 px-3 py-1.5 rounded-full hover:bg-brand/10 transition-all flex items-center gap-2"
                                disabled={isLoadingData}
                            >
                                {isLoadingData ? <Spinner /> : 'REFRESCAR'}
                            </button>
                        </header>

                        {pendingConsents.length === 0 ? (
                            <div className="p-16 text-center border-2 border-dashed border-white/5 rounded-[3rem] bg-[#050505] opacity-40">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.3em]">No hay documentos nuevos por ahora</p>
                            </div>
                        ) : (
                            <div className="grid gap-4">
                                {pendingConsents.map(c => (
                                    <button 
                                        key={c.id} 
                                        onClick={() => openConsent(c)} 
                                        className="w-full p-8 bg-brand/5 border-2 border-brand/40 rounded-[2.5rem] flex justify-between items-center group transition-all hover:bg-brand/10 shadow-[0_0_40px_rgba(232,21,220,0.1)]"
                                    >
                                        <div className="text-left">
                                            <p className="text-[9px] text-brand font-black uppercase tracking-[0.2em] mb-1">¡REQUIERE TU FIRMA!</p>
                                            <h3 className="text-white font-black uppercase text-base tracking-tight italic">Consentimiento de Salud</h3>
                                            <p className="text-[9px] text-gray-500 uppercase mt-1">Recibido: {new Date(c.created_at).toLocaleDateString()}</p>
                                        </div>
                                        <div className="w-14 h-14 bg-brand text-white rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                                            <PencilIcon className="w-6 h-6" />
                                        </div>
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="space-y-6">
                        <header className="flex items-center gap-4">
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                            <h2 className="text-sm font-black text-gray-600 uppercase tracking-[0.3em] italic">Contratos Firmados</h2>
                            <div className="h-0.5 flex-grow bg-white/5"></div>
                        </header>

                        {signedConsents.length === 0 ? (
                            <p className="text-center text-[9px] font-black uppercase text-gray-700 tracking-widest py-10 opacity-30">Tu historial está vacío</p>
                        ) : (
                            <div className="grid gap-3">
                                {signedConsents.map(c => (
                                    <div 
                                        key={c.id} 
                                        onClick={() => openConsent(c, true)}
                                        className="p-6 bg-white/[0.02] border border-white/5 rounded-3xl flex justify-between items-center hover:bg-white/[0.05] cursor-pointer group"
                                    >
                                        <div>
                                            <h4 className="text-xs font-black text-white uppercase group-hover:text-brand transition-colors">Contrato Completado</h4>
                                            <p className="text-[9px] text-gray-500 font-bold uppercase mt-1 italic">Firmado el {new Date(c.signed_at!).toLocaleDateString()}</p>
                                        </div>
                                        <EyeIcon className="text-gray-700 w-5 h-5 group-hover:text-white transition-colors" />
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </>
            ) : (
                <div className="bg-[#050505] p-10 rounded-[3rem] border border-brand/30 shadow-2xl space-y-8 relative animate-fade-in">
                    <button onClick={() => setActiveConsent(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors">
                        <CloseIcon className="w-6 h-6" />
                    </button>

                    <div className="text-center md:text-left">
                        <h3 className="text-xl font-black text-white italic uppercase tracking-tighter mb-2">
                            {viewOnlyMode ? 'Vista de Archivo' : 'Firmar Documento'}
                        </h3>
                        <p className="text-[10px] text-brand font-black uppercase tracking-widest">Bribiesca Studio Digital Consent</p>
                    </div>

                    <div className="bg-black p-8 rounded-3xl border border-white/5 text-sm text-gray-400 leading-relaxed max-h-[400px] overflow-y-auto custom-scrollbar italic shadow-inner">
                        {activeConsent.content}
                    </div>

                    <div className="space-y-4">
                        <p className="text-[10px] font-black uppercase text-gray-600 tracking-[0.3em] text-center">
                            {viewOnlyMode ? 'ESTA ES TU FIRMA REGISTRADA' : 'USA TU DEDO PARA FIRMAR AQUÍ'}
                        </p>
                        <div className={`bg-white rounded-[2rem] h-64 overflow-hidden touch-none border-4 border-brand/10 shadow-2xl ${viewOnlyMode ? 'pointer-events-none' : 'cursor-crosshair'}`}>
                            {viewOnlyMode && activeConsent.signature ? (
                                <img src={activeConsent.signature} className="w-full h-full object-contain p-6" alt="Firma" />
                            ) : (
                                <canvas 
                                    ref={canvasRef}
                                    width={600}
                                    height={256}
                                    className="w-full h-full"
                                    onMouseDown={startDrawing}
                                    onMouseMove={draw}
                                    onMouseUp={stopDrawing}
                                    onMouseOut={stopDrawing}
                                    onTouchStart={startDrawing}
                                    onTouchMove={draw}
                                    onTouchEnd={stopDrawing}
                                ></canvas>
                            )}
                        </div>
                        {!viewOnlyMode && (
                            <div className="flex justify-center">
                                <button 
                                    onClick={() => {
                                        const ctx = canvasRef.current?.getContext('2d');
                                        if (canvasRef.current && ctx) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                                    }} 
                                    className="text-[9px] font-black text-brand/60 uppercase tracking-widest border-b border-brand/20 hover:text-brand transition-colors"
                                >
                                    LIMPIAR Y REPETIR
                                </button>
                            </div>
                        )}
                    </div>

                    {!viewOnlyMode && (
                        <button 
                            onClick={handleSaveSignature}
                            disabled={isSaving}
                            className="w-full py-6 bg-brand text-white font-black rounded-2xl uppercase tracking-widest shadow-xl flex justify-center items-center gap-3 active:scale-95 transition-all text-xs"
                        >
                            {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> FINALIZAR Y ENVIAR AL STUDIO</>}
                        </button>
                    )}
                </div>
            )}
        </div>
    );
};

payload.text:
El error que viste en Supabase (`relation "consents" is already member of publication`) significa que la tabla ya está vinculada al sistema de tiempo real, por lo que esa parte ya está bien. Sin embargo, el hecho de que no veas los documentos suele deberse a dos cosas: **Falta de permisos (RLS)** o una **mismatch (desajuste) entre el nombre de usuario del administrador y el del cliente**.

He preparado una solución definitiva que incluye un "Modo de Diagnóstico" visual para que puedas ver exactamente qué está pasando.

### 1. Código SQL Corrector (Ejecuta esto en Supabase)

Ejecuta este bloque. He añadido la desactivación de **RLS (Row Level Security)**. Si el RLS está activado y no hay "Políticas", Supabase bloquea la lectura de datos aunque existan en la tabla.

```sql
-- 1. Asegurar que la tabla tenga la columna correcta para filtrar
DO $$ 
BEGIN 
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='consents' AND column_name='client_username') THEN
        ALTER TABLE public.consents ADD COLUMN client_username TEXT;
    END IF;
END $$;

-- 2. DESACTIVAR RLS (Esto es lo más probable que esté bloqueando la vista)
-- Al desactivar RLS, permitimos que la App lea los datos con la "Anon Key"
ALTER TABLE IF EXISTS public.consents DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS public.clients DISABLE ROW LEVEL SECURITY;

-- 3. Asegurar que la tabla está en la publicación de tiempo real (sin dar error si ya existe)
-- Ya vimos que existe por tu captura, así que esto es solo por seguridad
DO $$ 
BEGIN 
    IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'consents') THEN
        ALTER PUBLICATION supabase_realtime ADD TABLE consents;
    END IF;
EXCEPTION WHEN OTHERS THEN 
    NULL; 
END $$;
```

