        schooling: '',
        email: '',
        conditions: [],
        allergies_detail: '',
        appointment_motive: '',
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        const { data: hist } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        const { data: clie } = await supabase.from('clients').select('*').order('name');
        if (hist) setHistories(hist);
        if (clie) setClients(clie);
        setLoading(false);
    };

    const handleConditionToggle = (cond: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(cond) 
                ? prev.conditions.filter(c => c !== cond) 
                : [...prev.conditions, cond]
        }));
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const { error } = await supabase.from('medical_histories').insert([formData]);
        if (!error) {
            alert("Historial Clínico Guardado.");
            setIsModalOpen(false);
            fetchData();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const exportToPDF = (item: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.text("BRIBIESCA STUDIO - FICHA CLÍNICA", 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.text(`Expediente N: ${item.id} | Fecha: ${new Date(item.created_at!).toLocaleDateString()}`, 105, 28, { align: 'center' });

        doc.setLineWidth(0.5);
        doc.line(20, 35, 190, 35);

        doc.setFont("helvetica", "bold");
        doc.text("DATOS PERSONALES", 20, 45);
        doc.setFont("helvetica", "normal");
        doc.text(`Nombre: ${item.client_name}`, 20, 52);
        doc.text(`F. Nacimiento: ${item.birth_date} | Edad: ${item.age} | Sexo: ${item.sex}`, 20, 59);
        doc.text(`Dirección: ${item.address}`, 20, 66);
        doc.text(`Teléfono: ${item.phone} | Ocupación: ${item.occupation}`, 20, 73);
        doc.text(`Residencia: ${item.residence} | Escolaridad: ${item.schooling}`, 20, 80);
        doc.text(`Email: ${item.email}`, 20, 87);

        doc.setFont("helvetica", "bold");
        doc.text("INFORMACIÓN DE SALUD", 20, 100);
        doc.setFont("helvetica", "normal");
        doc.text(`Condiciones registradas: ${item.conditions.join(', ') || 'Ninguna'}`, 20, 107);
        doc.text(`Alergias: ${item.allergies_detail || 'No declaradas'}`, 20, 114);

        doc.setFont("helvetica", "bold");
        doc.text("MOTIVO DE LA CITA", 20, 127);
        doc.setFont("helvetica", "normal");
        doc.setLineWidth(0.1);
        doc.rect(20, 132, 170, 40);
        doc.text(item.appointment_motive || 'Sin descripción', 25, 138, { maxWidth: 160 });

        doc.text("__________________________", 50, 220);
        doc.text("Firma del Cliente", 58, 225);
        doc.text("__________________________", 130, 220);
        doc.text("Firma Testigo / Artista", 135, 225);

        doc.save(`Historial_${item.client_name.replace(' ', '_')}.pdf`);
    };

    const handlePrint = (item: MedicalHistory) => {
        const printWindow = window.open('', '_blank');
        if (printWindow) {
            printWindow.document.write(`
                <html>
                    <head><title>Imprimir Historial</title><style>body{font-family:sans-serif;padding:40px;} h1{text-align:center;border-bottom:2px solid #000;padding-bottom:10px;} .field{margin-bottom:10px;} label{font-weight:bold;}</style></head>
                    <body>
                        <h1>BRIBIESCA STUDIO - FICHA CLÍNICA</h1>
                        <div class="field"><label>Nombre:</label> ${item.client_name}</div>
                        <div class="field"><label>Edad/Sexo:</label> ${item.age} / ${item.sex}</div>
                        <div class="field"><label>Salud:</label> ${item.conditions.join(', ')}</div>
                        <div class="field"><label>Alergias:</label> ${item.allergies_detail}</div>
                        <div class="field"><label>Motivo:</label><p>${item.appointment_motive}</p></div>
                        <br><br><br>
                        <div style="display:flex;justify-content:space-around">
                            <p>_____________________<br>Firma Cliente</p>
                            <p>_____________________<br>Firma Artista</p>
                        </div>
                    </body>
                </html>
            `);
            printWindow.document.close();
            printWindow.print();
        }
    };

    const filtered = histories.filter(h => h.client_name.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="space-y-8 animate-fade-in pb-20">
            <header className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Historial Clínico</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Archivo de Salud del Studio</p>
                </div>
                <button 
                    onClick={() => setIsModalOpen(true)}
                    className="bg-brand text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 active:scale-95"
                >
                    <PlusIcon className="w-4 h-4" /> Nueva Ficha
                </button>
            </header>

            <div className="relative">
                <input 
                    type="text" 
                    placeholder="BUSCAR EXPEDIENTE POR NOMBRE..."
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full bg-black p-6 pl-14 rounded-3xl border border-white/5 font-bold text-white focus:border-brand outline-none"
                />
                <SearchIcon className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-500 w-5 h-5" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {loading ? <Spinner /> : filtered.map(item => (
                    <div key={item.id} className="bg-[#050505] p-6 rounded-[2.5rem] border border-white/5 group hover:border-brand/40 transition-all shadow-2xl">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="font-black text-white text-base uppercase italic">{item.client_name}</h4>
                                <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Registrado el {new Date(item.created_at!).toLocaleDateString()}</p>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setViewMode(item)} className="p-3 bg-white/5 rounded-xl text-gray-400 hover:text-white"><PlusIcon className="w-4 h-4" /></button>
                                <button onClick={() => exportToPDF(item)} className="p-3 bg-white/5 rounded-xl text-brand hover:scale-110 transition-transform"><DownloadIcon className="w-4 h-4" /></button>
                            </div>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {item.conditions.slice(0, 3).map(c => (
                                <span key={c} className="text-[7px] font-black uppercase bg-brand/10 text-brand px-2 py-1 rounded-md border border-brand/20">{c}</span>
                            ))}
                            {item.conditions.length > 3 && <span className="text-[7px] text-gray-600 font-black">+{item.conditions.length - 3} MÁS</span>}
                        </div>
                    </div>
                ))}
            </div>

            {/* Modal: Nuevo Historial */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[150] flex items-center justify-center p-6">
                    <div className="bg-[#050505] border border-white/10 w-full max-w-4xl rounded-[3rem] p-10 space-y-8 shadow-2xl overflow-y-auto max-h-[90vh] custom-scrollbar">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-2xl font-black text-brand italic uppercase tracking-tighter">Nueva Ficha Clínica</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white"><CloseIcon /></button>
                        </div>

                        <form onSubmit={handleSave} className="space-y-8">
                            <section className="space-y-6">
                                <h5 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] border-b border-white/5 pb-2">1. DATOS PERSONALES</h5>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    <div className="md:col-span-2">
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Nombre del Paciente</label>
                                        <input type="text" list="client-list" value={formData.client_name} onChange={e => setFormData({...formData, client_name: e.target.value})} required className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                        <datalist id="client-list">
                                            {clients.map(c => <option key={c.id} value={c.name} />)}
                                        </datalist>
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">F. Nacimiento</label>
                                        <input type="date" value={formData.birth_date} onChange={e => setFormData({...formData, birth_date: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Edad</label>
                                        <input type="number" value={formData.age} onChange={e => setFormData({...formData, age: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Sexo</label>
                                        <select value={formData.sex} onChange={e => setFormData({...formData, sex: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold">
                                            <option value="M">Masculino</option>
                                            <option value="F">Femenino</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Teléfono</label>
                                        <input type="tel" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div className="md:col-span-3">
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Dirección Completa</label>
                                        <input type="text" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Ocupación</label>
                                        <input type="text" value={formData.occupation} onChange={e => setFormData({...formData, occupation: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Residencia</label>
                                        <input type="text" value={formData.residence} onChange={e => setFormData({...formData, residence: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div>
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Escolaridad</label>
                                        <input type="text" value={formData.schooling} onChange={e => setFormData({...formData, schooling: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div className="md:col-span-3">
                                        <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Email</label>
                                        <input type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                </div>
                            </section>

                            <section className="space-y-6">
                                <h5 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] border-b border-white/5 pb-2">2. INFORMACIÓN DE SALUD</h5>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                    {CONDITIONS_LIST.map(cond => (
                                        <button 
                                            key={cond} 
                                            type="button"
                                            onClick={() => handleConditionToggle(cond)}
                                            className={`p-4 rounded-2xl border text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center text-center ${formData.conditions.includes(cond) ? 'bg-brand border-brand text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-500 hover:border-brand/40'}`}
                                        >
                                            {cond}
                                        </button>
                                    ))}
                                </div>
                                <div className="mt-6">
                                    <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-2">Alergias (Especificar)</label>
                                    <input type="text" value={formData.allergies_detail} onChange={e => setFormData({...formData, allergies_detail: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-red-500/20 text-red-500 font-bold" placeholder="Escriba alergias críticas..." />
                                </div>
                            </section>

                            <section className="space-y-6">
                                <h5 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] border-b border-white/5 pb-2">3. MOTIVO DE LA CITA</h5>
                                <textarea 
                                    value={formData.appointment_motive} 
                                    onChange={e => setFormData({...formData, appointment_motive: e.target.value})}
                                    className="w-full bg-black p-6 rounded-[2rem] border border-white/10 font-bold min-h-[150px]"
                                    placeholder="Diseño, tamaño aproximado y zona del cuerpo..."
                                ></textarea>
                            </section>

                            <div className="flex gap-4">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-6 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest">Cancelar</button>
                                <button type="submit" disabled={isSaving} className="flex-1 py-6 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex justify-center items-center gap-2">
                                    {isSaving ? <Spinner /> : <><SaveIcon className="w-4 h-4"/> Guardar Expediente</>}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Modal: Ver Ficha Completa */}
            {viewMode && (
                <div className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[150] flex items-center justify-center p-6 animate-fade-in">
                    <div className="bg-[#050505] border border-brand/30 w-full max-w-3xl rounded-[3rem] p-10 space-y-8 shadow-2xl relative overflow-y-auto max-h-[90vh]">
                        <button onClick={() => setViewMode(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white"><CloseIcon /></button>

                        <div className="text-center">
                            <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">Ficha del Paciente</h3>
                            <p className="text-[10px] text-brand font-black uppercase tracking-widest">Vista de Lectura</p>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-sm">
                            <div className="space-y-4">
                                <p><span className="text-gray-500 uppercase font-black text-[9px] tracking-widest">Nombre:</span> <br/> <strong className="text-white uppercase">{viewMode.client_name}</strong></p>
                                <p><span className="text-gray-500 uppercase font-black text-[9px] tracking-widest">F. Nac / Edad:</span> <br/> {viewMode.birth_date} / {viewMode.age} años</p>
                                <p><span className="text-gray-500 uppercase font-black text-[9px] tracking-widest">Contacto:</span> <br/> {viewMode.phone} | {viewMode.email}</p>
                            </div>
                            <div className="space-y-4">
                                <p><span className="text-gray-500 uppercase font-black text-[9px] tracking-widest">Salud:</span> <br/> {viewMode.conditions.join(', ') || 'Ninguna declarada'}</p>
                                <p><span className="text-gray-500 uppercase font-black text-[9px] tracking-widest">Alergias:</span> <br/> <span className="text-red-500 font-bold">{viewMode.allergies_detail || 'Sin alergias'}</span></p>
                            </div>
                            <div className="md:col-span-2 p-6 bg-white/[0.02] rounded-3xl border border-white/5">
                                <p className="text-gray-500 uppercase font-black text-[9px] tracking-widest mb-2">Motivo y Diseño:</p>
                                <p className="text-white italic">{viewMode.appointment_motive}</p>
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <button onClick={() => handlePrint(viewMode)} className="flex-1 py-5 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><PrintIcon className="w-4 h-4"/> Imprimir</button>
                            <button onClick={() => exportToPDF(viewMode)} className="flex-1 py-5 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl"><DownloadIcon className="w-4 h-4"/> Exportar PDF</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, MedicalHistory } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon, MedicalIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [notifications, setNotifications] = useState<Consent[]>([]);
    const [alert, setAlert] = useState<{ type: 'firma' | 'historial', name: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchDashboardData();

        // Canal para Firmas (Updates en consents)
        const consentSub = supabase
            .channel('consents_signs')
            .on('postgres_changes', { 
                event: 'UPDATE', 
                schema: 'public', 
                table: 'consents',
                filter: 'status=eq.signed'
            }, (payload) => {
                const updated = payload.new as Consent;
                triggerSystemNotification('NUEVA FIRMA', `El cliente ${updated.client_name} ha firmado su consentimiento.`);
                triggerAlert('firma', updated.client_name);
                fetchDashboardData();
            })
            .subscribe();

        // Canal para Historiales Médicos (Nuevos envíos)
        const medicalSub = supabase
            .channel('medical_alerts')
            .on('postgres_changes', { 
                event: 'INSERT', 
                schema: 'public', 
                table: 'medical_histories' 
            }, (payload) => {
                const newHistory = payload.new as MedicalHistory;
                triggerSystemNotification('NUEVO HISTORIAL', `Recibiste la ficha clínica de ${newHistory.client_name}.`);
                triggerAlert('historial', newHistory.client_name);
                fetchDashboardData();
            })
            .subscribe();

        return () => { 
            supabase.removeChannel(consentSub);
            supabase.removeChannel(medicalSub);
        };
    }, []);

    const triggerSystemNotification = (title: string, body: string) => {
        if ("Notification" in window && Notification.permission === "granted") {
            // Fix: 'vibrate' property removed from NotificationOptions as it's not a valid property for the Notification constructor.
            new Notification(title, {
                body,
                icon: 'https://appdesignmex.com/bribiescaicono.png',
            });
        }
    };

    const triggerAlert = (type: 'firma' | 'historial', name: string) => {
        setAlert({ type, name });
        try { new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3').play(); } catch(e) {}
        setTimeout(() => setAlert(null), 8000);
    };

    const fetchDashboardData = async () => {
        const { data: apps } = await supabase.from('appointments').select('*');
        const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
        const { data: clients } = await supabase.from('clients').select('*');
        const { data: signs } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'signed')
            .order('signed_at', { ascending: false })
            .limit(5);

        if (signs) setNotifications(signs);
        setStats({
            appointments: apps?.length || 0,
            revenue: apps?.reduce((acc, curr) => acc + (curr.price_total || 0), 0) || 0,
            lowStock: stock?.length || 0,
            newClients: clients?.length || 0
        });
        setLoading(false);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in relative pb-20">
            {alert && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-5 rounded-3xl shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce border-2 border-white/20 flex items-center gap-4">
                    <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                        {alert.type === 'firma' ? <PencilIcon className="w-4 h-4" /> : <MedicalIcon className="w-4 h-4" />}
                    </div>
                    <div>
                        <p className="text-[10px] font-black uppercase tracking-widest">
                            {alert.type === 'firma' ? 'NOTIFICACIÓN DE FIRMA' : 'SISTEMA: FICHA MÉDICA'}
                        </p>
                        <p className="text-xs font-bold">{alert.name.toUpperCase()}</p>
                    </div>
                </div>
            )}

            <header className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Studio Intelligence</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em]">Panel de Control en Vivo</p>
                </div>
            </header>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS" value={stats.appointments} icon={<CalendarIcon />} />
                <StatCard title="INGRESOS" value={`$${stats.revenue}`} icon={<CheckIcon />} />
                <StatCard title="STOCK BAJO" value={stats.lowStock} icon={<InventoryIcon />} color={stats.lowStock > 0 ? 'text-brand' : 'text-white'} />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <div className="w-2.5 h-2.5 bg-brand rounded-full animate-pulse"></div> Actividad Reciente
                    </h3>
                    <div className="space-y-4">
                        {notifications.length === 0 ? (
                            <p className="text-center py-10 opacity-20 text-[10px] font-black uppercase">Sin firmas hoy</p>
                        ) : (
                            notifications.map(n => (
                                <div key={n.id} className="p-5 bg-white/[0.03] rounded-2xl border border-white/5 flex items-center justify-between group">
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand">
                                            <PencilIcon className="w-4 h-4"/>
                                        </div>
                                        <div>
                                            <p className="text-xs font-black text-white uppercase">{n.client_name}</p>
                                            <p className="text-[9px] text-gray-500 font-bold">{new Date(n.signed_at!).toLocaleTimeString()}</p>
                                        </div>
                                    </div>
                                    <img src={n.signature} className="h-6 invert opacity-50" alt="Sig" />
                                </div>
                            ))
                        )}
                    </div>
                </section>

                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <InventoryIcon className="w-5 h-5 text-brand"/> Suministros Críticos
                    </h3>
                    {stats.lowStock > 0 ? (
                        <div className="p-8 text-center border-2 border-brand/20 rounded-[2rem] bg-brand/[0.03] animate-pulse">
                            <p className="text-brand font-black text-[11px] uppercase tracking-widest">Atención: Reponer Stock</p>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-40 opacity-20">
                            <CheckIcon className="w-10 h-10 mb-2" />
                            <p className="text-[10px] font-black uppercase tracking-widest">Almacén lleno</p>
                        </div>
                    )}
                </section>
            </div>
        </div>
    );
};

const StatCard = ({ title, value, icon, color = 'text-white' }: any) => (
