                                    </div>
                                </section>

                                <section className="space-y-6">
                                    <h5 className="text-[10px] font-black text-brand uppercase tracking-[0.3em] border-b border-brand/20 pb-2">2. INFORMACIÓN DE SALUD</h5>
                                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
