                                                className={`p-4 rounded-2xl border text-[9px] font-black uppercase tracking-widest transition-all flex items-center justify-center text-center leading-tight ${formData.conditions.includes(cond) ? 'bg-brand border-brand text-white shadow-[0_0_20px_rgba(232,21,220,0.4)]' : 'bg-white/5 border-white/10 text-gray-600 hover:border-brand/40'}`}
