                                    <p className="text-white italic leading-relaxed text-base font-medium whitespace-pre-line">{viewMode.appointment_motive || 'Información no proporcionada'}</p>
                                </div>
                            </div>

                            {/* Actions with padding for bottom nav */}
                            <div className="pb-32 pt-10 flex flex-col sm:flex-row gap-4">
                                <button onClick={() => handlePrint(viewMode)} className="flex-1 py-5 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 border border-white/5 hover:bg-white/10 transition-colors">
