                                    <DownloadIcon className="w-5 h-5"/> Generar Reporte PDF
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { MedicalHistory, Client } from '../types';
import { Spinner, PlusIcon, SearchIcon, CloseIcon, SaveIcon, DownloadIcon, PrintIcon } from './Icons';
import { jsPDF } from 'jspdf';

const CONDITIONS_LIST = [
    "Diabetes", "Hipertensión", "Epilepsia", "COVID-19", "Hepatitis A, B o C", "Influenza", "VIH/SIDA"
];

export const MedicalHistoryManager: React.FC = () => {
    const [histories, setHistories] = useState<MedicalHistory[]>([]);
    const [clients, setClients] = useState<Client[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [viewMode, setViewMode] = useState<MedicalHistory | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [isSaving, setIsSaving] = useState(false);

    // Form State
    const [formData, setFormData] = useState<MedicalHistory>({
        client_name: '',
        birth_date: '',
        age: '',
        sex: 'M',
        address: '',
        phone: '',
        occupation: '',
        residence: '',
        schooling: '',
        email: '',
        conditions: [],
        allergies_detail: '',
        appointment_motive: '',
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        const { data: hist } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        const { data: clie } = await supabase.from('clients').select('*').order('name');
        if (hist) setHistories(hist);
        if (clie) setClients(clie);
        setLoading(false);
    };

    const handleConditionToggle = (cond: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(cond) 
                ? prev.conditions.filter(c => c !== cond) 
                : [...prev.conditions, cond]
        }));
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const { error } = await supabase.from('medical_histories').insert([formData]);
        if (!error) {
            alert("Historial Clínico Guardado.");
            setIsModalOpen(false);
            fetchData();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const exportToPDF = (item: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.text("BRIBIESCA STUDIO - FICHA CLÍNICA", 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.text(`Expediente N: ${item.id} | Fecha: ${new Date(item.created_at!).toLocaleDateString()}`, 105, 28, { align: 'center' });
        doc.setLineWidth(0.5);
        doc.line(20, 35, 190, 35);
        doc.setFont("helvetica", "bold");
        doc.text("DATOS PERSONALES", 20, 45);
        doc.setFont("helvetica", "normal");
        doc.text(`Nombre: ${item.client_name}`, 20, 52);
        doc.text(`F. Nacimiento: ${item.birth_date} | Edad: ${item.age} | Sexo: ${item.sex}`, 20, 59);
        doc.text(`Dirección: ${item.address}`, 20, 66);
        doc.text(`Teléfono: ${item.phone} | Ocupación: ${item.occupation}`, 20, 73);
        doc.text(`Residencia: ${item.residence} | Escolaridad: ${item.schooling}`, 20, 80);
        doc.text(`Email: ${item.email}`, 20, 87);
        doc.setFont("helvetica", "bold");
        doc.text("INFORMACIÓN DE SALUD", 20, 100);
        doc.setFont("helvetica", "normal");
        doc.text(`Condiciones registradas: ${item.conditions.join(', ') || 'Ninguna'}`, 20, 107);
        doc.text(`Alergias: ${item.allergies_detail || 'No declaradas'}`, 20, 114);
        doc.setFont("helvetica", "bold");
        doc.text("MOTIVO DE LA CITA", 20, 127);
        doc.setFont("helvetica", "normal");
        doc.setLineWidth(0.1);
        doc.rect(20, 132, 170, 40);
        doc.text(item.appointment_motive || 'Sin descripción', 25, 138, { maxWidth: 160 });
        doc.save(`Historial_${item.client_name.replace(' ', '_')}.pdf`);
    };

    const handlePrint = (item: MedicalHistory) => {
        const printWindow = window.open('', '_blank');
        if (printWindow) {
            printWindow.document.write(`
                <html>
                    <head><title>Imprimir Historial</title><style>body{font-family:sans-serif;padding:40px;} h1{text-align:center;border-bottom:2px solid #000;padding-bottom:10px;} .field{margin-bottom:10px;} label{font-weight:bold;}</style></head>
                    <body>
                        <h1>BRIBIESCA STUDIO - FICHA CLÍNICA</h1>
                        <div class="field"><label>Nombre:</label> ${item.client_name}</div>
                        <div class="field"><label>Edad/Sexo:</label> ${item.age} / ${item.sex}</div>
                        <div class="field"><label>Salud:</label> ${item.conditions.join(', ')}</div>
                        <div class="field"><label>Alergias:</label> ${item.allergies_detail}</div>
                        <div class="field"><label>Motivo:</label><p>${item.appointment_motive}</p></div>
                        <br><br><br>
                        <div style="display:flex;justify-content:space-around">
                            <p>_____________________<br>Firma Cliente</p>
                            <p>_____________________<br>Firma Artista</p>
                        </div>
                    </body>
                </html>
            `);
            printWindow.document.close();
            printWindow.print();
        }
    };

    const filtered = histories.filter(h => h.client_name.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="space-y-6 animate-fade-in pb-20">
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Historial Clínico</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Archivo de Salud del Studio</p>
                </div>
                <button 
                    onClick={() => setIsModalOpen(true)}
                    className="w-full sm:w-auto bg-brand text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 active:scale-95 transition-transform"
                >
                    <PlusIcon className="w-4 h-4" /> Nueva Ficha
                </button>
            </header>

            <div className="relative">
                <input 
                    type="text" 
                    placeholder="BUSCAR EXPEDIENTE POR NOMBRE..."
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full bg-black p-5 pl-14 rounded-3xl border border-white/5 font-bold text-white focus:border-brand outline-none shadow-2xl"
                />
                <SearchIcon className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-500 w-5 h-5" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {loading ? <Spinner /> : filtered.map(item => (
                    <div key={item.id} className="bg-[#050505] p-6 rounded-[2rem] border border-white/5 group hover:border-brand/40 transition-all shadow-xl">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h4 className="font-black text-white text-base uppercase italic">{item.client_name}</h4>
                                <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Registrado el {new Date(item.created_at!).toLocaleDateString()}</p>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setViewMode(item)} className="p-3 bg-white/5 rounded-xl text-gray-400 hover:text-white transition-colors" title="Ver Detalles">
                                    <SearchIcon className="w-4 h-4" />
                                </button>
                                <button onClick={() => exportToPDF(item)} className="p-3 bg-white/5 rounded-xl text-brand hover:scale-110 transition-transform" title="Descargar PDF">
                                    <DownloadIcon className="w-4 h-4" />
                                </button>
                            </div>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {item.conditions.slice(0, 3).map(c => (
                                <span key={c} className="text-[7px] font-black uppercase bg-brand/10 text-brand px-2 py-1 rounded-md border border-brand/20">{c}</span>
                            ))}
                            {item.conditions.length > 3 && <span className="text-[7px] text-gray-600 font-black">+{item.conditions.length - 3} MÁS</span>}
                        </div>
                    </div>
                ))}
            </div>

            {/* Modal: Nuevo Historial - ESTRUCTURA RECENTRADA Y RESPONSIVA */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[500] flex flex-col items-center justify-start overflow-y-auto px-4 py-8 custom-scrollbar">
                    <div className="w-full max-w-4xl bg-[#050505] border border-white/10 rounded-[3rem] shadow-2xl overflow-hidden animate-fade-in my-auto">
                        {/* Modal Header Fijo */}
                        <div className="sticky top-0 bg-[#050505]/90 backdrop-blur-xl p-8 sm:p-10 border-b border-white/5 flex justify-between items-center z-10">
                            <div>
                                <h3 className="text-xl sm:text-3xl font-black text-brand italic uppercase tracking-tighter leading-none">Nueva Ficha Clínica</h3>
                                <p className="text-[10px] text-gray-500 uppercase font-black tracking-[0.3em] mt-2">Expediente Médico de Arte Corporal</p>
                            </div>
                            <button onClick={() => setIsModalOpen(false)} className="p-4 bg-white/5 rounded-full text-gray-500 hover:text-white transition-colors">
                                <CloseIcon className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Modal Content - Scroll Interno con Padding Extra al Final */}
                        <div className="p-8 sm:p-12 space-y-12">
                            <form onSubmit={handleSave} className="space-y-12">
                                <section className="space-y-8">
                                    <h5 className="text-[11px] font-black text-brand uppercase tracking-[0.4em] border-l-4 border-brand pl-4">1. DATOS PERSONALES</h5>
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                        <div className="md:col-span-2">
                                            <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Nombre del Paciente</label>
                                            <input type="text" list="client-list" value={formData.client_name} onChange={e => setFormData({...formData, client_name: e.target.value})} required className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold text-lg" />
                                            <datalist id="client-list">
                                                {clients.map(c => <option key={c.id} value={c.name} />)}
                                            </datalist>
                                        </div>
                                        <div>
                                            <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">F. Nacimiento</label>
                                            <input type="date" value={formData.birth_date} onChange={e => setFormData({...formData, birth_date: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                        </div>

                                        <div className="grid grid-cols-2 md:grid-cols-3 gap-6 md:col-span-3">
                                            <div>
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Edad</label>
                                                <input type="number" value={formData.age} onChange={e => setFormData({...formData, age: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                            </div>
                                            <div>
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Sexo</label>
                                                <select value={formData.sex} onChange={e => setFormData({...formData, sex: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold">
                                                    <option value="M">Masculino</option>
                                                    <option value="F">Femenino</option>
                                                </select>
                                            </div>
                                            <div className="col-span-2 md:col-span-1">
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Teléfono de Contacto</label>
                                                <input type="tel" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                            </div>
                                        </div>

                                        <div className="md:col-span-3">
                                            <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Dirección de Domicilio</label>
                                            <input type="text" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                        </div>

                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:col-span-3">
                                            <div>
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Ocupación</label>
                                                <input type="text" value={formData.occupation} onChange={e => setFormData({...formData, occupation: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                            </div>
                                            <div>
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Residencia Actual</label>
                                                <input type="text" value={formData.residence} onChange={e => setFormData({...formData, residence: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                            </div>
                                            <div>
                                                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Escolaridad</label>
                                                <input type="text" value={formData.schooling} onChange={e => setFormData({...formData, schooling: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold" />
                                            </div>
                                        </div>

                                        <div className="md:col-span-3">
                                            <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-3">Correo Electrónico</label>
                                            <input type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-white/10 font-bold text-brand" />
                                        </div>
                                    </div>
                                </section>

                                <section className="space-y-8">
                                    <h5 className="text-[11px] font-black text-brand uppercase tracking-[0.4em] border-l-4 border-brand pl-4">2. INFORMACIÓN DE SALUD</h5>
                                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                                        {CONDITIONS_LIST.map(cond => (
                                            <button 
                                                key={cond} 
                                                type="button"
                                                onClick={() => handleConditionToggle(cond)}
                                                className={`p-5 rounded-2xl border text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center text-center leading-tight h-20 ${formData.conditions.includes(cond) ? 'bg-brand border-brand text-white shadow-[0_0_25px_rgba(232,21,220,0.5)] scale-105' : 'bg-white/5 border-white/10 text-gray-600 hover:border-brand/40'}`}
                                            >
                                                {cond}
                                            </button>
                                        ))}
                                    </div>
                                    <div className="mt-8">
                                        <label className="text-[10px] font-black uppercase text-red-500/60 tracking-widest block mb-3 italic">Alergias Conocidas (Níquel, Látex, Tintas, etc.)</label>
                                        <input type="text" value={formData.allergies_detail} onChange={e => setFormData({...formData, allergies_detail: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-red-500/20 text-red-500 font-bold placeholder:text-red-900/40" placeholder="Declarar alergias críticas aquí..." />
                                    </div>
                                </section>

                                <section className="space-y-8">
                                    <h5 className="text-[11px] font-black text-brand uppercase tracking-[0.4em] border-l-4 border-brand pl-4">3. ESPECIFICACIONES DEL TRABAJO</h5>
                                    <textarea 
                                        value={formData.appointment_motive} 
                                        onChange={e => setFormData({...formData, appointment_motive: e.target.value})}
                                        className="w-full bg-black p-8 rounded-[2.5rem] border border-white/10 font-bold min-h-[200px] text-base italic leading-relaxed"
                                        placeholder="Descripción detallada del diseño, tamaño en centímetros y zona exacta del cuerpo donde se aplicará..."
                                    ></textarea>
                                </section>

                                {/* Espaciador y Botones - pb-40 asegura que sea visible sobre el nav móvil */}
                                <div className="pb-40 flex flex-col sm:flex-row gap-6">
                                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-6 bg-white/5 rounded-2xl text-[11px] font-black uppercase tracking-widest text-gray-500 hover:bg-white/10 transition-colors">Cancelar Registro</button>
                                    <button type="submit" disabled={isSaving} className="flex-1 py-6 bg-brand text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-brand/20 flex justify-center items-center gap-4 active:scale-95 transition-all">
                                        {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> ARCHIVAR HISTORIAL</>}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                </div>
            )}

            {/* Modal: Ver Ficha - REDISEÑO SIMILAR */}
            {viewMode && (
                <div className="fixed inset-0 bg-black/98 backdrop-blur-2xl z-[500] flex flex-col items-center justify-start overflow-y-auto px-4 py-8 custom-scrollbar">
                    <div className="w-full max-w-3xl bg-[#050505] border border-brand/30 rounded-[3rem] shadow-2xl my-auto overflow-hidden animate-fade-in">
                        <div className="sticky top-0 bg-[#050505]/95 backdrop-blur-xl p-8 sm:p-10 border-b border-white/5 flex justify-between items-center z-10">
                            <div>
                                <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">Expediente Médico</h3>
                                <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">Archivo de Seguridad • Bribiesca Studio</p>
                            </div>
                            <button onClick={() => setViewMode(null)} className="p-4 text-gray-500 hover:text-white transition-colors">
                                <CloseIcon className="w-8 h-8" />
                            </button>
                        </div>

                        <div className="p-8 sm:p-12 space-y-10">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 text-sm">
                                <div className="space-y-8">
                                    <div>
                                        <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-3 italic">Titular de la Ficha</p>
                                        <p className="text-2xl font-black text-white uppercase">{viewMode.client_name}</p>
                                    </div>
                                    <div className="grid grid-cols-2 gap-6 bg-white/[0.02] p-6 rounded-3xl border border-white/5">
                                        <div>
                                            <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-1">F. Nacimiento</p>
                                            <p className="text-white font-bold">{viewMode.birth_date}</p>
                                        </div>
                                        <div>
                                            <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-1">Edad/Sexo</p>
                                            <p className="text-white font-bold">{viewMode.age} años / {viewMode.sex}</p>
                                        </div>
                                    </div>
                                    <div>
                                        <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-2">Información de Contacto</p>
                                        <p className="text-white font-bold">{viewMode.phone}</p>
                                        <p className="text-brand/70 font-bold lowercase mt-1">{viewMode.email}</p>
                                    </div>
                                </div>

                                <div className="space-y-8">
                                    <div>
                                        <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-4 italic">Anamnesis de Salud</p>
                                        <div className="flex flex-wrap gap-2">
                                            {viewMode.conditions.length > 0 ? viewMode.conditions.map(c => (
                                                <span key={c} className="bg-white/5 px-4 py-2 rounded-xl text-[10px] font-black uppercase text-gray-400 border border-white/5">{c}</span>
                                            )) : <span className="text-gray-600 italic">No declara patologías</span>}
                                        </div>
                                    </div>
                                    <div className="p-6 bg-red-500/5 border border-red-500/20 rounded-[2rem]">
                                        <p className="text-red-500 font-black text-[10px] uppercase tracking-widest mb-2 italic flex items-center gap-2">
                                            <span className="w-1.5 h-1.5 bg-red-500 rounded-full animate-pulse"></span> Alergias Críticas
                                        </p>
                                        <p className="text-red-400 font-bold uppercase text-[12px] leading-tight">{viewMode.allergies_detail || 'NINGUNA DECLARADA'}</p>
                                    </div>
                                </div>

                                <div className="md:col-span-2 p-10 bg-black/40 rounded-[2.5rem] border border-white/10 shadow-inner">
                                    <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-4 italic">Memoria Descriptiva del Tatuaje</p>
                                    <p className="text-white italic leading-relaxed text-lg font-medium whitespace-pre-line">{viewMode.appointment_motive || 'Detalles no especificados'}</p>
                                </div>
                            </div>

                            <div className="pb-40 pt-6 flex flex-col sm:flex-row gap-6">
                                <button onClick={() => handlePrint(viewMode)} className="flex-1 py-6 bg-white/5 rounded-2xl text-[11px] font-black uppercase tracking-widest flex items-center justify-center gap-4 border border-white/5 hover:bg-white/10 transition-colors">
                                    <PrintIcon className="w-6 h-6"/> Imprimir Ficha
                                </button>
                                <button onClick={() => exportToPDF(viewMode)} className="flex-1 py-6 bg-brand text-white rounded-2xl text-[11px] font-black uppercase tracking-widest flex items-center justify-center gap-4 shadow-2xl shadow-brand/20 active:scale-95 transition-all">
                                    <DownloadIcon className="w-6 h-6"/> Descargar PDF
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { MedicalHistory, Client } from '../types';
import { Spinner, PlusIcon, SearchIcon, CloseIcon, SaveIcon, DownloadIcon, PrintIcon } from './Icons';
import { jsPDF } from 'jspdf';

const CONDITIONS_LIST = [
    "Diabetes", "Hipertensión", "Epilepsia", "COVID-19", "Hepatitis A, B o C", "Influenza", "VIH/SIDA"
];

export const MedicalHistoryManager: React.FC = () => {
    const [histories, setHistories] = useState<MedicalHistory[]>([]);
    const [clients, setClients] = useState<Client[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [viewMode, setViewMode] = useState<MedicalHistory | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [isSaving, setIsSaving] = useState(false);

    const [formData, setFormData] = useState<MedicalHistory>({
        client_name: '',
        birth_date: '',
        age: '',
        sex: 'M',
        address: '',
        phone: '',
        occupation: '',
        residence: '',
        schooling: '',
        email: '',
        conditions: [],
        allergies_detail: '',
        appointment_motive: '',
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        const { data: hist } = await supabase.from('medical_histories').select('*').order('created_at', { ascending: false });
        const { data: clie } = await supabase.from('clients').select('*').order('name');
        if (hist) setHistories(hist);
        if (clie) setClients(clie);
        setLoading(false);
    };

    const handleConditionToggle = (cond: string) => {
        setFormData(prev => ({
            ...prev,
            conditions: prev.conditions.includes(cond) 
                ? prev.conditions.filter(c => c !== cond) 
                : [...prev.conditions, cond]
        }));
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const { error } = await supabase.from('medical_histories').insert([formData]);
        if (!error) {
            alert("Historial Clínico Guardado.");
            setIsModalOpen(false);
            fetchData();
        } else {
            alert("Error: " + error.message);
        }
        setIsSaving(false);
    };

    const exportToPDF = (item: MedicalHistory) => {
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.text("BRIBIESCA STUDIO - FICHA CLÍNICA", 105, 20, { align: 'center' });
        doc.setFontSize(10);
        doc.text(`Expediente N: ${item.id} | Fecha: ${new Date(item.created_at!).toLocaleDateString()}`, 105, 28, { align: 'center' });
        doc.setLineWidth(0.5);
        doc.line(20, 35, 190, 35);
        doc.setFont("helvetica", "bold");
        doc.text("DATOS PERSONALES", 20, 45);
        doc.setFont("helvetica", "normal");
        doc.text(`Nombre: ${item.client_name}`, 20, 52);
        doc.text(`F. Nacimiento: ${item.birth_date} | Edad: ${item.age} | Sexo: ${item.sex}`, 20, 59);
        doc.text(`Dirección: ${item.address}`, 20, 66);
        doc.text(`Teléfono: ${item.phone} | Ocupación: ${item.occupation}`, 20, 73);
        doc.text(`Residencia: ${item.residence} | Escolaridad: ${item.schooling}`, 20, 80);
        doc.text(`Email: ${item.email}`, 20, 87);
        doc.setFont("helvetica", "bold");
        doc.text("INFORMACIÓN DE SALUD", 20, 100);
        doc.setFont("helvetica", "normal");
        doc.text(`Condiciones registradas: ${item.conditions.join(', ') || 'Ninguna'}`, 20, 107);
        doc.text(`Alergias: ${item.allergies_detail || 'No declaradas'}`, 20, 114);
        doc.setFont("helvetica", "bold");
        doc.text("MOTIVO DE LA CITA", 20, 127);
        doc.setFont("helvetica", "normal");
        doc.setLineWidth(0.1);
        doc.rect(20, 132, 170, 40);
        doc.text(item.appointment_motive || 'Sin descripción', 25, 138, { maxWidth: 160 });
        doc.save(`Historial_${item.client_name.replace(' ', '_')}.pdf`);
    };

    const handlePrint = (item: MedicalHistory) => {
        const printWindow = window.open('', '_blank');
        if (printWindow) {
            printWindow.document.write(`
                <html>
                    <head><title>Imprimir Historial</title><style>body{font-family:sans-serif;padding:40px;} h1{text-align:center;border-bottom:2px solid #000;padding-bottom:10px;} .field{margin-bottom:10px;} label{font-weight:bold;}</style></head>
                    <body>
                        <h1>BRIBIESCA STUDIO - FICHA CLÍNICA</h1>
