                                        <input type="text" placeholder="RESIDENCIA" value={formData.residence} onChange={e => setFormData({...formData, residence: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                        <input type="text" placeholder="ESCOLARIDAD" value={formData.schooling} onChange={e => setFormData({...formData, schooling: e.target.value})} className="w-full bg-black p-4 rounded-2xl border border-white/10 font-bold" />
                                    </div>
                                    <div className="md:col-span-3">
