                                        <button 
                                            key={cond} 
                                            type="button"
                                            onClick={() => handleConditionToggle(cond)}
                                            className={`p-4 rounded-2xl border text-[9px] font-black uppercase tracking-widest transition-all flex items-center justify-center text-center h-16 ${formData.conditions.includes(cond) ? 'bg-brand border-brand text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-600 hover:border-brand/40'}`}
                                        >
                                            {cond}
                                        </button>
                                    ))}
                                </div>
                                <div className="mt-8">
                                    <label className="text-[10px] font-black uppercase text-red-500/60 tracking-widest block mb-3 italic">Alergias Conocidas</label>
                                    <input type="text" value={formData.allergies_detail} onChange={e => setFormData({...formData, allergies_detail: e.target.value})} className="w-full bg-black p-5 rounded-2xl border border-red-500/20 text-red-500 font-bold placeholder:text-red-900/40" placeholder="Declare alergias críticas..." />
                                </div>
                            </section>

                            {/* Sección 3 */}
                            <section className="space-y-6">
                                <h5 className="text-[10px] font-black text-brand uppercase tracking-[0.4em] border-l-4 border-brand pl-4">3. MOTIVO DE LA CITA</h5>
                                <textarea 
                                    value={formData.appointment_motive} 
                                    onChange={e => setFormData({...formData, appointment_motive: e.target.value})}
                                    className="w-full bg-black p-6 rounded-[2rem] border border-white/10 font-bold min-h-[180px] text-sm italic"
                                    placeholder="Diseño, tamaño y zona del cuerpo..."
                                ></textarea>
                            </section>

                            {/* Botones de Acción - Padding extra para móviles */}
                            <div className="pt-6 pb-20 sm:pb-12 flex flex-col sm:flex-row gap-4">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-5 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-gray-500 order-2 sm:order-1">Descartar</button>
                                <button type="submit" disabled={isSaving} className="flex-1 py-5 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex justify-center items-center gap-3 order-1 sm:order-2 active:scale-95 transition-all">
                                    {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> ARCHIVAR EXPEDIENTE</>}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* MODAL VER EXPEDIENTE: REPARADO */}
            {viewMode && (
                <div className="fixed inset-0 bg-black/98 backdrop-blur-2xl z-[500] overflow-y-auto px-4 py-8 sm:py-12 custom-scrollbar">
                    <div className="mx-auto w-full max-w-3xl bg-[#050505] border border-brand/30 rounded-[3rem] shadow-2xl overflow-hidden animate-fade-in">

                        <div className="p-8 border-b border-white/5 flex justify-between items-center bg-black/40">
                            <div>
                                <h3 className="text-xl sm:text-2xl font-black text-white italic uppercase tracking-tighter">EXPEDIENTE ARCHIVADO</h3>
                                <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-1">BRIBIESCA STUDIO • MODO LECTURA</p>
