                            <form id="medical-form" onSubmit={handleSave} className="space-y-12">
                                <section className="space-y-8">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-xl bg-brand/10 flex items-center justify-center text-brand font-black text-lg">1</div>
                                        <h5 className="text-[11px] font-black text-white uppercase tracking-[0.4em]">Datos Personales</h5>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                        <div className="md:col-span-2">
                                            <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Nombre del Paciente</label>
                                            <input type="text" list="client-list" value={formData.client_name} onChange={e => setFormData({...formData, client_name: e.target.value})} required className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold text-lg text-white focus:border-brand" />
                                            <datalist id="client-list">
                                                {clients.map(c => <option key={c.id} value={c.name} />)}
