                                        </div>
                                        <div>
                                            <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">F. Nacimiento</label>
                                            <input type="date" value={formData.birth_date} onChange={e => setFormData({...formData, birth_date: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold" />
                                        </div>

                                        <div className="grid grid-cols-2 md:grid-cols-3 gap-6 md:col-span-3">
                                            <div>
                                                <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Edad</label>
                                                <input type="number" value={formData.age} onChange={e => setFormData({...formData, age: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold" />
                                            </div>
                                            <div>
                                                <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Sexo</label>
                                                <select value={formData.sex} onChange={e => setFormData({...formData, sex: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold text-white">
                                                    <option value="M">Masculino</option>
                                                    <option value="F">Femenino</option>
                                                </select>
                                            </div>
                                            <div className="col-span-2 md:col-span-1">
                                                <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Teléfono</label>
                                                <input type="tel" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold" />
                                            </div>
                                        </div>

                                        <div className="md:col-span-3">
                                            <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Dirección</label>
                                            <input type="text" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold" />
                                        </div>

                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:col-span-3">
                                            <input type="text" placeholder="OCUPACIÓN" value={formData.occupation} onChange={e => setFormData({...formData, occupation: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold uppercase" />
                                            <input type="text" placeholder="RESIDENCIA" value={formData.residence} onChange={e => setFormData({...formData, residence: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold uppercase" />
                                            <input type="text" placeholder="ESCOLARIDAD" value={formData.schooling} onChange={e => setFormData({...formData, schooling: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold uppercase" />
                                        </div>

                                        <div className="md:col-span-3">
                                            <label className="text-[9px] font-black uppercase text-gray-600 tracking-widest block mb-3">Email</label>
                                            <input type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-black p-4 rounded-xl border border-white/10 font-bold text-brand" />
                                        </div>
                                    </div>
                                </section>

                                <section className="space-y-8">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-xl bg-brand/10 flex items-center justify-center text-brand font-black text-lg">2</div>
                                        <h5 className="text-[11px] font-black text-white uppercase tracking-[0.4em]">Salud</h5>
                                    </div>
                                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                                        {CONDITIONS_LIST.map(cond => (
                                            <button 
                                                key={cond} 
                                                type="button"
                                                onClick={() => handleConditionToggle(cond)}
                                                className={`p-4 rounded-xl border text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center text-center h-16 ${formData.conditions.includes(cond) ? 'bg-brand border-brand text-white shadow-lg' : 'bg-white/5 border-white/10 text-gray-600 hover:border-brand/40'}`}
                                            >
                                                {cond}
                                            </button>
                                        ))}
                                    </div>
                                    <div className="mt-8">
                                        <label className="text-[10px] font-black uppercase text-red-500/60 tracking-widest block mb-3 italic">Alergias Críticas</label>
                                        <input type="text" value={formData.allergies_detail} onChange={e => setFormData({...formData, allergies_detail: e.target.value})} className="w-full bg-black p-5 rounded-xl border border-red-500/20 text-red-500 font-bold placeholder:text-red-900/40" placeholder="Especifique alergias conocidas..." />
                                    </div>
                                </section>

                                <section className="space-y-8">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-xl bg-brand/10 flex items-center justify-center text-brand font-black text-lg">3</div>
                                        <h5 className="text-[11px] font-black text-white uppercase tracking-[0.4em]">Proyecto</h5>
                                    </div>
                                    <textarea 
                                        value={formData.appointment_motive} 
                                        onChange={e => setFormData({...formData, appointment_motive: e.target.value})}
                                        className="w-full bg-black p-6 rounded-[2rem] border border-white/10 font-bold min-h-[180px] text-base italic leading-relaxed text-white"
                                        placeholder="Descripción detallada: Diseño, tamaño y zona del cuerpo..."
                                    ></textarea>
                                </section>

                                <div className="h-20 sm:h-0"></div> {/* Espacio extra para móviles */}
                            </form>
                        </div>

                        {/* Pie de Página Fijo (Acciones) */}
                        <div className="flex-shrink-0 p-6 sm:p-10 border-t border-white/5 bg-black/80 backdrop-blur-xl flex flex-col sm:flex-row gap-4">
                            <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-5 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-gray-500 hover:bg-white/10">Cancelar</button>
                            <button type="submit" form="medical-form" disabled={isSaving} className="flex-1 py-5 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex justify-center items-center gap-4 active:scale-95 transition-all">
                                {isSaving ? <Spinner /> : <><SaveIcon className="w-5 h-5"/> ARCHIVAR EXPEDIENTE</>}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* MODAL VIEW: VER FICHA - OPTIMIZADO */}
            {viewMode && (
                <div className="fixed inset-0 bg-black/99 backdrop-blur-3xl z-[500] flex items-end sm:items-center justify-center p-0 sm:p-4 lg:p-6 overflow-hidden">
                    <div className="w-full h-[95dvh] sm:h-[85vh] max-w-4xl bg-[#050505] border border-brand/40 rounded-t-[3rem] sm:rounded-[4rem] shadow-2xl flex flex-col overflow-hidden animate-fade-in">

                        <div className="flex-shrink-0 p-6 sm:p-10 border-b border-white/5 flex justify-between items-center bg-black/60">
                            <div>
                                <h3 className="text-xl sm:text-2xl font-black text-white italic uppercase tracking-tighter">Expediente Archivat</h3>
                                <p className="text-[10px] text-brand font-black uppercase tracking-widest mt-2">Modo Lectura • Bribiesca Studio</p>
                            </div>
                            <button onClick={() => setViewMode(null)} className="p-3 text-gray-500 hover:text-white transition-colors">
                                <CloseIcon className="w-7 h-7" />
                            </button>
                        </div>

                        <div className="flex-grow overflow-y-auto p-6 sm:p-16 custom-scrollbar space-y-10">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 text-sm">
                                <div className="space-y-8">
                                    <div>
                                        <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-3 italic">Identidad</p>
                                        <p className="text-2xl font-black text-white uppercase tracking-tighter">{viewMode.client_name}</p>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4 bg-white/[0.02] p-6 rounded-[2rem] border border-white/5">
                                        <div>
                                            <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-1">Nacimiento</p>
                                            <p className="text-white font-bold">{viewMode.birth_date}</p>
                                        </div>
                                        <div>
                                            <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-1">Edad/Sexo</p>
                                            <p className="text-white font-bold">{viewMode.age} / {viewMode.sex}</p>
                                        </div>
                                    </div>
                                    <div>
                                        <p className="text-gray-600 font-black text-[9px] uppercase tracking-widest mb-2">Contacto</p>
                                        <p className="text-white font-bold">{viewMode.phone}</p>
                                        <p className="text-brand/80 font-bold lowercase mt-1">{viewMode.email}</p>
                                    </div>
                                </div>

                                <div className="space-y-8">
                                    <div>
                                        <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-4 italic">Salud General</p>
                                        <div className="flex flex-wrap gap-2">
                                            {viewMode.conditions.length > 0 ? viewMode.conditions.map(c => (
                                                <span key={c} className="bg-white/5 px-4 py-2 rounded-xl text-[9px] font-black uppercase text-gray-400 border border-white/5">{c}</span>
                                            )) : <span className="text-gray-700 italic">No reportado</span>}
                                        </div>
                                    </div>
                                    <div className="p-6 bg-red-500/5 border border-red-500/20 rounded-[2rem]">
                                        <p className="text-red-500 font-black text-[9px] uppercase tracking-widest mb-2 italic">Alergias</p>
                                        <p className="text-red-400 font-bold uppercase leading-tight">{viewMode.allergies_detail || 'NINGUNA'}</p>
                                    </div>
                                </div>

                                <div className="md:col-span-2 p-8 bg-black rounded-[2.5rem] border border-white/10">
                                    <p className="text-brand font-black text-[10px] uppercase tracking-widest mb-4 italic">Motivo de Consulta</p>
                                    <p className="text-white italic leading-relaxed text-lg font-medium whitespace-pre-line">{viewMode.appointment_motive}</p>
                                </div>
                            </div>
                            <div className="h-10"></div>
                        </div>

                        {/* Pie de Página Fijo (Acciones) */}
                        <div className="flex-shrink-0 p-6 sm:p-10 border-t border-white/5 bg-black/90 backdrop-blur-2xl flex flex-col sm:flex-row gap-4">
                            <button onClick={() => handlePrint(viewMode)} className="flex-1 py-5 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-4 border border-white/5 hover:bg-white/10">
                                <PrintIcon className="w-6 h-6"/> Imprimir
                            </button>
                            <button onClick={() => exportToPDF(viewMode)} className="flex-1 py-5 bg-brand text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-4 shadow-2xl active:scale-95 transition-all">
                                <DownloadIcon className="w-6 h-6"/> Descargar PDF
                            </button>
