import React, { useState } from 'react';
import { UserRole } from '../types';
import { Spinner, EyeIcon, EyeOffIcon, CloseIcon } from './Icons';
import { supabase } from '../utils/supabase';

interface AuthProps {
    onLogin: (username: string, role: UserRole) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
    const [authMode, setAuthMode] = useState<'login' | 'register' | 'recover'>('login');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');
    const [showPassword, setShowPassword] = useState(false);

    // Form States
    const [fullName, setFullName] = useState('');
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [whatsapp, setWhatsapp] = useState('');
    const [password, setPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');

    const resetMessages = () => {
        setError('');
        setSuccessMessage('');
    };

    const handleRecoverPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        resetMessages();

        try {
            // Verificar si el correo existe
            const { data: user, error: fetchError } = await supabase
                .from('clients')
                .select('id, username')
                .eq('contact', email.toLowerCase().trim())
                .single();

            if (fetchError || !user) {
                throw new Error('CORREO NO REGISTRADO EN EL SISTEMA');
            }

            // En una app PRO real aquí se enviaría un OTP. 
            // Para esta versión de estudio, permitimos el cambio tras validación de correo.
            const { error: updateError } = await supabase
                .from('clients')
                .update({ password: newPassword })
                .eq('id', user.id);

            if (updateError) throw new Error('ERROR AL ACTUALIZAR CONTRASEÑA');

            setSuccessMessage('¡CONTRASEÑA ACTUALIZADA CON ÉXITO!');
            setTimeout(() => {
                setAuthMode('login');
                resetMessages();
            }, 2000);

        } catch (err: any) {
            setError(err.message.toUpperCase());
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (authMode === 'recover') return handleRecoverPassword(e);

        setLoading(true);
        resetMessages();

        const cleanUsername = username.toLowerCase().trim();
        const cleanEmail = email.toLowerCase().trim();

        try {
            if (authMode === 'login') {
                const { data: user, error: fetchError } = await supabase
                    .from('clients')
                    .select('username, password, role')
                    .eq('username', cleanUsername)
                    .single();

                if (fetchError || !user) {
                    throw new Error('USUARIO NO ENCONTRADO');
                }

                if (user.password !== password) {
                    throw new Error('CONTRASEÑA INCORRECTA');
                }

                onLogin(user.username, user.role as UserRole);
            } else {
                if (!fullName || !username || !email || !whatsapp || !password) {
                    throw new Error('TODOS LOS CAMPOS SON OBLIGATORIOS');
                }

                const { error: dbError } = await supabase
                    .from('clients')
                    .insert([{
                        name: fullName.trim(),
                        username: cleanUsername,
                        contact: cleanEmail,
                        whatsapp: whatsapp.trim(),
                        password: password,
                        role: 'client',
                        notes: `Registro vía App`
                    }]);

                if (dbError) {
                    if (dbError.code === '23505') throw new Error('EL USUARIO O CORREO YA EXISTEN');
                    throw new Error(dbError.message);
                }

                onLogin(cleanUsername, 'client');
            }
        } catch (err: any) {
            setError(err.message.toUpperCase());
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-black relative overflow-hidden">
            <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-brand/10 blur-[120px] rounded-full pointer-events-none"></div>

            <div className="w-full max-w-md space-y-8 animate-fade-in py-10 px-6 relative z-10">
                <div className="text-center mb-10">
                    <img src="https://tritex.com.mx/Bribiesca%20logo%2002.jpg" alt="Logo" className="relative h-28 w-auto mx-auto mb-6 rounded-3xl shadow-2xl border border-white/10" />
                    <h2 className="text-3xl font-black text-white uppercase italic leading-none">
                        {authMode === 'login' ? 'Acceso' : authMode === 'register' ? 'Registro' : 'Recuperar'}
                    </h2>
                    {authMode === 'recover' && (
                        <p className="text-[9px] text-gray-500 font-black uppercase tracking-widest mt-4">Introduce tu correo para restablecer</p>
                    )}
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {authMode === 'recover' ? (
                        <>
                            <input 
                                type="email" 
                                value={email} 
                                onChange={(e) => setEmail(e.target.value)} 
                                placeholder="CORREO REGISTRADO" 
                                className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" 
                                required 
                            />
                            <div className="relative">
                                <input 
                                    type={showPassword ? "text" : "password"} 
                                    value={newPassword} 
                                    onChange={(e) => setNewPassword(e.target.value)} 
                                    placeholder="NUEVA CONTRASEÑA" 
                                    className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold pr-14" 
                                    required 
                                />
                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-600 hover:text-brand transition-colors">
                                    {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                                </button>
                            </div>
                        </>
                    ) : (
                        <>
                            {authMode === 'register' && (
                                <input type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} placeholder="NOMBRE COMPLETO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                            )}
                            <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="USUARIO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                            {authMode === 'register' && (
                                <>
                                    <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="CORREO" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                                    <input type="tel" value={whatsapp} onChange={(e) => setWhatsapp(e.target.value)} placeholder="WHATSAPP" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold" required />
                                </>
                            )}
                            <div className="relative">
                                <input type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="CONTRASEÑA" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white font-bold pr-14" required />
                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-600 hover:text-brand transition-colors">
                                    {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                                </button>
                            </div>
                        </>
                    )}

                    {error && <p className="text-brand text-[10px] font-black uppercase text-center tracking-widest bg-brand/10 p-3 rounded-xl animate-shake">{error}</p>}
                    {successMessage && <p className="text-green-500 text-[10px] font-black uppercase text-center tracking-widest bg-green-500/10 p-3 rounded-xl">{successMessage}</p>}

                    <button type="submit" disabled={loading} className="w-full py-5 bg-brand text-white text-[11px] font-black rounded-2xl shadow-xl active:scale-95 transition-all disabled:opacity-50">
                        {loading ? <Spinner /> : (authMode === 'login' ? 'ENTRAR' : authMode === 'register' ? 'REGISTRARME' : 'ACTUALIZAR ACCESO')}
                    </button>
                </form>

                <div className="flex flex-col gap-4 text-center">
                    {authMode === 'login' && (
                        <button 
                            onClick={() => { setAuthMode('recover'); resetMessages(); }} 
                            className="text-[9px] font-black text-brand/60 hover:text-brand uppercase tracking-widest transition-colors"
                        >
                            ¿Olvidaste tu contraseña?
                        </button>
                    )}

                    <button onClick={() => { 
                        setAuthMode(authMode === 'login' ? 'register' : 'login'); 
                        resetMessages(); 
                    }} className="text-[10px] font-black text-gray-500 hover:text-white uppercase tracking-widest transition-colors">
                        {authMode === 'login' ? '¿No tienes cuenta? Regístrate' : '¿Ya tienes cuenta? Inicia sesión'}
                    </button>

                    {authMode === 'recover' && (
                        <button onClick={() => { setAuthMode('login'); resetMessages(); }} className="text-[9px] font-black text-gray-500 hover:text-white uppercase tracking-widest">
                            Volver al inicio
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../utils/supabase';
import { Consent, MedicalHistory } from '../types';
import { Spinner, CalendarIcon, InventoryIcon, ClientsIcon, CheckIcon, PencilIcon, MedicalIcon } from './Icons';

export const AdminDashboard: React.FC = () => {
    const [stats, setStats] = useState({ appointments: 0, revenue: 0, lowStock: 0, newClients: 0 });
    const [notifications, setNotifications] = useState<Consent[]>([]);
    const [alert, setAlert] = useState<{ type: 'firma' | 'historial', name: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchDashboardData();

        // Canal para Firmas (Updates en consents)
        const consentSub = supabase
            .channel('consents_signs')
            .on('postgres_changes', { 
                event: 'UPDATE', 
                schema: 'public', 
                table: 'consents',
                filter: 'status=eq.signed'
            }, (payload) => {
                const updated = payload.new as Consent;
                triggerSystemNotification('NUEVA FIRMA', `El cliente ${updated.client_name} ha firmado su consentimiento.`);
                triggerAlert('firma', updated.client_name);
                fetchDashboardData();
            })
            .subscribe();

        // Canal para Historiales Médicos (Nuevos envíos)
        const medicalSub = supabase
            .channel('medical_alerts')
            .on('postgres_changes', { 
                event: 'INSERT', 
                schema: 'public', 
                table: 'medical_histories' 
            }, (payload) => {
                const newHistory = payload.new as MedicalHistory;
                triggerSystemNotification('NUEVO HISTORIAL', `Recibiste la ficha clínica de ${newHistory.client_name}.`);
                triggerAlert('historial', newHistory.client_name);
                fetchDashboardData();
            })
            .subscribe();

        return () => { 
            supabase.removeChannel(consentSub);
            supabase.removeChannel(medicalSub);
        };
    }, []);

    const triggerSystemNotification = (title: string, body: string) => {
        if ("Notification" in window && Notification.permission === "granted") {
            // Fix: 'vibrate' property removed from NotificationOptions as it's not a valid property for the Notification constructor.
            new Notification(title, {
                body,
                icon: 'https://tritex.com.mx/Bribiesca%20logo%2002.jpg',
            });
        }
    };

    const triggerAlert = (type: 'firma' | 'historial', name: string) => {
        setAlert({ type, name });
        try { new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3').play(); } catch(e) {}
        setTimeout(() => setAlert(null), 8000);
    };

    const fetchDashboardData = async () => {
        const { data: apps } = await supabase.from('appointments').select('*');
        const { data: stock } = await supabase.from('inventory').select('*').lt('quantity', 'min_stock');
        const { data: clients } = await supabase.from('clients').select('*');
        const { data: signs } = await supabase
            .from('consents')
            .select('*')
            .eq('status', 'signed')
            .order('signed_at', { ascending: false })
            .limit(5);

        if (signs) setNotifications(signs);
        setStats({
            appointments: apps?.length || 0,
            revenue: apps?.reduce((acc, curr) => acc + (curr.price_total || 0), 0) || 0,
            lowStock: stock?.length || 0,
            newClients: clients?.length || 0
        });
        setLoading(false);
    };

    if (loading) return <div className="flex justify-center p-20"><Spinner /></div>;

    return (
        <div className="space-y-8 animate-fade-in relative pb-20">
            {alert && (
                <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-brand text-white px-8 py-5 rounded-3xl shadow-[0_0_50px_rgba(232,21,220,0.6)] animate-bounce border-2 border-white/20 flex items-center gap-4">
                    <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                        {alert.type === 'firma' ? <PencilIcon className="w-4 h-4" /> : <MedicalIcon className="w-4 h-4" />}
                    </div>
                    <div>
                        <p className="text-[10px] font-black uppercase tracking-widest">
                            {alert.type === 'firma' ? 'NOTIFICACIÓN DE FIRMA' : 'SISTEMA: FICHA MÉDICA'}
                        </p>
                        <p className="text-xs font-bold">{alert.name.toUpperCase()}</p>
                    </div>
                </div>
            )}

            <header className="flex justify-between items-end">
                <div>
                    <h2 className="text-3xl font-black text-white italic tracking-tighter uppercase">Studio Intelligence</h2>
                    <p className="text-[10px] text-brand font-black uppercase tracking-[0.4em]">Panel de Control en Vivo</p>
                </div>
            </header>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard title="CITAS" value={stats.appointments} icon={<CalendarIcon />} />
                <StatCard title="INGRESOS" value={`$${stats.revenue}`} icon={<CheckIcon />} />
                <StatCard title="STOCK BAJO" value={stats.lowStock} icon={<InventoryIcon />} color={stats.lowStock > 0 ? 'text-brand' : 'text-white'} />
                <StatCard title="CLIENTES" value={stats.newClients} icon={<ClientsIcon />} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <div className="w-2.5 h-2.5 bg-brand rounded-full animate-pulse"></div> Actividad Reciente
                    </h3>
                    <div className="space-y-4">
                        {notifications.length === 0 ? (
                            <p className="text-center py-10 opacity-20 text-[10px] font-black uppercase">Sin firmas hoy</p>
                        ) : (
                            notifications.map(n => (
                                <div key={n.id} className="p-5 bg-white/[0.03] rounded-2xl border border-white/5 flex items-center justify-between group">
                                    <div className="flex items-center gap-4">
                                        <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand">
                                            <PencilIcon className="w-4 h-4"/>
                                        </div>
                                        <div>
                                            <p className="text-xs font-black text-white uppercase">{n.client_name}</p>
                                            <p className="text-[9px] text-gray-500 font-bold">{new Date(n.signed_at!).toLocaleTimeString()}</p>
                                        </div>
                                    </div>
                                    <img src={n.signature} className="h-6 invert opacity-50" alt="Sig" />
                                </div>
                            ))
                        )}
                    </div>
                </section>

                <section className="bg-[#050505] p-10 rounded-[2.5rem] border border-white/5 shadow-2xl">
                    <h3 className="font-black mb-8 flex items-center gap-4 text-white uppercase tracking-widest text-[11px]">
                        <InventoryIcon className="w-5 h-5 text-brand"/> Suministros Críticos
                    </h3>
                    {stats.lowStock > 0 ? (
                        <div className="p-8 text-center border-2 border-brand/20 rounded-[2rem] bg-brand/[0.03] animate-pulse">
                            <p className="text-brand font-black text-[11px] uppercase tracking-widest">Atención: Reponer Stock</p>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-40 opacity-20">
                            <CheckIcon className="w-10 h-10 mb-2" />
                            <p className="text-[10px] font-black uppercase tracking-widest">Almacén lleno</p>
                        </div>
                    )}
                </section>
            </div>
        </div>
    );
};

const CACHE_NAME = 'bribiesca-cache-v1';
const ASSETS = [
  '/',
  '/index.html',
  '/index.tsx',
  'https://tritex.com.mx/Bribiesca%20logo%2002.jpg'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

